async function openLocalLlmChatTemplateModal(provider, model, options = {}) {
  const providerToken = normalizeLocalLlmProviderToken(provider);
  const modelId = String(model || "").trim();
  if (!isLocalLlmProviderToken(providerToken) || !modelId) {
    showToast("Select a local model first.", "error", 2600);
    return null;
  }
  const providerLabel = localLlmProviderLabel(providerToken);
  const modal = ensureLocalLlmChatTemplateModal();
  const titleEl = document.getElementById("llama-chat-template-title");
  const modelEl = document.getElementById("llama-chat-template-model");
  const summaryEl = document.getElementById("llama-chat-template-summary");
  const editorEl = document.getElementById("llama-chat-template-editor");
  const statusEl = document.getElementById("llama-chat-template-status");
  const saveBtn = document.getElementById("llama-chat-template-save");
  const resetBtn = document.getElementById("llama-chat-template-reset");
  const reloadBtn = document.getElementById("llama-chat-template-reload");
  const embeddedBtn = document.getElementById("llama-chat-template-use-embedded");
  let latestPayload = null;

  const setStatus = (text, tone = "") => {
    if (!statusEl) {
      return;
    }
    statusEl.textContent = String(text || "").trim();
    statusEl.classList.toggle("success", tone === "success");
    statusEl.classList.toggle("error", tone === "error");
  };
  const setBusy = (busy) => {
    [
      document.getElementById("llama-chat-template-save"),
      document.getElementById("llama-chat-template-reset"),
      document.getElementById("llama-chat-template-reload"),
      document.getElementById("llama-chat-template-use-embedded"),
    ].forEach((button) => {
      if (button) {
        button.disabled = Boolean(busy);
      }
    });
  };
  const renderPayload = (payload) => {
    latestPayload = payload && typeof payload === "object" ? payload : {};
    const effective = String(latestPayload.effective_template || latestPayload.override_template || latestPayload.embedded_template || "");
    if (titleEl) {
      titleEl.textContent = latestPayload.override_active ? "Chat Template Override" : "Chat Template";
    }
    if (modelEl) {
      modelEl.textContent = `${providerLabel} • ${modelId}`;
    }
    if (editorEl) {
      editorEl.value = effective;
    }
    const templateNames = Array.isArray(latestPayload.template_names) ? latestPayload.template_names : [];
    const source = String(latestPayload.source || "none").trim();
    const sourceLabel = source === "override" ? "Override active" : source === "gguf" || source === "embedded" ? "Using embedded model template" : "No embedded template found";
    const embeddedChars = Number(latestPayload.embedded_template_chars || 0);
    const overrideChars = Number(latestPayload.override_template_chars || 0);
    const maxChars = Number(latestPayload.max_chars || 0);
    if (summaryEl) {
      summaryEl.innerHTML = `
        <div class="llama-chat-template-summary-row">
          <strong>${escapeHtml(sourceLabel)}</strong>
          <span>${escapeHtml(templateNames.length ? templateNames.join(", ") : "default template")}</span>
        </div>
        <div class="llama-chat-template-badges">
          ${localLlmChatTemplateCapabilityBadges(latestPayload.capabilities || {})}
        </div>
        <div class="llama-chat-template-meta">
          <span>Embedded ${embeddedChars.toLocaleString()} chars</span>
          <span>Override ${overrideChars.toLocaleString()} chars</span>
          ${maxChars > 0 ? `<span>Limit ${maxChars.toLocaleString()} chars</span>` : ""}
        </div>
      `;
    }
    const embeddedButton = document.getElementById("llama-chat-template-use-embedded");
    if (embeddedButton) {
      embeddedButton.disabled = embeddedChars <= 0;
    }
    setStatus(source === "none" || source === "fallback" ? "No embedded template was found for this model." : "Template loaded.");
  };
  const load = async () => {
    setBusy(true);
    setStatus("Loading chat template...");
    try {
      const payload = await api(`/api/settings/local-llm/chat-template?provider=${encodeURIComponent(providerToken)}&model=${encodeURIComponent(modelId)}`, {
        _timeoutMs: HEALTH_REQUEST_TIMEOUT_MS,
      });
      renderPayload(payload);
    } catch (error) {
      setStatus(`Load failed: ${error.message}`, "error");
      if (summaryEl) {
        summaryEl.innerHTML = `<div class="hf-model-browser-empty">Template metadata could not be loaded.</div>`;
      }
    } finally {
      setBusy(false);
    }
  };
  const save = async ({ reset = false } = {}) => {
    setBusy(true);
    setStatus(reset ? "Resetting override..." : "Saving override...");
    try {
      const payload = await api("/api/settings/local-llm/chat-template", {
        method: "POST",
        body: JSON.stringify({
          provider: providerToken,
          model: modelId,
          template: reset ? "" : String(editorEl?.value || ""),
          reset,
        }),
        _timeoutMs: HEALTH_REQUEST_TIMEOUT_MS,
      });
      renderPayload(payload);
      setStatus(reset ? "Override reset. The next model call will use the embedded template." : "Override saved. The matching loaded model was unloaded for a clean reload.", "success");
      if (typeof options.onSaved === "function") {
        options.onSaved(payload);
      }
    } catch (error) {
      setStatus(`${reset ? "Reset" : "Save"} failed: ${error.message}`, "error");
    } finally {
      setBusy(false);
    }
  };

  saveBtn?.replaceWith(saveBtn.cloneNode(true));
  resetBtn?.replaceWith(resetBtn.cloneNode(true));
  reloadBtn?.replaceWith(reloadBtn.cloneNode(true));
  embeddedBtn?.replaceWith(embeddedBtn.cloneNode(true));
  document.getElementById("llama-chat-template-save")?.addEventListener("click", () => {
    void save();
  });
  document.getElementById("llama-chat-template-reset")?.addEventListener("click", () => {
    if (window.confirm(`Reset chat template override for ${modelId}?`)) {
      void save({ reset: true });
    }
  });
  document.getElementById("llama-chat-template-reload")?.addEventListener("click", () => {
    void load();
  });
  document.getElementById("llama-chat-template-use-embedded")?.addEventListener("click", () => {
    if (editorEl && latestPayload) {
      editorEl.value = String(latestPayload.embedded_template || "");
      setStatus("Embedded template copied into the editor.");
    }
  });

  openPopupModal(modal);
  await load();
  return modal;
}

async function api(path, options = {}) {
  const requestOptions = options && typeof options === "object" ? options : {};
  const skipRedisRecovery = Boolean(requestOptions._skipRedisRecovery);
  const skipAuthRecovery = Boolean(requestOptions._skipAuthRecovery);
  const timeoutMs = Math.max(0, Number(requestOptions._timeoutMs || 0));
  const { _skipRedisRecovery, _skipAuthRecovery, _timeoutMs, ...fetchOptions } = requestOptions;

  let timeoutId = 0;
  let timeoutController = null;
  let requestSignal = fetchOptions.signal;
  if (!requestSignal && timeoutMs > 0 && typeof AbortController !== "undefined") {
    timeoutController = new AbortController();
    requestSignal = timeoutController.signal;
    timeoutId = window.setTimeout(() => {
      try {
        timeoutController.abort();
      } catch {
        // ignore
      }
    }, timeoutMs);
  }

  let response;
  try {
    response = await fetch(withBasePath(path), {
      headers: { "Content-Type": "application/json", ...(fetchOptions.headers || {}) },
      ...fetchOptions,
      ...(requestSignal ? { signal: requestSignal } : {}),
    });
  } catch (error) {
    if (timeoutId) {
      window.clearTimeout(timeoutId);
    }
    if (timeoutController && error?.name === "AbortError") {
      throw new Error(`Request timed out after ${timeoutMs}ms`);
    }
    throw error;
  }
  if (timeoutId) {
    window.clearTimeout(timeoutId);
  }

  if (!response.ok) {
    let detail = "Request failed";
    let detailPayload = null;
    try {
      const body = await response.json();
      detailPayload = body.detail || detail;
      if (detailPayload && typeof detailPayload === "object") {
        detail = String(detailPayload.message || detailPayload.detail || detail);
      } else {
        detail = String(detailPayload || detail);
      }
    } catch {
      detail = response.statusText || detail;
    }
    if (!skipAuthRecovery && _shouldTriggerWebuiAuthRecovery(path, response.status)) {
      void promptWebuiAuthRecovery(detail);
    }
    if (!skipRedisRecovery && _shouldTriggerRedisRecovery(path, response.status, detail)) {
      void promptRedisSetupRecovery(detail);
    }
    const error = new Error(detail);
    error.status = response.status;
    error.detail = detailPayload;
    if (detailPayload && typeof detailPayload === "object" && detailPayload.code) {
      error.code = String(detailPayload.code || "");
    }
    throw error;
  }

  if (response.status === 204) {
    return {};
  }

  return response.json();
}

function formatBytes(value) {
  const n = Math.max(0, Number(value) || 0);
  if (n >= 1024 * 1024 * 1024) {
    return `${(n / (1024 * 1024 * 1024)).toFixed(1)} GB`;
  }
  if (n >= 1024 * 1024) {
    return `${(n / (1024 * 1024)).toFixed(1)} MB`;
  }
  if (n >= 1024) {
    return `${(n / 1024).toFixed(1)} KB`;
  }
  return `${Math.round(n)} B`;
}

function formatByteRate(value) {
  const n = Math.max(0, Number(value) || 0);
  return n > 0 ? `${formatBytes(n)}/s` : "Idle";
}

function formatDurationShort(value) {
  const total = Math.max(0, Math.round(Number(value) || 0));
  if (total <= 0) {
    return "Unknown";
  }
  const hours = Math.floor(total / 3600);
  const minutes = Math.floor((total % 3600) / 60);
  const seconds = total % 60;
  if (hours > 0) {
    return `${hours}h ${minutes}m`;
  }
  if (minutes > 0) {
    return `${minutes}m ${seconds}s`;
  }
  return `${seconds}s`;
}

function clampPercent(value) {
  return Math.max(0, Math.min(100, Number(value) || 0));
}

function hfLlmWarmupPercent(snapshot) {
  const direct = Number(snapshot?.progress);
  if (Number.isFinite(direct) && direct > 0) {
    return clampPercent(direct);
  }
  const items = Array.isArray(snapshot?.items) ? snapshot.items : [];
  if (!items.length) {
    return snapshot?.running ? 8 : 0;
  }
  const sum = items.reduce((total, item) => total + clampPercent(item?.progress), 0);
  return clampPercent(sum / items.length);
}

function hfLlmWarmupStatusText(snapshot) {
  const running = Boolean(snapshot?.running);
  const errors = Array.isArray(snapshot?.errors) ? snapshot.errors.filter(Boolean) : [];
  const items = Array.isArray(snapshot?.items) ? snapshot.items : [];
  const active = items.find((item) => ["preparing", "downloading", "loading", "working", "cancelling"].includes(String(item?.status || "").toLowerCase()));
  if (running && active) {
    return String(active.message || active.status || "Working").trim();
  }
  if (running) {
    return "Preparing local model download...";
  }
  if (errors.length) {
    return errors[0];
  }
  if (items.some((item) => ["loaded", "downloaded"].includes(String(item?.status || "").toLowerCase()))) {
    return snapshot?.load_models === false ? "Local model downloaded." : "Local model ready.";
  }
  return "No local model download is running.";
}

function hfLlmWarmupActiveItem(snapshot) {
  const items = Array.isArray(snapshot?.items) ? snapshot.items : [];
  return (
    items.find((item) => Boolean(item?.active)) ||
    items.find((item) => ["preparing", "downloading", "loading", "working", "cancelling"].includes(String(item?.status || "").toLowerCase())) ||
    items[0] ||
    null
  );
}

function hfLlmProjectedByteStats(item) {
  const total = Math.max(0, Number(item?.download_total_bytes || item?.current_total_bytes || 0));
  let done = Math.max(0, Number(item?.download_bytes || item?.current_bytes || 0));
  const speed = Math.max(0, Number(item?.download_speed_bytes_per_sec || item?.current_speed_bytes_per_sec || 0));
  const status = String(item?.status || "").trim().toLowerCase();
  const updatedTs = Math.max(0, Number(item?.updated_ts || 0));
  const canProject =
    total > 0 &&
    done > 0 &&
    speed > 0 &&
    updatedTs > 0 &&
    done < total &&
    ["downloading", "working", "preparing"].includes(status);
  if (canProject) {
    const ageSeconds = Math.max(0, Date.now() / 1000 - updatedTs);
    const projectionSeconds = Math.min(ageSeconds, 20);
    done = Math.min(total, done + speed * projectionSeconds);
  }
  return {
    done,
    total,
    speed,
    eta: total > done && speed > 0 ? (total - done) / speed : 0,
  };
}

function hfLlmWarmupAggregateStats(snapshot) {
  const items = Array.isArray(snapshot?.items) ? snapshot.items : [];
  const active = hfLlmWarmupActiveItem(snapshot);
  const running = Boolean(snapshot?.running);
  const errors = Array.isArray(snapshot?.errors) ? snapshot.errors.filter(Boolean) : [];
  const loadedCount = items.filter((item) => ["loaded", "downloaded"].includes(String(item?.status || "").toLowerCase())).length;
  const errorCount = items.filter((item) => String(item?.status || "").toLowerCase() === "error").length;
  const cancelledCount = items.filter((item) => ["cancelled", "canceled"].includes(String(item?.status || "").toLowerCase())).length;
  const activeCount = items.filter((item) =>
    ["preparing", "downloading", "loading", "working", "cancelling"].includes(String(item?.status || "").toLowerCase())
  ).length;
  let bytesDone = 0;
  let bytesTotal = 0;
  let speed = 0;
  let eta = 0;
  items.forEach((item) => {
    const byteStats = hfLlmProjectedByteStats(item);
    if (byteStats.total > 0) {
      bytesDone += byteStats.done;
      bytesTotal += byteStats.total;
    }
    speed += byteStats.speed;
  });
  if (active) {
    const activeByteStats = hfLlmProjectedByteStats(active);
    eta = activeByteStats.eta || Number(active?.download_eta_seconds || active?.current_eta_seconds || active?.files_eta_seconds || 0);
  }
  return {
    items,
    active,
    running,
    errors,
    loadedCount,
    errorCount,
    cancelledCount,
    activeCount,
    percent: hfLlmWarmupPercent(snapshot),
    downloadPercent: bytesTotal > 0 ? clampPercent((bytesDone / bytesTotal) * 100) : 0,
    bytesDone,
    bytesTotal,
    speed,
    eta,
  };
}

function renderHfDownloadSummary(snapshot = {}) {
  const block = document.getElementById("hf-download-summary-block");
  if (!block) {
    return;
  }
  const stats = hfLlmWarmupAggregateStats(snapshot || {});
  const titleEl = document.getElementById("hf-download-summary-title");
  const detailEl = document.getElementById("hf-download-summary-detail");
  const statEl = document.getElementById("hf-download-summary-stat");
  const speedEl = document.getElementById("hf-download-summary-speed");
  const etaEl = document.getElementById("hf-download-summary-eta");
  const fillEl = document.getElementById("hf-download-summary-fill");
  const count = stats.items.length;
  const activeModel = String(stats.active?.model || "").trim();
  const hasErrors = stats.errors.length || stats.errorCount > 0;
  const tone = hasErrors ? "error" : stats.running ? "running" : stats.loadedCount > 0 ? "success" : stats.cancelledCount > 0 ? "cancelled" : "idle";
  const byteStat = stats.bytesTotal > 0 ? `${formatBytes(stats.bytesDone)} / ${formatBytes(stats.bytesTotal)}` : "";
  const fallbackStat = count
    ? `${stats.loadedCount} ready • ${stats.errorCount} failed • ${stats.cancelledCount} cancelled`
    : "No downloads yet";
  block.classList.toggle("is-running", tone === "running");
  block.classList.toggle("success", tone === "success");
  block.classList.toggle("error", tone === "error");
  block.classList.toggle("cancelled", tone === "cancelled");
  if (titleEl) {
    titleEl.textContent = stats.running
      ? activeModel || "Local model download"
      : hasErrors
        ? "Download needs attention"
        : stats.loadedCount > 0
          ? "Downloads complete"
          : stats.cancelledCount > 0
            ? "Downloads cancelled"
            : "Model downloads";
  }
  if (detailEl) {
    detailEl.textContent = stats.running
      ? hfLlmWarmupStatusText(snapshot)
      : count
        ? `${count} download${count === 1 ? "" : "s"} tracked`
        : "Click to view local model download details.";
  }
  if (statEl) {
    statEl.textContent = byteStat || fallbackStat;
  }
  if (speedEl) {
    speedEl.textContent = formatByteRate(stats.speed);
  }
  if (etaEl) {
    etaEl.textContent = stats.running && stats.eta > 0 ? `${formatDurationShort(stats.eta)} left` : stats.running ? "Calculating" : "Idle";
  }
  if (fillEl) {
    const fillPercent = stats.running && stats.bytesTotal > 0 ? stats.downloadPercent : stats.percent;
    fillEl.style.width = `${Math.max(stats.running ? 6 : 0, fillPercent)}%`;
    fillEl.classList.toggle("success", tone === "success");
    fillEl.classList.toggle("error", tone === "error");
  }
}

function renderHfLlmWarmupItem(item) {
  const providerLabel = String(item?.provider_label || "").trim();
  const model = String(item?.model || "local model").trim();
  const status = String(item?.status || "pending").trim().toLowerCase();
  const tone = status === "error" ? "error" : ["loaded", "downloaded"].includes(status) ? "success" : status === "cancelled" || status === "canceled" ? "cancelled" : "running";
  const message = String(item?.message || item?.error || status || "Pending").trim();
  const key = String(item?.key || "").trim();
  const canCancel = Boolean(item?.cancelable) && key;
  const detailParts = [];
  const byteStats = hfLlmProjectedByteStats(item);
  const byteProgress = byteStats.total > 0 ? clampPercent((byteStats.done / byteStats.total) * 100) : 0;
  const progress = ["loaded", "downloaded"].includes(status)
    ? 100
    : status === "downloading" && byteProgress > 0
      ? byteProgress
      : status === "downloading"
        ? clampPercent(item?.download_progress || item?.current_progress || item?.progress)
        : clampPercent(item?.progress);
  const filesTotal = Number(item?.files_total || 0);
  const filesCompleted = Number(item?.files_completed || 0);
  if (filesTotal > 0) {
    detailParts.push(`Files ${Math.max(0, Math.round(filesCompleted))}/${Math.max(0, Math.round(filesTotal))}`);
  }
  const currentTotalBytes = byteStats.total;
  const currentBytes = byteStats.done;
  if (currentTotalBytes > 0) {
    detailParts.push(`${formatBytes(currentBytes)} / ${formatBytes(currentTotalBytes)}`);
  }
  const speed = byteStats.speed;
  const eta = byteStats.eta || Number(item?.download_eta_seconds || item?.current_eta_seconds || 0);
  if (speed > 0) {
    detailParts.push(formatByteRate(speed));
  }
  if (eta > 0) {
    detailParts.push(`${formatDurationShort(eta)} left`);
  }
  if (item?.device) {
    detailParts.push(`Device ${String(item.device)}`);
  }
  const detail = detailParts.join(" • ");
  return `
    <div class="hf-llm-progress-item ${escapeHtml(tone)}">
      <div class="hf-llm-progress-item-head">
        <strong>${escapeHtml(providerLabel ? `${providerLabel}: ${model}` : model)}</strong>
        <span>${escapeHtml(status || "pending")}</span>
      </div>
      <div class="action-progress-track" aria-hidden="true">
        <div class="action-progress-fill ${tone === "success" ? "success" : tone === "error" ? "error" : ""}" style="width: ${Math.max(status === "downloading" ? 2 : 0, progress)}%"></div>
      </div>
      <div class="small">${escapeHtml(message)}</div>
      ${detail ? `<div class="small muted">${escapeHtml(detail)}</div>` : ""}
      ${canCancel ? `<div class="hf-llm-progress-item-actions"><button type="button" class="inline-btn" data-hf-download-cancel="${escapeHtml(key)}">Cancel</button></div>` : ""}
    </div>
  `;
}

function ensureHfLlmWarmupModal() {
  let modal = document.getElementById("hf-llm-warmup-modal");
  if (modal) {
    return modal;
  }

  document.body.insertAdjacentHTML(
    "beforeend",
    `
      <div id="hf-llm-warmup-modal" class="cerb-modal" aria-hidden="true">
        <div class="cerb-modal-dialog card action-progress-dialog hf-llm-progress-dialog" role="dialog" aria-modal="true" aria-label="Local Model Download">
          <div class="card-head">
            <h3 class="card-title">Local Model Download</h3>
            <button type="button" class="inline-btn" id="hf-llm-warmup-close">Close</button>
          </div>
          <div id="hf-llm-warmup-detail" class="small muted">Preparing...</div>
          <div class="action-progress-track" aria-hidden="true">
            <div id="hf-llm-warmup-fill" class="action-progress-fill"></div>
          </div>
          <div id="hf-llm-warmup-status" class="small action-progress-status">Starting...</div>
          <div id="hf-llm-warmup-items" class="hf-llm-progress-items"></div>
        </div>
      </div>
    `
  );

  modal = document.getElementById("hf-llm-warmup-modal");
  const closeBtn = document.getElementById("hf-llm-warmup-close");
  const closeModal = () => {
    closePopupModal(modal);
  };
  closeBtn?.addEventListener("click", closeModal);
  modal.addEventListener("click", (event) => {
    const cancelButton = event.target instanceof Element ? event.target.closest("[data-hf-download-cancel]") : null;
    if (cancelButton) {
      event.preventDefault();
      const key = String(cancelButton.getAttribute("data-hf-download-cancel") || "").trim();
      if (key) {
        void cancelHfLlmWarmupDownload(key);
      }
      return;
    }
    if (event.target === modal) {
      closeModal();
    }
  });
  document.addEventListener("keydown", (event) => {
    if (event.key === "Escape" && modal.classList.contains("active")) {
      closeModal();
    }
  });
  return modal;
}

function renderHfLlmWarmupModal(snapshot = {}) {
  const modal = ensureHfLlmWarmupModal();
  const running = Boolean(snapshot?.running);
  const errors = Array.isArray(snapshot?.errors) ? snapshot.errors.filter(Boolean) : [];
  const items = Array.isArray(snapshot?.items) ? snapshot.items : [];
  const percent = hfLlmWarmupPercent(snapshot);
  const tone = errors.length ? "error" : running ? "running" : percent >= 100 ? "success" : "running";
  const detailEl = document.getElementById("hf-llm-warmup-detail");
  const fillEl = document.getElementById("hf-llm-warmup-fill");
  const statusEl = document.getElementById("hf-llm-warmup-status");
  const itemsEl = document.getElementById("hf-llm-warmup-items");
  const closeBtn = document.getElementById("hf-llm-warmup-close");

  modal.dataset.running = running ? "true" : "false";
  if (detailEl) {
    const loadsModel = snapshot?.load_models !== false;
    detailEl.textContent = running
      ? "Download continues in the background across refreshes and tab changes."
      : errors.length
        ? loadsModel
          ? "The download/load task stopped with an error."
          : "The download stopped with an error."
        : loadsModel
          ? "Download/load finished."
          : "Download finished.";
  }
  if (fillEl) {
    fillEl.style.width = `${Math.max(running ? 6 : 0, percent)}%`;
    fillEl.classList.toggle("success", tone === "success");
    fillEl.classList.toggle("error", tone === "error");
  }
  if (statusEl) {
    statusEl.textContent = hfLlmWarmupStatusText(snapshot);
    statusEl.classList.toggle("success", tone === "success");
    statusEl.classList.toggle("error", tone === "error");
  }
  if (itemsEl) {
    itemsEl.innerHTML = items.length ? items.map((item) => renderHfLlmWarmupItem(item)).join("") : `<div class="small muted">Waiting for model download state...</div>`;
  }
  if (closeBtn) {
    closeBtn.disabled = false;
    closeBtn.textContent = "Close";
  }
  return modal;
}

async function cancelHfLlmWarmupDownload(key = "") {
  const cleanKey = String(key || "").trim();
  try {
    const snapshot = await api("/api/settings/hf-llm/warmup/cancel", {
      method: "POST",
      body: JSON.stringify(cleanKey ? { key: cleanKey } : { cancel_all: true }),
      _skipRedisRecovery: true,
      _timeoutMs: HEALTH_REQUEST_TIMEOUT_MS,
    });
    state.hfLlmWarmupLastSnapshot = snapshot;
    renderHfDownloadSummary(snapshot);
    renderHfLlmWarmupModal(snapshot);
    scheduleHfLlmWarmupPoll(650);
  } catch (error) {
    showToast(`Cancel failed: ${error.message}`, "error", 3200);
  }
}

function updateHfLlmWarmupUi(snapshot = {}) {
  state.hfLlmWarmupLastSnapshot = snapshot;
  renderHfDownloadSummary(snapshot);
  const modal = document.getElementById("hf-llm-warmup-modal");
  if (modal?.classList.contains("active")) {
    renderHfLlmWarmupModal(snapshot);
  }
}

function scheduleHfLlmWarmupPoll(delayMs = 1000) {
  if (state.hfLlmWarmupPollTimer) {
    window.clearTimeout(state.hfLlmWarmupPollTimer);
    state.hfLlmWarmupPollTimer = 0;
  }
  state.hfLlmWarmupPollTimer = window.setTimeout(async () => {
    state.hfLlmWarmupPollTimer = 0;
    try {
      const snapshot = await api("/api/settings/hf-llm/warmup", { _skipRedisRecovery: true });
      updateHfLlmWarmupUi(snapshot);
      if (snapshot?.running) {
        scheduleHfLlmWarmupPoll(500);
      }
    } catch (error) {
      updateHfLlmWarmupUi({
        running: false,
        errors: [String(error?.message || "Failed to read local model download progress.")],
        items: state.hfLlmWarmupLastSnapshot?.items || [],
        progress: hfLlmWarmupPercent(state.hfLlmWarmupLastSnapshot || {}),
      });
    }
  }, Math.max(250, Number(delayMs) || 1000));
}

function openHfLlmWarmupModal(snapshot = null) {
  const initial = snapshot && typeof snapshot === "object" ? snapshot : state.hfLlmWarmupLastSnapshot || {};
  updateHfLlmWarmupUi(initial);
  const modal = renderHfLlmWarmupModal(initial);
  openPopupModal(modal);
  if (initial?.running || initial?.started || initial?.already_running) {
    scheduleHfLlmWarmupPoll(450);
  }
}

function maybeOpenHfLlmWarmupModal(snapshot) {
  if (!snapshot || typeof snapshot !== "object") {
    return;
  }
  updateHfLlmWarmupUi(snapshot);
  if (snapshot.running || snapshot.started || snapshot.already_running) {
    scheduleHfLlmWarmupPoll(450);
  }
}

async function reconnectHfLlmWarmupModal() {
  try {
    const snapshot = await api("/api/settings/hf-llm/warmup", { _skipRedisRecovery: true });
    maybeOpenHfLlmWarmupModal(snapshot);
  } catch {
    // Best effort: the settings page can still reconnect on its own.
  }
}

function safeJsonParse(raw) {
  try {
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

function readFileAsDataUrl(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(String(reader.result || ""));
    reader.onerror = () => reject(new Error("Failed to read image file."));
    reader.readAsDataURL(file);
  });
}

function boolFromAny(value, fallback = false) {
  if (typeof value === "boolean") {
    return value;
  }
  if (value === null || value === undefined) {
    return Boolean(fallback);
  }
  const text = String(value).trim().toLowerCase();
  if (["1", "true", "yes", "y", "on", "enabled"].includes(text)) {
    return true;
  }
  if (["0", "false", "no", "n", "off", "disabled"].includes(text)) {
    return false;
  }
  return Boolean(fallback);
}

function renderNotice(text) {
  return `<div class="notice">${escapeHtml(text)}</div>`;
}

function consumeNoticeHtml() {
  const text = String(state.notice || "").trim();
  state.notice = "";
  if (!text) {
    return "";
  }
  return renderNotice(text);
}

function normalizeSettingsTab(value) {
  const token = String(value || "").trim().toLowerCase();
  return SETTINGS_TAB_KEYS.includes(token) ? token : "general";
}

function setPreferredSettingsTab(tabKey) {
  const normalized = normalizeSettingsTab(tabKey);
  state.settingsTab = normalized;
  safeStorageSet("tater_tateros_settings_tab", normalized);
  return normalized;
}

function setPreferredIntegrationTab(tabKey) {
  const token = String(tabKey || "").trim().toLowerCase();
  const normalized = ["setup", "manager", "devices", "runtime"].includes(token) ? token : "setup";
  state.integrationSubtab = normalized;
  safeStorageSet("tater_tateros_integration_tab", normalized);
  return normalized;
}

function parseSettingValue(raw, type) {
  if (type === "number") {
    const parsed = Number(raw);
    return Number.isNaN(parsed) ? 0 : parsed;
  }
  if (type === "multiselect") {
    if (Array.isArray(raw)) {
      return raw
        .map((item) => String(item || "").trim())
        .filter(Boolean);
    }
    return [];
  }
  if (type === "checkbox") {
    return Boolean(raw);
  }
  return raw;
}

function renderToggleRow(inputHtml, statusText = "Enabled") {
  return `<div class="inline-row toggle-row">${inputHtml}<span class="small">${escapeHtml(statusText)}</span></div>`;
}

function renderSettingsSectionIntro(title, description = "", badge = "", variant = "primary") {
  const safeTitle = String(title || "").trim();
  if (!safeTitle) {
    return "";
  }
  const safeBadge = String(badge || safeTitle.slice(0, 2)).trim().slice(0, 4).toUpperCase();
  const safeDescription = String(description || "").trim();
  const variantClass = String(variant || "").trim().toLowerCase() === "subtle" ? " is-subtle" : "";
  return `
    <div class="settings-section-intro${variantClass}">
      <span class="settings-section-intro-badge" aria-hidden="true">${escapeHtml(safeBadge || "T")}</span>
      <div>
        <h3>${escapeHtml(safeTitle)}</h3>
        ${safeDescription ? `<p>${escapeHtml(safeDescription)}</p>` : ""}
      </div>
    </div>
  `;
}

function settingsIntegrationDomPart(value) {
  return String(value || "")
    .trim()
    .replace(/[^a-zA-Z0-9_-]+/g, "_")
    .replace(/^_+|_+$/g, "") || "integration";
}

function settingsIntegrationFieldId(integrationId, fieldKey) {
  return `set_integration_${settingsIntegrationDomPart(integrationId)}_${settingsIntegrationDomPart(fieldKey)}`;
}

function settingsIntegrationStatusId(integrationId) {
  return `settings-integration-status-${settingsIntegrationDomPart(integrationId)}`;
}

function settingsIntegrationActionId(integrationId, actionId) {
  return `settings-integration-action-${settingsIntegrationDomPart(integrationId)}-${settingsIntegrationDomPart(actionId)}`;
}

function settingsIntegrationValue(integration, field) {
  const values = integration?.values && typeof integration.values === "object" ? integration.values : {};
  const key = String(field?.key || "").trim();
  if (key && Object.prototype.hasOwnProperty.call(values, key)) {
    return values[key];
  }
  return field?.default ?? "";
}

function renderSettingsIntegrationField(integration, field) {
  const integrationId = String(integration?.id || "").trim();
  const key = String(field?.key || "").trim();
  if (!integrationId || !key) {
    return "";
  }
  const label = String(field?.label || key).trim() || key;
  const type = String(field?.type || "text").trim().toLowerCase();
  const value = settingsIntegrationValue(integration, field);
  const inputId = settingsIntegrationFieldId(integrationId, key);
  const description = String(field?.description || "").trim();
  const descHtml = description ? `<div class="small">${escapeHtml(description)}</div>` : "";
  const placeholder = String(field?.placeholder || "").trim();
  const placeholderAttr = placeholder ? ` placeholder="${escapeHtml(placeholder).replace(/\n/g, "&#10;")}"` : "";
  const minAttr = field?.min !== undefined ? ` min="${escapeHtml(String(field.min))}"` : "";
  const maxAttr = field?.max !== undefined ? ` max="${escapeHtml(String(field.max))}"` : "";
  const stepAttr = field?.step !== undefined ? ` step="${escapeHtml(String(field.step))}"` : "";
  const fullWidth = boolFromAny(field?.full_width, false) || type === "textarea";
  const styleAttr = fullWidth ? ` style="grid-column: 1 / -1;"` : "";

  if (type === "checkbox") {
    return `<label${styleAttr}>${escapeHtml(label)}
      ${renderToggleRow(
        `<input id="${escapeHtml(inputId)}" class="toggle-input" type="checkbox" ${
          boolFromAny(value, boolFromAny(field?.default, false)) ? "checked" : ""
        } />`
      )}
      ${descHtml}
    </label>`;
  }

  if (type === "textarea") {
    const rows = Number(field?.rows || 3);
    return `<label${styleAttr}>${escapeHtml(label)}
      <textarea id="${escapeHtml(inputId)}" rows="${escapeHtml(String(Math.max(2, rows)))}"${placeholderAttr}>${escapeHtml(
        String(value ?? "")
      )}</textarea>
      ${descHtml}
    </label>`;
  }

  const inputType = type === "password" || type === "number" || type === "email" || type === "url" ? type : "text";
  return `<label${styleAttr}>${escapeHtml(label)}
    <input
      id="${escapeHtml(inputId)}"
      type="${escapeHtml(inputType)}"
      value="${escapeHtml(String(value ?? ""))}"
      ${placeholderAttr}${minAttr}${maxAttr}${stepAttr}
    />
    ${descHtml}
  </label>`;
}

function renderSettingsIntegrationSection(integration) {
  const integrationId = String(integration?.id || "").trim();
  if (!integrationId) {
    return "";
  }
  const name = String(integration?.name || integrationId).trim() || integrationId;
  const fields = Array.isArray(integration?.fields) ? integration.fields : [];
  const actions = Array.isArray(integration?.actions) ? integration.actions : [];
  const description = String(integration?.description || "").trim();
  const status = integration?.status && typeof integration.status === "object" ? integration.status : {};
  const initialStatus = String(status.message || actions[0]?.status || "").trim();
  return `
    <section class="core-inline-section" data-settings-integration="${escapeHtml(integrationId)}">
      <div class="small core-inline-section-title">${escapeHtml(name)}</div>
      ${description ? `<div class="small">${escapeHtml(description)}</div>` : ""}
      <div class="form-grid two-col" style="margin-top: 10px;">
        ${fields.map((field) => renderSettingsIntegrationField(integration, field)).join("")}
      </div>
      ${
        actions.length
          ? `<div class="inline-row">
              ${actions
                .map((action) => {
                  const actionId = String(action?.id || "").trim();
                  if (!actionId) {
                    return "";
                  }
                  const label = String(action?.label || actionId).trim() || actionId;
                  return `<button type="button" id="${escapeHtml(
                    settingsIntegrationActionId(integrationId, actionId)
                  )}" class="action-btn">${escapeHtml(label)}</button>`;
                })
                .join("")}
              <span id="${escapeHtml(settingsIntegrationStatusId(integrationId))}" class="small">${escapeHtml(initialStatus)}</span>
            </div>`
          : ""
      }
    </section>
  `;
}

function renderSettingsIntegrationSections(settings) {
  const integrations = Array.isArray(settings?.integrations) ? settings.integrations : [];
  if (!integrations.length) {
    return renderNotice("No direct integrations are registered.");
  }
  return integrations.map((integration) => renderSettingsIntegrationSection(integration)).join("");
}

function integrationRuntimeStatusLabel(runtime, prefix) {
  const configured = runtime?.[`${prefix}_configured`];
  const connected = boolFromAny(runtime?.[`${prefix}_ws_connected`], false) || boolFromAny(runtime?.[`${prefix}_connected`], false);
  if (connected) {
    return "Connected";
  }
  if (configured === false || String(configured).toLowerCase() === "false") {
    return "Not configured";
  }
  return "Disconnected";
}

function integrationRuntimeTimeLabel(epochRaw) {
  const epoch = Number(epochRaw || 0);
  if (!Number.isFinite(epoch) || epoch <= 0) {
    return "-";
  }
  return `${_runtimeAgeLabel(Math.max(0, Date.now() / 1000 - epoch))} ago`;
}

function integrationRuntimeNameFromId(integrationId) {
  const id = String(integrationId || "").trim();
  const known = {
    aladdin: "Aladdin",
    brave_search: "Brave Search",
    ecobee_homekit: "Ecobee",
    google_search: "Google Search",
    homeassistant: "Home Assistant",
    homekit: "HomeKit",
    hue: "Philips Hue",
    searxng_search: "SearXNG Search",
    serper_search: "Serper Search",
    sonos: "Sonos",
    unifi_network: "UniFi Network",
    unifi_protect: "UniFi Protect",
    weather_api: "WeatherAPI",
  };
  if (known[id]) {
    return known[id];
  }
  return id
    .split("_")
    .filter(Boolean)
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ") || "Integration";
}

function integrationRuntimeProviderIds(runtime) {
  const enabled = Array.isArray(runtime?.enabled_integrations)
    ? runtime.enabled_integrations.map((item) => String(item || "").trim()).filter(Boolean)
    : [];
  if (enabled.length) {
    return enabled;
  }
  return ["homeassistant", "unifi_protect", "unifi_network", "hue", "homekit"].filter((id) =>
    Object.prototype.hasOwnProperty.call(runtime || {}, `${id === "homekit" ? "ecobee_homekit" : id}_connected`) ||
    Object.prototype.hasOwnProperty.call(runtime || {}, `${id === "homekit" ? "ecobee_homekit" : id}_configured`)
  );
}

function integrationRuntimeStatusPrefix(integrationId) {
  return integrationId === "homekit" ? "ecobee_homekit" : integrationId;
}

function integrationRuntimeProviderIsEnabled(provider, enabledIds) {
  const token = String(provider || "").trim();
  const owner = token === "ecobee_homekit" ? "homekit" : token;
  const enabled = new Set((Array.isArray(enabledIds) ? enabledIds : []).map((item) => String(item || "").trim()).filter(Boolean));
  return !token || enabled.has(token) || enabled.has(owner);
}

function renderSettingsIntegrationRuntimeSummary(runtime) {
  const row = runtime && typeof runtime === "object" ? runtime : {};
  const providerIds = integrationRuntimeProviderIds(row);
  const showLastEvent = row.last_event_ts && integrationRuntimeProviderIsEnabled(row.last_event_provider, providerIds);
  const providerHtml = providerIds.length
    ? providerIds
        .map((integrationId) => {
          const prefix = integrationRuntimeStatusPrefix(integrationId);
          const hasRuntimeFields = [
            `${prefix}_configured`,
            `${prefix}_connected`,
            `${prefix}_ws_connected`,
            `${prefix}_poll_connected`,
            `${prefix}_eventstream_connected`,
          ].some((field) => Object.prototype.hasOwnProperty.call(row, field));
          const statusText = hasRuntimeFields ? integrationRuntimeStatusLabel(row, prefix) : "Enabled";
          return `
            <div class="core-metric-pill">
              <div class="small">${escapeHtml(integrationRuntimeNameFromId(integrationId))}</div>
              <strong>${escapeHtml(statusText)}</strong>
            </div>
          `;
        })
        .join("")
    : `
      <div class="core-metric-pill">
        <div class="small">Integrations</div>
        <strong>None enabled</strong>
      </div>
    `;
  return `
    <div class="core-metric-row">
      ${providerHtml}
      <div class="core-metric-pill">
        <div class="small">Events</div>
        <strong>${escapeHtml(String(row.last_event_seq || 0))}</strong>
      </div>
      <div class="core-metric-pill">
        <div class="small">Live States</div>
        <strong>${escapeHtml(String(row.state_count || 0))}</strong>
      </div>
    </div>
    ${
      showLastEvent
        ? `<div class="small" style="margin-top: 8px;">Last event ${escapeHtml(
            integrationRuntimeTimeLabel(row.last_event_ts)
          )}</div>`
        : ""
    }
  `;
}

function renderSettingsIntegrationRuntimeStates(payload) {
  const states = Array.isArray(payload?.states) ? payload.states : [];
  if (!states.length) {
    return `<div class="small">No live device states have been seen yet.</div>`;
  }
  return `
    <div class="core-data-table-wrap">
      <table class="core-data-table">
        <thead>
          <tr>
            <th>Provider</th>
            <th>Device / Sensor</th>
            <th>State</th>
            <th>Updated</th>
          </tr>
        </thead>
        <tbody>
          ${states
            .slice(0, 80)
            .map((row) => {
              const payload = row?.payload && typeof row.payload === "object" ? row.payload : {};
              const provider = String(row?.provider || "").replace(/_/g, " ");
              const stateText = String(payload.state ?? payload.event_type ?? payload.id ?? "").trim() || "-";
              return `
                <tr>
                  <td>${escapeHtml(provider || "-")}</td>
                  <td>${escapeHtml(String(row?.id || row?.key || "-"))}</td>
                  <td>${escapeHtml(stateText)}</td>
                  <td>${escapeHtml(integrationRuntimeTimeLabel(row?.updated_at))}</td>
                </tr>
              `;
            })
            .join("")}
        </tbody>
      </table>
    </div>
  `;
}

function renderSettingsIntegrationRuntime(settings) {
  return `
    <section class="core-inline-section" id="settings-integration-runtime">
      <div class="inline-row" style="justify-content: space-between; align-items: center;">
        <div>
          <div class="small core-inline-section-title">Live Runtime</div>
          <div class="small">Shared integration streams, pollers, and live device state.</div>
        </div>
        <button type="button" id="settings-integration-runtime-refresh" class="action-btn">Refresh</button>
      </div>
      <div id="settings-integration-runtime-summary">
        ${renderSettingsIntegrationRuntimeSummary(settings?.integration_runtime || {})}
      </div>
      <div id="settings-integration-runtime-states" style="margin-top: 10px;">
        <div class="small">Loading live device states...</div>
      </div>
    </section>
  `;
}

function integrationDeviceValueText(value) {
  if (value === null || value === undefined || value === "") {
    return "";
  }
  if (typeof value === "boolean") {
    return value ? "yes" : "no";
  }
  if (typeof value === "number") {
    return Number.isFinite(value) ? String(value) : "";
  }
  if (typeof value === "object") {
    try {
      const text = JSON.stringify(value);
      return text.length > 180 ? `${text.slice(0, 177)}...` : text;
    } catch {
      return "";
    }
  }
  return String(value);
}

function integrationDeviceDetailsHtml(details) {
  const row = details && typeof details === "object" ? details : {};
  const items = Object.entries(row)
    .map(([key, value]) => [String(key || "").trim(), integrationDeviceValueText(value)])
    .filter(([key, value]) => key && value);
  if (!items.length) {
    return "-";
  }
  return items
    .map(([key, value]) => `<div><strong>${escapeHtml(key)}:</strong> ${escapeHtml(value)}</div>`)
    .join("");
}

function renderSettingsIntegrationDeviceGroup(group) {
  const devices = Array.isArray(group?.devices) ? group.devices : [];
  const name = String(group?.name || group?.id || "Integration").trim();
  const message = String(group?.error || group?.message || "").trim();
  return `
    <section class="core-inline-section" data-integration-devices="${escapeHtml(String(group?.id || ""))}">
      <div class="inline-row" style="justify-content: space-between; align-items: center;">
        <div>
          <div class="small core-inline-section-title">${escapeHtml(name)}</div>
          ${message ? `<div class="small">${escapeHtml(message)}</div>` : ""}
        </div>
        <span class="small">${escapeHtml(String(devices.length))} device${devices.length === 1 ? "" : "s"}</span>
      </div>
      ${
        devices.length
          ? `<div class="core-data-table-wrap" style="margin-top: 10px;">
              <table class="core-data-table">
                <thead>
                  <tr>
                    <th>Name</th>
                    <th>Type</th>
                    <th>Current</th>
                    <th>Area</th>
                    <th>Info</th>
                  </tr>
                </thead>
                <tbody>
                  ${devices
                    .map((device) => {
                      const current = String(device?.state || device?.status || "").trim() || "-";
                      return `
                        <tr>
                          <td>${escapeHtml(String(device?.name || device?.id || "Device"))}</td>
                          <td>${escapeHtml(String(device?.type || "device"))}</td>
                          <td>${escapeHtml(current)}</td>
                          <td>${escapeHtml(String(device?.area || "-"))}</td>
                          <td>${integrationDeviceDetailsHtml(device?.details)}</td>
                        </tr>
                      `;
                    })
                    .join("")}
                </tbody>
              </table>
            </div>`
          : `<div class="small" style="margin-top: 8px;">No devices returned from this integration.</div>`
      }
    </section>
  `;
}

function renderSettingsIntegrationDevices(payload) {
  const groups = Array.isArray(payload?.groups) ? payload.groups : [];
  if (!groups.length) {
    return renderNotice("No integrations are registered.");
  }
  return groups.map((group) => renderSettingsIntegrationDeviceGroup(group)).join("");
}

function renderSettingsIntegrationDeviceTabs(integrations) {
  const rows = (Array.isArray(integrations) ? integrations : [])
    .map((integration) => ({
      id: String(integration?.id || "").trim(),
      name: String(integration?.name || integration?.id || "Integration").trim(),
      badge: String(integration?.badge || "").trim(),
    }))
    .filter((integration) => integration.id);
  if (!rows.length) {
    return `<div class="small">No integrations are registered.</div>`;
  }
  return `
    <div class="settings-subtabs settings-integration-device-tabs">
      ${rows
        .map(
          (integration, index) => `
            <button
              type="button"
              class="settings-subtab-btn${index === 0 ? " active" : ""}"
              data-integration-device-tab="${escapeHtml(integration.id)}"
            >
              ${integration.badge ? `<span>${escapeHtml(integration.badge)}</span> ` : ""}${escapeHtml(integration.name || integration.id)}
            </button>
          `
        )
        .join("")}
    </div>
  `;
}

function renderSettingsIntegrationDevicesShell(integrations = []) {
  const rows = (Array.isArray(integrations) ? integrations : []).filter((integration) =>
    String(integration?.id || "").trim()
  );
  const firstId = String(rows[0]?.id || "").trim();
  return `
    <section class="core-inline-section" id="settings-integration-devices" data-active-device-integration="${escapeHtml(firstId)}">
      <div class="inline-row" style="justify-content: space-between; align-items: center;">
        <div>
          <div class="small core-inline-section-title">Devices</div>
          <div class="small">Current devices and entities by integration.</div>
        </div>
        <button type="button" id="settings-integration-devices-refresh" class="action-btn"${firstId ? "" : " disabled"}>Refresh</button>
      </div>
      ${renderSettingsIntegrationDeviceTabs(rows)}
      <div id="settings-integration-devices-content" style="margin-top: 10px;">
        <div class="small">${firstId ? "Open or refresh this tab to load devices." : "No integrations are registered."}</div>
      </div>
    </section>
  `;
}

function bindSettingsIntegrationDevices() {
  const host = document.getElementById("settings-integration-devices");
  const contentEl = document.getElementById("settings-integration-devices-content");
  const button = document.getElementById("settings-integration-devices-refresh");
  const tabButtons = Array.from(document.querySelectorAll("[data-integration-device-tab]"));
  if (!host || !contentEl || !button) {
    return;
  }

  const loadIntegrationDevices = async (integrationIdRaw) => {
    const integrationId = String(integrationIdRaw || host.dataset.activeDeviceIntegration || "").trim();
    if (!integrationId) {
      contentEl.innerHTML = `<div class="small">Choose an integration to load devices.</div>`;
      return;
    }
    host.dataset.activeDeviceIntegration = integrationId;
    tabButtons.forEach((tabButton) => {
      tabButton.classList.toggle("active", tabButton.dataset.integrationDeviceTab === integrationId);
    });
    button.disabled = true;
    button.textContent = "Refreshing...";
    contentEl.innerHTML = `<div class="small">Loading devices...</div>`;
    try {
      const payload = await api(`/api/settings/integrations/${encodeURIComponent(integrationId)}/devices`);
      contentEl.innerHTML = renderSettingsIntegrationDeviceGroup(payload?.group || {});
    } catch (error) {
      contentEl.innerHTML = `<div class="notice error">Device refresh failed: ${escapeHtml(error.message)}</div>`;
    } finally {
      button.disabled = false;
      button.textContent = "Refresh";
    }
  };

  tabButtons.forEach((tabButton) => {
    tabButton.addEventListener("click", () => loadIntegrationDevices(tabButton.dataset.integrationDeviceTab));
  });
  button.addEventListener("click", () => loadIntegrationDevices(host.dataset.activeDeviceIntegration));
}

function bindSettingsIntegrationRuntime() {
  const summaryEl = document.getElementById("settings-integration-runtime-summary");
  const statesEl = document.getElementById("settings-integration-runtime-states");
  const button = document.getElementById("settings-integration-runtime-refresh");
  if (!summaryEl || !statesEl) {
    return;
  }
  const refresh = async () => {
    if (button) {
      button.disabled = true;
      button.textContent = "Refreshing...";
    }
    try {
      const [runtimePayload, statesPayload] = await Promise.all([
        api("/api/settings/integrations/runtime"),
        api("/api/settings/integrations/runtime/states"),
      ]);
      summaryEl.innerHTML = renderSettingsIntegrationRuntimeSummary(runtimePayload?.runtime || {});
      statesEl.innerHTML = renderSettingsIntegrationRuntimeStates(statesPayload || {});
    } catch (error) {
      statesEl.innerHTML = `<div class="notice error">Runtime refresh failed: ${escapeHtml(error.message)}</div>`;
    } finally {
      if (button) {
        button.disabled = false;
        button.textContent = "Refresh";
      }
    }
  };
  button?.addEventListener("click", refresh);
  refresh();
}

function bindSettingsIntegrationTabs(root = document) {
  const host =
    root instanceof HTMLElement
      ? root.querySelector("#settings-integrations-shell")
      : document.getElementById("settings-integrations-shell");
  if (!(host instanceof HTMLElement)) {
    return;
  }
  const buttons = Array.from(host.querySelectorAll(".settings-subtab-btn[data-integrations-tab]"));
  const panels = Array.from(host.querySelectorAll(".settings-subpanel[data-integrations-panel]"));
  if (!buttons.length || !panels.length) {
    return;
  }
  const activate = (tabKey) => {
    const key = String(tabKey || "setup").trim() || "setup";
    setPreferredIntegrationTab(key);
    host.dataset.integrationsActiveTab = key;
    buttons.forEach((button) => {
      button.classList.toggle("active", button.dataset.integrationsTab === key);
    });
    panels.forEach((panel) => {
      panel.classList.toggle("active", panel.dataset.integrationsPanel === key);
    });
    if (key === "runtime") {
      document.getElementById("settings-integration-runtime-refresh")?.click();
    } else if (key === "devices") {
      document.getElementById("settings-integration-devices-refresh")?.click();
    }
  };
  const refreshIntegrationSubtab = async (tabKey) => {
    const key = String(tabKey || "setup").trim() || "setup";
    if (host.dataset.integrationsSubtabRefreshing === "1") {
      return;
    }
    host.dataset.integrationsSubtabRefreshing = "1";
    setPreferredSettingsTab("integrations");
    setPreferredIntegrationTab(key);
    try {
      await loadSettingsView();
    } catch (error) {
      activate(key);
      showToast(`Integration ${key} refresh failed: ${error.message}`, "error", 3600);
    } finally {
      if (document.body.contains(host)) {
        delete host.dataset.integrationsSubtabRefreshing;
      }
    }
  };
  buttons.forEach((button) => {
    if (button.dataset.integrationsTabBound === "1") {
      return;
    }
    button.dataset.integrationsTabBound = "1";
    button.addEventListener("click", () => {
      const key = String(button.dataset.integrationsTab || "setup").trim() || "setup";
      if (key === "setup" || key === "devices") {
        refreshIntegrationSubtab(key);
        return;
      }
      activate(key);
    });
  });
  activate(String(host.dataset.integrationsActiveTab || state.integrationSubtab || "setup").trim() || "setup");
}

function collectSettingsIntegrationPayload(integration) {
  const out = {};
  const integrationId = String(integration?.id || "").trim();
  const fields = Array.isArray(integration?.fields) ? integration.fields : [];
  fields.forEach((field) => {
    const key = String(field?.key || "").trim();
    if (!integrationId || !key) {
      return;
    }
    const el = document.getElementById(settingsIntegrationFieldId(integrationId, key));
    if (!el) {
      return;
    }
    const type = String(field?.type || "text").trim().toLowerCase();
    if (type === "checkbox") {
      out[key] = Boolean(el.checked);
    } else if (type === "number") {
      out[key] = Number(el.value || field?.default || 0);
    } else {
      out[key] = el.value;
    }
  });
  return out;
}

function applySettingsIntegrationResult(integration, result) {
  const values = {
    ...(result && typeof result === "object" ? result : {}),
    ...(result?.values && typeof result.values === "object" ? result.values : {}),
  };
  const integrationId = String(integration?.id || "").trim();
  const fields = Array.isArray(integration?.fields) ? integration.fields : [];
  fields.forEach((field) => {
    const key = String(field?.key || "").trim();
    if (!integrationId || !key || !Object.prototype.hasOwnProperty.call(values, key)) {
      return;
    }
    const el = document.getElementById(settingsIntegrationFieldId(integrationId, key));
    if (!el) {
      return;
    }
    const type = String(field?.type || "text").trim().toLowerCase();
    if (type === "checkbox") {
      el.checked = boolFromAny(values[key], false);
    } else {
      el.value = String(values[key] ?? "");
    }
  });
}

function bindSettingsIntegrationActions(integrations, statusEl) {
  (Array.isArray(integrations) ? integrations : []).forEach((integration) => {
    const integrationId = String(integration?.id || "").trim();
    const actions = Array.isArray(integration?.actions) ? integration.actions : [];
    actions.forEach((action) => {
      const actionId = String(action?.id || "").trim();
      if (!integrationId || !actionId) {
        return;
      }
      const button = document.getElementById(settingsIntegrationActionId(integrationId, actionId));
      if (!button) {
        return;
      }
      const sectionStatusEl = document.getElementById(settingsIntegrationStatusId(integrationId));
      const originalText = button.textContent || String(action?.label || actionId || "Run");
      button.addEventListener("click", async () => {
        button.disabled = true;
        button.textContent = "Working...";
        const pending = String(action?.status || `Running ${originalText}...`).trim();
        if (sectionStatusEl) {
          sectionStatusEl.textContent = pending;
        }
        if (statusEl) {
          statusEl.textContent = pending;
        }
        try {
          const result = await api(
            `/api/settings/integrations/${encodeURIComponent(integrationId)}/actions/${encodeURIComponent(actionId)}`,
            {
              method: "POST",
              body: JSON.stringify({ payload: collectSettingsIntegrationPayload(integration) }),
            }
          );
          applySettingsIntegrationResult(integration, result);
          const message = String(result?.message || (result?.ok === false ? `${originalText} failed.` : `${originalText} complete.`));
          if (sectionStatusEl) {
            sectionStatusEl.textContent = message;
          }
          if (statusEl) {
            statusEl.textContent = message;
          }
          showToast(message, result?.ok === false ? "error" : "success", result?.ok === false ? 4200 : 2800);
        } catch (error) {
          const message = `${originalText} failed: ${error.message}`;
          if (sectionStatusEl) {
            sectionStatusEl.textContent = message;
          }
          if (statusEl) {
            statusEl.textContent = message;
          }
          showToast(message, "error", 5200);
        } finally {
          button.disabled = false;
          button.textContent = originalText;
        }
      });
    });
  });
}

function renderSimpleDataTable(columns, rows, emptyMessage = "No rows.") {
  const cols = Array.isArray(columns) ? columns : [];
  const list = Array.isArray(rows) ? rows : [];
  if (!cols.length) {
    return `<div class="small">${escapeHtml(emptyMessage)}</div>`;
  }
  const head = cols.map((col) => `<th>${escapeHtml(col.label || col.key || "")}</th>`).join("");
  const body = list.length
    ? list
        .map((row) => {
          const cells = cols
            .map((col) => {
              const value = row && typeof row === "object" ? row[col.key] : "";
              return `<td>${escapeHtml(value ?? "")}</td>`;
            })
            .join("");
          return `<tr>${cells}</tr>`;
        })
        .join("")
    : `<tr><td colspan="${cols.length}" class="small">${escapeHtml(emptyMessage)}</td></tr>`;

  return `
    <div class="core-data-table-wrap">
      <table class="core-data-table">
        <thead><tr>${head}</tr></thead>
        <tbody>${body}</tbody>
      </table>
    </div>
  `;
}

function renderSimpleBarChart(points, emptyMessage = "No chart data.") {
  const rows = Array.isArray(points) ? points : [];
  const cleaned = rows
    .map((point) => {
      if (point && typeof point === "object") {
        const label = String(point.label ?? point.key ?? point.name ?? "").trim();
        const value = Number(point.value ?? point.count ?? 0);
        return {
          label: label || "item",
          value: Number.isFinite(value) ? value : 0,
        };
      }
      return {
        label: String(point ?? "").trim() || "item",
        value: 0,
      };
    })
    .filter((row) => row.label);
  if (!cleaned.length) {
    return `<div class="small">${escapeHtml(emptyMessage)}</div>`;
  }
  const maxValue = cleaned.reduce((acc, row) => Math.max(acc, row.value), 0);
  return `
    <div class="core-bar-chart">
      ${cleaned
        .map((row) => {
          const widthPct = maxValue > 0 ? Math.max(0, Math.min(100, (row.value / maxValue) * 100)) : 0;
          return `
            <div class="core-bar-row">
              <div class="core-bar-label">${escapeHtml(row.label)}</div>
              <div class="core-bar-track"><div class="core-bar-fill" style="width:${widthPct}%;"></div></div>
              <div class="core-bar-value">${escapeHtml(String(row.value))}</div>
            </div>
          `;
        })
        .join("")}
    </div>
  `;
}

function hydraPlatformLabel(platform) {
  const token = String(platform || "").trim().toLowerCase();
  const labels = {
    all: "All",
    webui: "WebUI",
    discord: "Discord",
    irc: "IRC",
    telegram: "Telegram",
    matrix: "Matrix",
    homeassistant: "Home Assistant",
    voice_core: "Voice Core",
    little_spud: "Little Spud",
    homekit: "HomeKit",
    xbmc: "XBMC",
    automation: "Automations",
  };
  return labels[token] || token || "unknown";
}

function runtimeSettingKeySupportsGenerator(field) {
  const key = String(field?.key || "").trim().toUpperCase();
  if (!key) {
    return false;
  }
  return key === "API_AUTH_KEY" || key === "AUTH_TOKEN";
}

function generateRuntimeApiKey() {
  const bytes = new Uint8Array(24);
  const cryptoObj = window?.crypto;
  if (cryptoObj && typeof cryptoObj.getRandomValues === "function") {
    cryptoObj.getRandomValues(bytes);
  } else {
    for (let i = 0; i < bytes.length; i += 1) {
      bytes[i] = Math.floor(Math.random() * 256);
    }
  }
  return Array.from(bytes, (value) => value.toString(16).padStart(2, "0")).join("");
}

async function copyTextToClipboard(value) {
  const source = String(value || "");
  if (!source) {
    return false;
  }
  if (navigator?.clipboard && typeof navigator.clipboard.writeText === "function") {
    try {
      await navigator.clipboard.writeText(source);
      return true;
    } catch {
      // Fall through to legacy copy path.
    }
  }
  try {
    const temp = document.createElement("textarea");
    temp.value = source;
    temp.setAttribute("readonly", "readonly");
    temp.style.position = "fixed";
    temp.style.opacity = "0";
    temp.style.pointerEvents = "none";
    document.body.appendChild(temp);
    temp.focus();
    temp.select();
    const ok = document.execCommand("copy");
    document.body.removeChild(temp);
    return Boolean(ok);
  } catch {
    return false;
  }
}

function buildSettingInput(field, inputId) {
  const safeLabel = escapeHtml(field.label || field.key);
  const safeKey = escapeHtml(field.key || "");
  const safeDesc = field.description ? `<div class="small">${escapeHtml(field.description)}</div>` : "";
  const type = String(field.type || "text").toLowerCase();

  if (type === "select") {
    const options = Array.isArray(field.options) ? field.options : [];
    const optionRows = options
      .map((optRaw) => {
        if (typeof optRaw === "object" && optRaw !== null) {
          const value = String(optRaw.value ?? optRaw.id ?? optRaw.key ?? optRaw.label ?? "");
          const label = String(optRaw.label ?? value);
          const selected = String(field.value ?? "") === value ? "selected" : "";
          return `<option value="${escapeHtml(value)}" ${selected}>${escapeHtml(label)}</option>`;
        }
        const value = String(optRaw ?? "");
        const selected = String(field.value ?? "") === value ? "selected" : "";
        return `<option value="${escapeHtml(value)}" ${selected}>${escapeHtml(value)}</option>`;
      })
      .join("");

    return `<label>${safeLabel}<select id="${inputId}" data-setting-type="select" data-setting-key="${safeKey}">${optionRows}</select>${safeDesc}</label>`;
  }

  if (type === "multiselect") {
    const options = Array.isArray(field.options) ? field.options : [];
    const selectedValues = (() => {
      if (Array.isArray(field.value)) {
        return new Set(field.value.map((item) => String(item ?? "")));
      }
      if (typeof field.value === "string") {
        const text = field.value.trim();
        if (text.startsWith("[") && text.endsWith("]")) {
          const parsed = safeJsonParse(text);
          if (Array.isArray(parsed)) {
            return new Set(parsed.map((item) => String(item ?? "")));
          }
        }
        if (text) {
          return new Set(
            text
              .split(",")
              .map((item) => item.trim())
              .filter(Boolean)
          );
        }
      }
      return new Set();
    })();

    const size = Math.max(4, Math.min(14, options.length || 8));
    const optionRows = options
      .map((optRaw) => {
        if (typeof optRaw === "object" && optRaw !== null) {
          const value = String(optRaw.value ?? optRaw.id ?? optRaw.key ?? optRaw.label ?? "");
          const label = String(optRaw.label ?? value);
          const selected = selectedValues.has(value) ? "selected" : "";
          return `<option value="${escapeHtml(value)}" ${selected}>${escapeHtml(label)}</option>`;
        }
        const value = String(optRaw ?? "");
        const selected = selectedValues.has(value) ? "selected" : "";
        return `<option value="${escapeHtml(value)}" ${selected}>${escapeHtml(value)}</option>`;
      })
      .join("");

    return `<label>${safeLabel}<select id="${inputId}" class="settings-multiselect" multiple size="${size}" data-setting-type="multiselect" data-setting-key="${safeKey}">${optionRows}</select>${safeDesc}</label>`;
  }

  if (type === "checkbox") {
    const checked = boolFromAny(field?.value, false) ? "checked" : "";
    const toggleInput = `<input id="${inputId}" class="toggle-input" type="checkbox" data-setting-type="checkbox" data-setting-key="${safeKey}" ${checked} />`;
    return `<label>${safeLabel}${renderToggleRow(toggleInput)}${safeDesc}</label>`;
  }

  if (type === "textarea" || type === "multiline") {
    return `<label>${safeLabel}<textarea id="${inputId}" data-setting-type="textarea" data-setting-key="${safeKey}">${escapeHtml(field.value ?? "")}</textarea>${safeDesc}</label>`;
  }

  if (type === "file") {
    const accept = String(field.accept || "").trim();
    const acceptAttr = accept ? ` accept="${escapeHtml(accept)}"` : "";
    const currentValue = String(field.value ?? "");
    const currentSummary = currentValue
      ? `Current file content saved (${currentValue.length.toLocaleString()} characters).`
      : "No file saved.";
    return `<label>${safeLabel}<input id="${inputId}" type="file"${acceptAttr} data-setting-type="file" data-setting-key="${safeKey}" /><textarea hidden data-setting-current-key="${safeKey}">${escapeHtml(
      currentValue
    )}</textarea><div class="small">${escapeHtml(currentSummary)}</div>${safeDesc}</label>`;
  }

  const htmlType = type === "password" ? "password" : type === "number" ? "number" : "text";
  const numberAttrs =
    type === "number"
      ? ` step="${escapeHtml(field?.step ?? "any")}"${
          field?.min !== undefined ? ` min="${escapeHtml(field.min)}"` : ""
        }${field?.max !== undefined ? ` max="${escapeHtml(field.max)}"` : ""}`
      : "";
  const inputHtml = `<input id="${inputId}" type="${htmlType}"${numberAttrs} value="${escapeHtml(
    field.value ?? ""
  )}" data-setting-type="${escapeHtml(type)}" data-setting-key="${safeKey}" />`;
  if (runtimeSettingKeySupportsGenerator(field) && (htmlType === "password" || htmlType === "text")) {
    return `<label>${safeLabel}<div class="runtime-setting-input-action">${inputHtml}<button type="button" class="inline-btn runtime-copy-key-btn" data-target-input="${escapeHtml(
      inputId
    )}">Copy Key</button><button type="button" class="inline-btn runtime-generate-key-btn" data-target-input="${escapeHtml(
      inputId
    )}">Generate Key</button></div>${safeDesc}</label>`;
  }
  return `<label>${safeLabel}${inputHtml}${safeDesc}</label>`;
}

async function getInputValue(input) {
  const type = input.dataset.settingType || input.type;
  if (type === "multiselect") {
    return Array.from(input.selectedOptions || [])
      .map((option) => String(option?.value || "").trim())
      .filter(Boolean);
  }
  if (type === "checkbox") {
    return input.checked;
  }
  if (type === "file") {
    const file = input.files && input.files.length ? input.files[0] : null;
    if (!file) {
      const key = String(input.dataset.settingKey || "").trim();
      const current = Array.from(input.form?.querySelectorAll("[data-setting-current-key]") || []).find(
        (item) => String(item?.dataset?.settingCurrentKey || "").trim() === key
      );
      return current ? current.value : "";
    }
    const text = await file.text();
    const accept = String(input.getAttribute("accept") || "").toLowerCase();
    if (accept.includes("json") || String(file.name || "").toLowerCase().endsWith(".json")) {
      try {
        JSON.parse(text);
      } catch (error) {
        throw new Error(`${file.name || "Selected file"} is not valid JSON.`);
      }
    }
    return text;
  }
  return input.value;
}

async function collectFormValues(formElement) {
  const values = {};
  for (const input of formElement.querySelectorAll("[data-setting-key]")) {
    const key = String(input.dataset.settingKey || "").trim();
    if (!key) {
      continue;
    }
    values[key] = parseSettingValue(await getInputValue(input), input.dataset.settingType || input.type);
  }
  return values;
}

function _normalizeRuntimeSettingsKind(kind) {
  const token = String(kind || "").trim().toLowerCase();
  if (token === "verbas" || token === "portals" || token === "cores") {
    return token;
  }
  return "";
}

function resetRuntimeSettingsCatalog(kind) {
  const token = _normalizeRuntimeSettingsKind(kind);
  if (!token) {
    return;
  }
  state.runtimeSettingsCatalog[token] = {};
}

function registerRuntimeSettings(kind, key, payload) {
  const token = _normalizeRuntimeSettingsKind(kind);
  const entryKey = String(key || "").trim();
  if (!token || !entryKey || !payload || typeof payload !== "object") {
    return;
  }
  state.runtimeSettingsCatalog[token][entryKey] = {
    key: entryKey,
    label: String(payload.label || entryKey).trim() || entryKey,
    kind: token,
    endpoint: String(payload.endpoint || "").trim(),
    settings: Array.isArray(payload.settings) ? payload.settings : [],
  };
}

function getRuntimeSettingsEntry(kind, key) {
  const token = _normalizeRuntimeSettingsKind(kind);
  const entryKey = String(key || "").trim();
  if (!token || !entryKey) {
    return null;
  }
  const group = state.runtimeSettingsCatalog[token];
  if (!group || typeof group !== "object") {
    return null;
  }
  return group[entryKey] || null;
}

function formatRuntimeSettingsTitle(label) {
  const base = String(label || "").trim() || "Settings";
  return /settings$/i.test(base) ? base : `${base} Settings`;
}

function ensureRuntimeSettingsModal() {
  let modal = document.getElementById("runtime-settings-modal");
  if (modal) {
    return modal;
  }

  document.body.insertAdjacentHTML(
    "beforeend",
    `
      <div id="runtime-settings-modal" class="cerb-modal" aria-hidden="true">
        <div class="cerb-modal-dialog card runtime-settings-dialog" role="dialog" aria-modal="true" aria-label="Runtime Settings">
          <div class="card-head">
            <h3 id="runtime-settings-title" class="card-title">Settings</h3>
            <div class="inline-row">
              <button type="button" class="inline-btn" id="runtime-settings-close">Close</button>
            </div>
          </div>
          <div id="runtime-settings-meta" class="small"></div>
          <form id="runtime-settings-form" class="form-grid runtime-settings-form">
            <div id="runtime-settings-fields" class="form-grid runtime-settings-fields"></div>
            <div class="inline-row">
              <button type="submit" id="runtime-settings-save" class="action-btn">Save Settings</button>
              <button type="button" id="runtime-settings-reset" class="inline-btn danger" style="display:none;">Restore Default Settings</button>
            </div>
          </form>
          <div id="runtime-settings-status" class="small"></div>
        </div>
      </div>
    `
  );

  modal = document.getElementById("runtime-settings-modal");
  const form = document.getElementById("runtime-settings-form");
  const closeBtn = document.getElementById("runtime-settings-close");
  const saveBtn = document.getElementById("runtime-settings-save");
  const resetBtn = document.getElementById("runtime-settings-reset");
  const statusEl = document.getElementById("runtime-settings-status");

  const closeModal = () => {
    if (typeof state.runtimeSettingsCloseHandler === "function") {
      try {
        state.runtimeSettingsCloseHandler({ modal, form, statusEl, saveBtn, closeBtn });
      } catch (_error) {
        // Ignore modal cleanup errors.
      }
    }
    state.runtimeSettingsSaveHandler = null;
    state.runtimeSettingsResetHandler = null;
    state.runtimeSettingsResetConfirm = "";
    state.runtimeSettingsOpenHandler = null;
    state.runtimeSettingsCloseHandler = null;
    closePopupModal(modal);
  };

  closeBtn?.addEventListener("click", closeModal);
  modal.addEventListener("click", (event) => {
    if (event.target === modal) {
      closeModal();
    }
  });
  document.addEventListener("keydown", (event) => {
    if (event.key === "Escape" && modal.classList.contains("active")) {
      closeModal();
    }
  });
  form?.addEventListener("submit", async (event) => {
    event.preventDefault();
    if (typeof state.runtimeSettingsSaveHandler !== "function") {
      return;
    }
    if (statusEl) {
      statusEl.textContent = "Saving...";
    }
    if (saveBtn) {
      saveBtn.disabled = true;
    }
    if (closeBtn) {
      closeBtn.disabled = true;
    }
    if (resetBtn) {
      resetBtn.disabled = true;
    }
    try {
      const values = await collectFormValues(form);
      const result = await state.runtimeSettingsSaveHandler(values);
      const successText = String(result?.message || "Settings saved.").trim() || "Settings saved.";
      if (statusEl) {
        statusEl.textContent = successText;
      }
      showToast(successText);
      closeModal();
    } catch (error) {
      const msg = String(error?.message || "unknown error");
      if (statusEl) {
        statusEl.textContent = `Save failed: ${msg}`;
      }
      showToast(`Save failed: ${msg}`, "error", 3600);
    } finally {
      if (saveBtn) {
        saveBtn.disabled = false;
      }
      if (closeBtn) {
        closeBtn.disabled = false;
      }
      if (resetBtn) {
        resetBtn.disabled = false;
      }
    }
  });
  resetBtn?.addEventListener("click", async () => {
    if (typeof state.runtimeSettingsResetHandler !== "function") {
      return;
    }
    const confirmText =
      String(state.runtimeSettingsResetConfirm || "").trim() || "Restore these settings to their defaults?";
    if (!window.confirm(confirmText)) {
      return;
    }
    if (statusEl) {
      statusEl.textContent = "Restoring defaults...";
    }
    if (saveBtn) {
      saveBtn.disabled = true;
    }
    if (resetBtn) {
      resetBtn.disabled = true;
    }
    if (closeBtn) {
      closeBtn.disabled = true;
    }
    try {
      const result = await state.runtimeSettingsResetHandler();
      const successText = String(result?.message || "Default settings restored.").trim() || "Default settings restored.";
      if (statusEl) {
        statusEl.textContent = successText;
      }
      showToast(successText);
      closeModal();
    } catch (error) {
      const msg = String(error?.message || "unknown error");
      if (statusEl) {
        statusEl.textContent = `Restore failed: ${msg}`;
      }
      showToast(`Restore failed: ${msg}`, "error", 3600);
    } finally {
      if (saveBtn) {
        saveBtn.disabled = false;
      }
      if (resetBtn) {
        resetBtn.disabled = false;
      }
      if (closeBtn) {
        closeBtn.disabled = false;
      }
    }
  });
  return modal;
}

function openRuntimeSettingsModal({ title, meta, fields, onSave, onReset, resetLabel, resetConfirm, onOpen, onClose }) {
  const modal = ensureRuntimeSettingsModal();
  const titleEl = document.getElementById("runtime-settings-title");
  const metaEl = document.getElementById("runtime-settings-meta");
  const fieldsEl = document.getElementById("runtime-settings-fields");
  const statusEl = document.getElementById("runtime-settings-status");
  const saveBtn = document.getElementById("runtime-settings-save");
  const resetBtn = document.getElementById("runtime-settings-reset");
  const normalizedFields = Array.isArray(fields) ? fields : [];

  if (typeof state.runtimeSettingsCloseHandler === "function") {
    try {
      state.runtimeSettingsCloseHandler({ modal, fieldsEl, statusEl, saveBtn });
    } catch (_error) {
      // Ignore cleanup errors while swapping modal content.
    }
  }
  state.runtimeSettingsSaveHandler = typeof onSave === "function" ? onSave : null;
  state.runtimeSettingsResetHandler = typeof onReset === "function" ? onReset : null;
  state.runtimeSettingsResetConfirm = String(resetConfirm || "").trim();
  state.runtimeSettingsOpenHandler = typeof onOpen === "function" ? onOpen : null;
  state.runtimeSettingsCloseHandler = typeof onClose === "function" ? onClose : null;

  if (titleEl) {
    titleEl.textContent = String(title || "Settings").trim() || "Settings";
  }
  if (metaEl) {
    metaEl.textContent = String(meta || "").trim();
  }
  if (statusEl) {
    statusEl.textContent = "";
  }
  if (saveBtn) {
    saveBtn.disabled = false;
    saveBtn.style.display = typeof state.runtimeSettingsSaveHandler === "function" ? "" : "none";
  }
  if (resetBtn) {
    resetBtn.disabled = false;
    resetBtn.textContent = String(resetLabel || "Restore Default Settings").trim() || "Restore Default Settings";
    resetBtn.style.display = typeof state.runtimeSettingsResetHandler === "function" ? "" : "none";
  }

  if (fieldsEl) {
    if (!normalizedFields.length) {
      fieldsEl.innerHTML = `<div class="small">No configurable settings.</div>`;
    } else {
      fieldsEl.innerHTML = normalizedFields
        .map((field, idx) => {
          const inputId = `runtime_settings_${idx}_${String(field?.key || "").replace(/[^a-zA-Z0-9_]/g, "_")}`;
          return buildSettingInput(field, inputId);
        })
        .join("");
      fieldsEl.querySelectorAll(".runtime-generate-key-btn").forEach((button) => {
        button.addEventListener("click", () => {
          const targetId = String(button.getAttribute("data-target-input") || "").trim();
          if (!targetId) {
            return;
          }
          const input = document.getElementById(targetId);
          if (!input || typeof input.value !== "string") {
            return;
          }
          input.value = generateRuntimeApiKey();
          input.dispatchEvent(new Event("input", { bubbles: true }));
          input.dispatchEvent(new Event("change", { bubbles: true }));
        });
      });
      fieldsEl.querySelectorAll(".runtime-copy-key-btn").forEach((button) => {
        button.addEventListener("click", async () => {
          const targetId = String(button.getAttribute("data-target-input") || "").trim();
          if (!targetId) {
            return;
          }
          const input = document.getElementById(targetId);
          const source = String(input?.value || "");
          if (!source) {
            showToast("No key to copy.", "error", 2000);
            return;
          }
          const original = String(button.textContent || "Copy Key");
          button.disabled = true;
          try {
            const copied = await copyTextToClipboard(source);
            if (!copied) {
              throw new Error("clipboard unavailable");
            }
            button.textContent = "Copied";
            showToast("API key copied.");
          } catch (error) {
            button.textContent = "Copy failed";
            showToast(`Copy failed: ${String(error?.message || "clipboard unavailable")}`, "error", 2600);
          } finally {
            window.setTimeout(() => {
              button.textContent = original;
              button.disabled = false;
            }, 1200);
          }
        });
      });
    }
  }

  openPopupModal(modal);
  if (typeof state.runtimeSettingsOpenHandler === "function") {
    try {
      state.runtimeSettingsOpenHandler({ modal, fieldsEl, statusEl, saveBtn, resetBtn, titleEl, metaEl });
    } catch (_error) {
      // Ignore modal setup errors.
    }
  }
}

function _composeName(firstRaw, lastRaw, fallback = "Tater Totterson") {
  const first = String(firstRaw || "").trim();
  const last = String(lastRaw || "").trim();
  const joined = [first, last].filter(Boolean).join(" ").trim();
  return joined || String(fallback || "Tater Totterson").trim() || "Tater Totterson";
}

function getTaterFirstName() {
  return String(state.chatProfile.taterFirstName || state.chatProfile.taterName || "Tater").trim() || "Tater";
}

function getTaterFullName() {
  return (
    String(state.chatProfile.taterFullName || "").trim() ||
    _composeName(state.chatProfile.taterFirstName, state.chatProfile.taterLastName, "Tater Totterson")
  );
}

function syncChatCopy() {
  if (state.view === "chat") {
    updateHeader();
  }
  const input = document.getElementById("chat-input");
  if (input) {
    input.placeholder = `Message ${getTaterFullName()}...`;
  }
}

function updateHeader() {
  const meta = VIEW_META[state.view] || { title: String(state.view || "Tater"), subtitle: "" };
  const subtitle = state.view === "chat" ? `Talk to ${getTaterFullName()}` : meta.subtitle;
  document.getElementById("view-title").textContent = meta.title;
  document.getElementById("view-subtitle").textContent = subtitle;
}

function applyBranding(firstNameRaw) {
  const firstName = String(firstNameRaw || "").trim() || "Tater";
  const brandNameEl = document.getElementById("brand-name");
  const brandSubtitleEl = document.getElementById("brand-subtitle");
  if (brandNameEl) {
    brandNameEl.textContent = firstName;
  }
  if (brandSubtitleEl) {
    brandSubtitleEl.textContent = `${firstName}OS Control Surface`;
  }
}

async function refreshBranding() {
  try {
    const profile = await api("/api/chat/profile");
    const firstName = String(profile.tater_first_name || profile.tater_name || "").trim() || "Tater";
    const lastName = String(profile.tater_last_name || "").trim() || "Totterson";
    const fullName = String(profile.tater_full_name || "").trim() || _composeName(firstName, lastName, "Tater Totterson");

    state.chatProfile.taterName = firstName;
    state.chatProfile.taterFirstName = firstName;
    state.chatProfile.taterLastName = lastName;
    state.chatProfile.taterFullName = fullName;
    state.chatProfile.attachMaxMbEach = Number(profile.attach_max_mb_each ?? state.chatProfile.attachMaxMbEach ?? 0);
    state.chatProfile.attachMaxMbTotal = Number(profile.attach_max_mb_total ?? state.chatProfile.attachMaxMbTotal ?? 0);
    if (profile && Object.prototype.hasOwnProperty.call(profile, "popup_effect_style")) {
      applyPopupEffectStyle(profile.popup_effect_style);
    }

    applyBranding(firstName);
    syncChatCopy();
  } catch {
    applyBranding(getTaterFirstName());
    syncChatCopy();
  }
}

function persistCoreTopTab(tabName) {
  const normalized = String(tabName || "manage").trim() || "manage";
  state.coreTopTab = normalized;
  safeStorageSet("tater_tateros_core_tab", normalized);
}

function setActiveNav(viewName) {
  document.querySelectorAll(".nav-btn").forEach((btn) => {
    btn.classList.toggle("active", btn.dataset.view === viewName);
  });
}

function formatRuntimeSummary(health) {
  const verbasEnabled = Number(health?.verbas_enabled ?? 0);
  const portalsRunning = Number(health?.portals_running ?? 0);
  const coresRunning = Number(health?.cores_running ?? 0);
  const hydraJobsActive = Number(health?.hydra_jobs_active ?? health?.chat_jobs_active ?? 0);
  const llmCallsActive = Number(health?.llm_calls_active ?? 0);
  const visionCallsActive = Number(health?.vision_calls_active ?? health?.voice_calls_active ?? 0);
  return `${verbasEnabled} verba enabled • ${portalsRunning} portals running • ${coresRunning} cores running • ${hydraJobsActive} hydra jobs • ${llmCallsActive} llm calls • ${visionCallsActive} vision calls`;
}

function runtimeMemoryPayload(source) {
  return source?.loaded_models && typeof source.loaded_models === "object"
    ? source.loaded_models
    : source?.loadedModels && typeof source.loadedModels === "object"
      ? source.loadedModels
      : {};
}

function runtimeMemoryMeter(memoryPayload = {}) {
  const system = memoryPayload?.system && typeof memoryPayload.system === "object" ? memoryPayload.system : {};
  const vram = system?.vram && typeof system.vram === "object" ? system.vram : {};
  const ram = system?.ram && typeof system.ram === "object" ? system.ram : {};
  const vramTotal = Number(vram.total_bytes || 0);
  const vramUsed = Number(vram.used_bytes || 0);
  const ramTotal = Number(ram.total_bytes || 0);
  const ramUsed = Number(ram.used_bytes || 0);
  if (vramTotal > 0) {
    return {
      label: "VRAM",
      used: Math.max(0, vramUsed),
      total: Math.max(0, vramTotal),
      percent: Math.max(0, Math.min(100, Number(vram.percent || (vramUsed / vramTotal) * 100) || 0)),
    };
  }
  return {
    label: system.unified_memory ? "Unified" : "RAM",
    used: Math.max(0, ramUsed),
    total: Math.max(0, ramTotal),
    percent: ramTotal > 0 ? Math.max(0, Math.min(100, Number(ram.percent || (ramUsed / ramTotal) * 100) || 0)) : 0,
  };
}

function _runtimePercentNumber(value) {
  if (value === null || value === undefined) {
    return null;
  }
  if (typeof value === "string" && !value.trim()) {
    return null;
  }
  const parsed = Number(value);
  if (!Number.isFinite(parsed) || parsed < 0) {
    return null;
  }
  return Math.max(0, Math.min(100, parsed));
}

function _runtimePercentText(value, fallback = "n/a") {
  const percent = _runtimePercentNumber(value);
  if (percent === null) {
    return fallback;
  }
  return `${Math.round(percent)}%`;
}

function _runtimeBytesTitle(label, used, total, extra = "") {
  const usedNum = Math.max(0, Number(used) || 0);
  const totalNum = Math.max(0, Number(total) || 0);
  const parts = [label];
  if (totalNum > 0) {
    parts.push(`${formatBytes(usedNum)} / ${formatBytes(totalNum)}`);
  } else {
    parts.push("unavailable");
  }
  if (extra) {
    parts.push(extra);
  }
  return parts.join(" • ");
}

function _renderRuntimeSummaryResource({ label, value, percent = null, title = "", unavailable = false } = {}) {
  const percentValue = _runtimePercentNumber(percent);
  const fillPercent = percentValue === null ? 0 : percentValue;
  return `
    <span class="runtime-summary-resource${unavailable ? " unavailable" : ""}" title="${escapeHtml(title || `${label} ${value || ""}`)}">
      <span class="runtime-summary-resource-label">${escapeHtml(label || "")}</span>
      <span class="runtime-summary-resource-track" aria-hidden="true">
        <span class="runtime-summary-resource-fill" style="width:${fillPercent.toFixed(1)}%"></span>
      </span>
      <span class="runtime-summary-resource-value">${escapeHtml(value || "n/a")}</span>
    </span>
  `;
}

function renderRuntimeSummaryBubble(health) {
  const baseText = formatRuntimeSummary(health);
  const memory = runtimeMemoryPayload(health);
  const system = memory?.system && typeof memory.system === "object" ? memory.system : {};
  const cpu = system?.cpu && typeof system.cpu === "object" ? system.cpu : {};
  const ram = system?.ram && typeof system.ram === "object" ? system.ram : {};
  const vram = system?.vram && typeof system.vram === "object" ? system.vram : {};
  const loadedCount = Number(memory?.loaded_count || 0);
  const totals = memory?.totals && typeof memory.totals === "object" ? memory.totals : {};
  const estimatedLoaded = Number(totals.estimated_total_bytes || 0);
  const loadedText = `${loadedCount} model${loadedCount === 1 ? "" : "s"} loaded${estimatedLoaded > 0 ? ` • est ${formatBytes(estimatedLoaded)}` : ""}`;
  const ramTotal = Number(ram.total_bytes || 0);
  const ramUsed = Number(ram.used_bytes || 0);
  const ramPercent = ramTotal > 0 ? Number(ram.percent || (ramUsed / ramTotal) * 100) : null;
  const vramTotal = Number(vram.total_bytes || 0);
  const vramUsed = Number(vram.used_bytes || 0);
  const vramPercent = vramTotal > 0 ? Number(vram.percent || (vramUsed / vramTotal) * 100) : null;
  const gpuPercent = _runtimePercentNumber(vram.utilization_percent);
  const gpuMemoryLabel = vram.unified ? "GPU Mem" : "VRAM";
  const gpuTitleParts = [
    vram.backend ? `Backend ${vram.backend}` : "",
    gpuPercent === null ? "GPU load unavailable" : `GPU load ${_runtimePercentText(gpuPercent)}`,
    vramTotal > 0 ? `${gpuMemoryLabel} ${formatBytes(vramUsed)} / ${formatBytes(vramTotal)}` : "",
  ].filter(Boolean);
  const resourceChips = [
    _renderRuntimeSummaryResource({
      label: "CPU",
      value: _runtimePercentText(cpu.percent),
      percent: cpu.percent,
      title: [
        `CPU ${_runtimePercentText(cpu.percent)}`,
        Number(cpu.logical_count || 0) > 0 ? `${Number(cpu.logical_count || 0)} logical cores` : "",
      ].filter(Boolean).join(" • "),
      unavailable: !cpu.available,
    }),
    _renderRuntimeSummaryResource({
      label: "GPU",
      value: gpuPercent === null ? "n/a" : _runtimePercentText(gpuPercent),
      percent: gpuPercent,
      title: gpuTitleParts.join(" • ") || "GPU load unavailable",
      unavailable: gpuPercent === null,
    }),
    _renderRuntimeSummaryResource({
      label: system.unified_memory ? "Unified" : "RAM",
      value: _runtimePercentText(ramPercent),
      percent: ramPercent,
      title: _runtimeBytesTitle(system.unified_memory ? "Unified memory" : "RAM", ramUsed, ramTotal),
      unavailable: ramTotal <= 0,
    }),
    _renderRuntimeSummaryResource({
      label: gpuMemoryLabel,
      value: _runtimePercentText(vramPercent),
      percent: vramPercent,
      title: _runtimeBytesTitle(
        vram.backend ? `${vram.unified ? "Unified GPU memory" : "VRAM"} (${vram.backend})` : gpuMemoryLabel,
        vramUsed,
        vramTotal
      ),
      unavailable: vramTotal <= 0,
    }),
  ];
  return `
    <span class="runtime-summary-main">${escapeHtml(baseText)}</span>
    <span class="runtime-summary-metrics">
      <span class="runtime-summary-models">${escapeHtml(loadedText)}</span>
      <span class="runtime-summary-resources">${resourceChips.join("")}</span>
    </span>
  `;
}

function setRuntimeSummaryText(text, tone = "normal") {
  const summary = document.getElementById("runtime-summary");
  if (!summary) {
    return;
  }
  summary.textContent = String(text || "").trim();
  summary.classList.toggle("degraded", tone === "degraded");
  summary.classList.toggle("offline", tone === "offline");
}

function setRuntimeSummaryHealth(health, tone = "normal") {
  const summary = document.getElementById("runtime-summary");
  if (!summary) {
    return;
  }
  summary.innerHTML = renderRuntimeSummaryBubble(health || {});
  summary.classList.toggle("degraded", tone === "degraded");
  summary.classList.toggle("offline", tone === "offline");
}

function _runtimeAgeLabel(secondsRaw) {
  const seconds = Math.max(0, Number(secondsRaw) || 0);
  if (seconds < 60) {
    return `${Math.round(seconds)}s`;
  }
  const minutes = Math.floor(seconds / 60);
  const remSeconds = Math.floor(seconds % 60);
  if (minutes < 60) {
    return `${minutes}m ${remSeconds}s`;
  }
  const hours = Math.floor(minutes / 60);
  const remMinutes = minutes % 60;
  return `${hours}h ${remMinutes}m`;
}

function _runtimeStartedLabel(epochSecondsRaw) {
  const epoch = Number(epochSecondsRaw);
  if (!Number.isFinite(epoch) || epoch <= 0) {
    return "";
  }
  try {
    return new Date(epoch * 1000).toLocaleTimeString([], { hour: "numeric", minute: "2-digit" });
  } catch {
    return "";
  }
}

function _runtimeHistoryWindowKey(valueRaw, fallback = "24h") {
  const value = String(valueRaw || "").trim().toLowerCase();
  if (value === "24h" || value === "7d" || value === "30d") {
    return value;
  }
  return String(fallback || "").trim().toLowerCase();
}

function _runtimeHistoryWindowLabel(row) {
  const key = _runtimeHistoryWindowKey(row?.key, "");
  if (key) {
    return key;
  }
  return String(row?.label || "window").trim() || "window";
}

function _renderRuntimeHistoryWindowTabs(historyWindows, selectedKey, ariaLabel = "History window") {
  const rows = Array.isArray(historyWindows) ? historyWindows.filter((row) => row && typeof row === "object") : [];
  if (rows.length <= 1) {
    return "";
  }
  return `
    <div class="runtime-history-tabs" role="tablist" aria-label="${escapeHtml(ariaLabel)}">
      ${rows
        .map((row) => {
          const key = _runtimeHistoryWindowKey(row?.key, "");
          if (!key) {
            return "";
          }
          const active = key === _runtimeHistoryWindowKey(selectedKey, "24h");
          return `<button type="button" class="runtime-history-tab-btn${active ? " active" : ""}" data-runtime-history-window="${escapeHtml(
            key
          )}">${escapeHtml(_runtimeHistoryWindowLabel(row))}</button>`;
        })
        .join("")}
    </div>
  `;
}

function _renderRuntimeHydraJobRows(hydraJobs) {
  const activeTurns = Array.isArray(hydraJobs?.active_turns) ? hydraJobs.active_turns : [];

  const activeTurnsHtml = activeTurns.length
    ? `
        <div class="runtime-breakdown-list runtime-hydra-turn-list">
          ${activeTurns
            .map((row) => {
              const turnId = String(row?.id || "").trim();
              const shortId = turnId ? turnId.slice(0, 8) : "";
              const platformLabel = String(row?.platform_label || row?.platform || "Unknown");
              const taskName = String(row?.task_name || "").trim() || "Hydra task";
              const currentTool = String(row?.current_tool || "").trim();
              const source = String(row?.source || "").trim();
              const scope = String(row?.scope || "").trim();
              const age = _runtimeAgeLabel(row?.age_seconds);
              const started = _runtimeStartedLabel(row?.started_at);
              const metaParts = [platformLabel, source, shortId ? `Drop ${shortId}` : "", started ? `Started ${started}` : ""].filter(Boolean);
              return `
                <div class="runtime-hydra-turn-card">
                  <div class="runtime-hydra-turn-head">
                    <div class="runtime-hydra-turn-name">${escapeHtml(taskName)}</div>
                    <div class="runtime-breakdown-status"><span class="status-chip running">${escapeHtml(`Running ${age}`)}</span></div>
                  </div>
                  <div class="runtime-hydra-turn-meta">
                    ${metaParts.map((part) => `<span class="runtime-hydra-turn-pill">${escapeHtml(part)}</span>`).join("")}
                  </div>
                  ${currentTool ? `<div class="small muted runtime-hydra-turn-scope">Current verba/tool: ${escapeHtml(currentTool)}</div>` : ""}
                  ${scope ? `<div class="small muted runtime-hydra-turn-scope">Scope: ${escapeHtml(scope)}</div>` : ""}
                </div>
              `;
            })
            .join("")}
        </div>
      `
    : `<div class="small muted">No active Hydra turns right now.</div>`;

  return `
    <div class="runtime-breakdown-block">
      <div class="runtime-breakdown-subtitle">Active Turns</div>
      ${activeTurnsHtml}
    </div>
  `;
}

function _renderRuntimeLlmCallRows(llmCalls) {
  const activeCalls = Array.isArray(llmCalls?.active_calls) ? llmCalls.active_calls : [];

  const activeCallsHtml = activeCalls.length
    ? `
        <div class="runtime-breakdown-list">
          ${activeCalls
            .map((row) => {
              const sourceLabel = String(row?.source_label || row?.label || "Unknown source");
              const model = String(row?.model || "model");
              const host = String(row?.host || "").trim();
              const functionName = String(row?.function || "").trim();
              const activity = String(row?.activity || "").trim();
              const messageCount = Number(row?.message_count ?? 0);
              const detailLineParts = [`Model ${model}`];
              if (host) {
                detailLineParts.push(host);
              }
              const extraLineParts = [];
              if (activity) {
                extraLineParts.push(`Activity ${activity}`);
              } else if (functionName) {
                extraLineParts.push(`Fn ${functionName}`);
              }
              if (messageCount > 0) {
                extraLineParts.push(`${messageCount} msgs`);
              }
              const age = _runtimeAgeLabel(row?.age_seconds);
              return `
                <div class="runtime-breakdown-row">
                  <div class="runtime-breakdown-main">
                    <div class="runtime-breakdown-name">${escapeHtml(sourceLabel)}</div>
                    <div class="small muted">${escapeHtml(detailLineParts.join(" • "))}</div>
                    ${extraLineParts.length ? `<div class="small muted">${escapeHtml(extraLineParts.join(" • "))}</div>` : ""}
                  </div>
                  <div class="runtime-breakdown-status"><span class="status-chip running">${escapeHtml(age)}</span></div>
                </div>
              `;
            })
            .join("")}
        </div>
      `
    : `<div class="small muted">No active LLM calls right now.</div>`;

  return `
    <div class="runtime-breakdown-block">
      <div class="runtime-breakdown-subtitle">Active Calls</div>
      ${activeCallsHtml}
    </div>
  `;
}

function _renderRuntimeVisionCallRows(visionCalls) {
  const activeCalls = Array.isArray(visionCalls?.active_calls) ? visionCalls.active_calls : [];

  const activeCallsHtml = activeCalls.length
    ? `
        <div class="runtime-breakdown-list">
          ${activeCalls
            .map((row) => {
              const sourceLabel = String(row?.source_label || row?.label || "Unknown source");
              const model = String(row?.model || "model");
              const apiBase = String(row?.api_base || "").trim();
              const functionName = String(row?.function || "").trim();
              const detailLineParts = [`Model ${model}`];
              if (apiBase) {
                detailLineParts.push(apiBase);
              }
              const extraLineParts = [];
              if (functionName) {
                extraLineParts.push(`Fn ${functionName}`);
              }
              const age = _runtimeAgeLabel(row?.age_seconds);
              return `
                <div class="runtime-breakdown-row">
                  <div class="runtime-breakdown-main">
                    <div class="runtime-breakdown-name">${escapeHtml(sourceLabel)}</div>
                    <div class="small muted">${escapeHtml(detailLineParts.join(" • "))}</div>
                    ${extraLineParts.length ? `<div class="small muted">${escapeHtml(extraLineParts.join(" • "))}</div>` : ""}
                  </div>
                  <div class="runtime-breakdown-status"><span class="status-chip running">${escapeHtml(age)}</span></div>
                </div>
              `;
            })
            .join("")}
        </div>
      `
    : `<div class="small muted">No active vision calls right now.</div>`;

  return `
    <div class="runtime-breakdown-block">
      <div class="runtime-breakdown-subtitle">Active Calls</div>
      ${activeCallsHtml}
    </div>
  `;
}

function _runtimeInt(value, fallback = 0) {
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) {
    return Number(fallback || 0);
  }
  return Math.max(0, Math.round(parsed));
}

function _runtimeFmtInt(value) {
  return _runtimeInt(value, 0).toLocaleString();
}

function _runtimePct(used, total) {
  const usedNum = Math.max(0, Number(used) || 0);
  const totalNum = Math.max(0, Number(total) || 0);
  return totalNum > 0 ? Math.max(0, Math.min(100, (usedNum / totalNum) * 100)) : 0;
}

function _renderRuntimeMemoryMeter(label, used, total, detail = "") {
  const percent = _runtimePct(used, total);
  const value = total > 0 ? `${formatBytes(used)} / ${formatBytes(total)}` : "Unavailable";
  return `
    <div class="runtime-memory-meter">
      <div class="runtime-memory-meter-head">
        <span>${escapeHtml(label)}</span>
        <span>${escapeHtml(value)}</span>
      </div>
      <div class="runtime-memory-meter-track" aria-hidden="true">
        <span class="runtime-memory-meter-fill" style="width:${percent.toFixed(1)}%"></span>
      </div>
      ${detail ? `<div class="small muted">${escapeHtml(detail)}</div>` : ""}
    </div>
  `;
}

function _renderRuntimePercentMeter(label, percentRaw, detail = "") {
  const percent = _runtimePercentNumber(percentRaw);
  const unavailable = percent === null;
  const value = unavailable ? "Unavailable" : `${percent.toFixed(percent >= 10 ? 0 : 1)}%`;
  return `
    <div class="runtime-memory-meter${unavailable ? " runtime-memory-meter-unavailable" : ""}">
      <div class="runtime-memory-meter-head">
        <span>${escapeHtml(label)}</span>
        <span>${escapeHtml(value)}</span>
      </div>
      <div class="runtime-memory-meter-track" aria-hidden="true">
        <span class="runtime-memory-meter-fill" style="width:${(unavailable ? 0 : percent).toFixed(1)}%"></span>
      </div>
      ${detail ? `<div class="small muted">${escapeHtml(detail)}</div>` : ""}
    </div>
  `;
}

function _runtimeLoadedAtLabel(value) {
  const epoch = Number(value || 0);
  if (!Number.isFinite(epoch) || epoch <= 0) {
    return "";
  }
  try {
    return `Loaded ${new Date(epoch * 1000).toLocaleTimeString([], { hour: "numeric", minute: "2-digit" })}`;
  } catch {
    return "";
  }
}

function _renderRuntimeLoadedModelsCard(memoryPayload) {
  const payload = memoryPayload && typeof memoryPayload === "object" ? memoryPayload : {};
  const models = Array.isArray(payload.models) ? payload.models : [];
  const system = payload.system && typeof payload.system === "object" ? payload.system : {};
  const cpu = system.cpu && typeof system.cpu === "object" ? system.cpu : {};
  const ram = system.ram && typeof system.ram === "object" ? system.ram : {};
  const vram = system.vram && typeof system.vram === "object" ? system.vram : {};
  const totals = payload.totals && typeof payload.totals === "object" ? payload.totals : {};
  const loadedCount = Number(payload.loaded_count || models.length || 0);
  const llmLoadedCount = Number(payload.local_llm_loaded_count || 0);
  const managedLoadedCount = Number(payload.managed_loaded_count || 0);
  const unloadableCount = Number(payload.unloadable_count || models.filter((row) => Boolean(row?.unloadable) && !Boolean(row?.managed)).length || 0);
  const estimatedTotal = Number(totals.estimated_total_bytes || 0);
  const estimatedVram = Number(totals.estimated_vram_bytes || 0);
  const estimatedRam = Number(totals.estimated_ram_bytes || 0);
  const estimatedUnified = Number(totals.estimated_unified_bytes || 0);
  const summaryParts = [
    `${loadedCount} loaded`,
    llmLoadedCount > 0 ? `${llmLoadedCount} LLM` : "",
    managedLoadedCount > 0 ? `${managedLoadedCount} managed voice` : "",
    estimatedTotal > 0 ? `est ${formatBytes(estimatedTotal)}` : "",
    estimatedVram > 0 ? `VRAM est ${formatBytes(estimatedVram)}` : "",
    estimatedRam > 0 ? `RAM est ${formatBytes(estimatedRam)}` : "",
    estimatedUnified > 0 ? `unified est ${formatBytes(estimatedUnified)}` : "",
  ].filter(Boolean);
  const cpuLoad = Array.isArray(cpu.load_average) ? cpu.load_average.map((item) => Number(item || 0)).filter((item) => Number.isFinite(item)) : [];
  const cpuDetails = [
    Number(cpu.logical_count || 0) > 0 ? `${Number(cpu.logical_count || 0)} logical cores` : "",
    Number(cpu.physical_count || 0) > 0 ? `${Number(cpu.physical_count || 0)} physical cores` : "",
    cpuLoad.length ? `load ${cpuLoad.map((item) => item.toFixed(2)).join(" / ")}` : "",
  ].filter(Boolean).join(" • ");
  const gpuUtilization = _runtimePercentNumber(vram.utilization_percent);
  const gpuDevices = Array.isArray(vram.devices) ? vram.devices.filter((row) => row && typeof row === "object") : [];
  const gpuDetailParts = [
    vram.backend ? `Backend ${vram.backend}` : "",
    Number(vram.total_bytes || 0) > 0 ? `${gpuDevices.length || 1} device${(gpuDevices.length || 1) === 1 ? "" : "s"}` : "",
    vram.unified ? "shared/unified memory" : "",
    gpuUtilization === null ? "GPU load unavailable from this runtime" : "",
  ].filter(Boolean);
  const gpuDevicesHtml = gpuDevices.length
    ? `
      <div class="runtime-breakdown-block">
        <div class="runtime-breakdown-subtitle">GPU Devices</div>
        <div class="runtime-breakdown-list runtime-breakdown-list-static runtime-breakdown-list-dense">
          ${gpuDevices
            .map((device) => {
              const name = String(device?.name || `GPU ${device?.index ?? ""}`).trim() || "GPU";
              const deviceUsed = Number(device?.used_bytes || 0);
              const deviceTotal = Number(device?.total_bytes || 0);
              const deviceUtil = _runtimePercentNumber(device?.utilization_percent);
              const sharedUsed = Number(device?.shared_memory_used_bytes || 0);
              const sharedTotal = Number(device?.shared_memory_total_bytes || 0);
              const temp = Number(device?.temperature_c);
              const power = Number(device?.power_draw_w);
              const powerLimit = Number(device?.power_limit_w);
              const meta = [
                deviceUtil === null ? "GPU load n/a" : `GPU ${_runtimePercentText(deviceUtil)}`,
                deviceTotal > 0 ? `${device?.unified ? "GPU memory" : "VRAM"} ${formatBytes(deviceUsed)} / ${formatBytes(deviceTotal)}` : "",
                sharedTotal > 0 ? `Shared RAM ${formatBytes(sharedUsed)} / ${formatBytes(sharedTotal)}` : "",
                Number.isFinite(temp) ? `${temp.toFixed(0)} C` : "",
                Number.isFinite(power) ? `${power.toFixed(0)} W${Number.isFinite(powerLimit) && powerLimit > 0 ? ` / ${powerLimit.toFixed(0)} W` : ""}` : "",
                device?.detail ? String(device.detail || "") : "",
              ].filter(Boolean);
              return `
                <div class="runtime-breakdown-row runtime-breakdown-row-dense">
                  <div class="runtime-breakdown-main">
                    <div class="runtime-breakdown-name">${escapeHtml(name)}</div>
                    <div class="small muted">${escapeHtml(meta.join(" • ") || "No GPU telemetry reported.")}</div>
                  </div>
                  <div class="runtime-breakdown-status"><span class="status-chip running">${escapeHtml(
                    deviceUtil === null ? "n/a" : _runtimePercentText(deviceUtil)
                  )}</span></div>
                </div>
              `;
            })
            .join("")}
        </div>
      </div>
    `
    : "";
  const rowsHtml = models.length
    ? `
        <div class="runtime-breakdown-list runtime-loaded-model-list">
          ${models
            .map((row) => {
              const provider = String(row?.provider || "");
              const providerLabel = String(row?.provider_label || provider || "Local");
              const kindLabel = String(row?.kind_label || row?.category || "").trim();
              const model = String(row?.model || "model");
              const cacheKey = String(row?.cache_key || "");
              const device = String(row?.device || "").trim();
              const kind = String(row?.memory_kind || "ram").toUpperCase();
              const estimated = Number(row?.estimated_bytes || 0);
              const loadedAt = _runtimeLoadedAtLabel(row?.loaded_ts);
              const managed = Boolean(row?.managed);
              const unloadable = Boolean(row?.unloadable) && !managed;
              const details = Array.isArray(row?.details) ? row.details.map((item) => String(item || "").trim()).filter(Boolean) : [];
              const meta = [
                kindLabel,
                providerLabel,
                device ? `Device ${device}` : "",
                estimated > 0 ? `${kind} est ${formatBytes(estimated)}` : `${kind} estimate unavailable`,
                loadedAt,
              ].filter(Boolean);
              const detailLine = [
                ...details,
                managed ? String(row?.managed_by || "Managed by settings").trim() || "Managed by settings" : "",
              ].filter(Boolean);
              return `
                <div class="runtime-breakdown-row runtime-loaded-model-row">
                  <div class="runtime-breakdown-main">
                    <div class="runtime-breakdown-name">${escapeHtml(model)}</div>
                    <div class="small muted">${escapeHtml(meta.join(" • "))}</div>
                    ${detailLine.length ? `<div class="small muted">${escapeHtml(detailLine.join(" • "))}</div>` : ""}
                    ${row?.warning ? `<div class="small muted">${escapeHtml(String(row.warning || ""))}</div>` : ""}
                  </div>
                  <div class="runtime-breakdown-status">
                    ${
                      unloadable
                        ? `<button
                            type="button"
                            class="inline-btn danger runtime-loaded-model-unload"
                            data-runtime-loaded-model-unload="one"
                            data-provider="${escapeHtml(provider)}"
                            data-model="${escapeHtml(model)}"
                            data-cache-key="${escapeHtml(cacheKey)}"
                          >Unload</button>`
                        : `<span class="status-chip running">${escapeHtml(managed ? "Managed" : "Loaded")}</span>`
                    }
                  </div>
                </div>
              `;
            })
            .join("")}
        </div>
      `
    : `<div class="small muted">No runtime models are loaded right now.</div>`;

  return `
    <section class="runtime-breakdown-card runtime-breakdown-card-wide runtime-card-model-memory">
      <div class="runtime-breakdown-head runtime-model-memory-head">
        <div>
          <h4 class="runtime-breakdown-title">Loaded Runtime Models</h4>
          <div class="small muted">${escapeHtml(summaryParts.join(" • ") || "No loaded runtime models")}</div>
        </div>
        ${
          unloadableCount > 0
            ? `<button type="button" class="inline-btn danger" data-runtime-loaded-model-unload="all">Unload Local LLMs</button>`
            : ""
        }
      </div>
      <div class="runtime-memory-meter-grid">
        ${_renderRuntimePercentMeter("CPU Usage", cpu.percent, cpuDetails || "CPU telemetry from psutil.")}
        ${_renderRuntimePercentMeter("GPU Usage", gpuUtilization, gpuDetailParts.join(" • ") || "GPU telemetry unavailable.")}
        ${_renderRuntimeMemoryMeter("System RAM", Number(ram.used_bytes || 0), Number(ram.total_bytes || 0))}
        ${_renderRuntimeMemoryMeter(
          Number(vram.total_bytes || 0) > 0
            ? `${vram.unified ? "Unified GPU Memory" : "System VRAM"}${vram.backend ? ` (${vram.backend})` : ""}`
            : vram.unified
              ? "Unified GPU Memory"
              : "System VRAM",
          Number(vram.used_bytes || 0),
          Number(vram.total_bytes || 0),
          Number(vram.total_bytes || 0) > 0
            ? vram.unified
              ? "Reported memory is shared with system RAM."
              : ""
            : vram.unified
              ? "GPU memory is shared with system RAM; no separate limit reported."
              : "No discrete GPU memory reported by this runtime."
        )}
      </div>
      ${gpuDevicesHtml}
      <div class="runtime-breakdown-block">
        <div class="runtime-breakdown-subtitle">Loaded Model Entries</div>
        ${rowsHtml}
      </div>
    </section>
  `;
}

function _renderRuntimeContextWindowCard(estimate) {
  const payload = estimate && typeof estimate === "object" ? estimate : {};
  const error = String(payload?.error || "").trim();
  if (error) {
    return `
      <section class="runtime-breakdown-card runtime-breakdown-card-wide runtime-card-context">
        <div class="runtime-breakdown-head">
          <h4 class="runtime-breakdown-title">Estimated Chat Context Window</h4>
          <div class="small muted">Estimator unavailable</div>
        </div>
        <div class="runtime-breakdown-block">
          <div class="small muted">${escapeHtml(error)}</div>
        </div>
      </section>
    `;
  }

  const promptTokens = _runtimeInt(payload?.prompt_tokens);
  const completionBudget = _runtimeInt(payload?.completion_budget_tokens);
  const minimumWindow = _runtimeInt(payload?.minimum_context_window);
  const recommendedWindow = _runtimeInt(payload?.recommended_context_window);
  const historyMessages = _runtimeInt(payload?.history_messages);
  const maxHistoryMessages = _runtimeInt(payload?.max_history_messages);
  const enabledVerbas = _runtimeInt(payload?.enabled_verbas);
  const connectedPortals = _runtimeInt(payload?.connected_portals);
  const runningCores = _runtimeInt(payload?.running_cores);
  const breakdown = payload?.breakdown && typeof payload.breakdown === "object" ? payload.breakdown : {};
  const systemTokens = _runtimeInt(breakdown?.system_tokens);
  const statusTokens = _runtimeInt(breakdown?.status_tokens);
  const coreTokens = _runtimeInt(breakdown?.core_context_tokens);
  const preambleTokens = _runtimeInt(breakdown?.platform_preamble_tokens);
  const historyTokens = _runtimeInt(breakdown?.history_tokens);
  const userTokens = _runtimeInt(breakdown?.user_tokens);
  const capabilityReserveTokens = _runtimeInt(payload?.capability_context_reserve_tokens ?? breakdown?.capability_reserve_tokens);
  const burstReserveTokens = _runtimeInt(payload?.burst_context_reserve_tokens ?? breakdown?.burst_reserve_tokens);
  const highContextVerbas = _runtimeInt(breakdown?.high_context_verbas);
  const heavyCores = _runtimeInt(breakdown?.heavy_cores);
  const reserveExamples = Array.isArray(breakdown?.high_context_verba_examples)
    ? breakdown.high_context_verba_examples.map((item) => String(item || "").trim()).filter(Boolean).slice(0, 4)
    : [];

  if (promptTokens <= 0 && minimumWindow <= 0 && recommendedWindow <= 0) {
    return `
      <section class="runtime-breakdown-card runtime-breakdown-card-wide runtime-card-context">
        <div class="runtime-breakdown-head">
          <h4 class="runtime-breakdown-title">Estimated Chat Context Window</h4>
          <div class="small muted">No estimate available yet</div>
        </div>
        <div class="runtime-breakdown-block">
          <div class="small muted">Send a chat message so Hydra can sample the active chat prompt stack.</div>
        </div>
      </section>
    `;
  }

  const summaryParts = [
    `Prompt ${_runtimeFmtInt(promptTokens)} tok`,
    `Reply budget ${_runtimeFmtInt(completionBudget)} tok`,
    capabilityReserveTokens > 0 ? `Capability reserve ${_runtimeFmtInt(capabilityReserveTokens)} tok` : "",
    burstReserveTokens > 0 ? `Burst reserve ${_runtimeFmtInt(burstReserveTokens)} tok` : "",
    `Min window ${_runtimeFmtInt(minimumWindow)}`,
    `Recommended ${_runtimeFmtInt(recommendedWindow)}`,
  ].filter(Boolean);
  const historyLine = `${historyMessages}/${maxHistoryMessages || historyMessages} msgs`;
  const promptCompositionRows = [
    { label: "System prompt", tokens: systemTokens },
    { label: "Runtime status", tokens: statusTokens },
    { label: "Core context + preamble", tokens: coreTokens + preambleTokens },
    { label: `Chat history (${historyLine})`, tokens: historyTokens },
    { label: "Current user turn", tokens: userTokens },
  ];
  if (capabilityReserveTokens > 0) {
    promptCompositionRows.push({ label: "Capability reserve", tokens: capabilityReserveTokens });
  }
  const promptCompositionHtml = promptCompositionRows
    .map(
      (row) => `
          <div class="runtime-breakdown-row runtime-breakdown-row-dense">
            <div class="runtime-breakdown-main">
              <div class="runtime-breakdown-name">${escapeHtml(String(row.label || ""))}</div>
            </div>
            <div class="runtime-breakdown-status"><span class="status-chip running">${escapeHtml(
              _runtimeFmtInt(row.tokens)
            )}</span></div>
          </div>
        `
    )
    .join("");

  return `
    <section class="runtime-breakdown-card runtime-breakdown-card-wide runtime-card-context">
      <div class="runtime-breakdown-head">
        <h4 class="runtime-breakdown-title">Estimated Chat Context Window</h4>
        <div class="small muted">${escapeHtml(summaryParts.join(" • "))}</div>
      </div>
      <div class="runtime-breakdown-block">
        <div class="runtime-breakdown-subtitle">Prompt Composition</div>
        <div class="runtime-breakdown-list runtime-breakdown-list-static runtime-breakdown-list-dense">
          ${promptCompositionHtml}
        </div>
      </div>
      <div class="runtime-breakdown-block">
        <div class="small muted">
          Active stack: ${escapeHtml(`${enabledVerbas} verbas enabled • ${connectedPortals} portals connected • ${runningCores} cores running`)}
        </div>
        ${
          burstReserveTokens > 0
            ? `<div class="small muted">Recommended window includes burst reserve: ${escapeHtml(_runtimeFmtInt(burstReserveTokens))} tok for heavy/multi-tool turns.</div>`
            : ""
        }
        ${
          highContextVerbas > 0 || heavyCores > 0
            ? `<div class="small muted">High-context signals: ${escapeHtml(`${highContextVerbas} high-context verbas • ${heavyCores} heavy cores`)}${reserveExamples.length ? ` • e.g. ${escapeHtml(reserveExamples.join(", "))}` : ""}</div>`
            : ""
        }
      </div>
    </section>
  `;
}

function renderRuntimeBreakdown(payload) {
  const hydraJobs =
    payload?.hydra_jobs && typeof payload.hydra_jobs === "object"
      ? payload.hydra_jobs
      : payload?.chat_jobs && typeof payload.chat_jobs === "object"
        ? payload.chat_jobs
        : {};
  const llmCalls = payload?.llm_calls && typeof payload.llm_calls === "object" ? payload.llm_calls : {};
  const visionCalls =
    payload?.vision_calls && typeof payload.vision_calls === "object"
      ? payload.vision_calls
      : payload?.voice_calls && typeof payload.voice_calls === "object"
        ? payload.voice_calls
        : {};
  const contextEstimate = payload?.chat_context_window && typeof payload.chat_context_window === "object"
    ? payload.chat_context_window
    : {};
  const loadedModels = runtimeMemoryPayload(payload);
  const activeTurnCount = Array.isArray(hydraJobs?.active_turns) ? hydraJobs.active_turns.length : Number(hydraJobs.surface_running_turns ?? 0);
  const hydraSummary = `${Number(hydraJobs.total ?? 0)} total • Active turns ${activeTurnCount} • WebUI queue ${Number(
    hydraJobs.webui_jobs ?? 0
  )} • Surface turns ${Number(hydraJobs.surface_running_turns ?? 0)}`;
  const llmSummary = `${Number(llmCalls.active_total ?? 0)} active • Started ${Number(
    llmCalls?.totals?.started ?? 0
  )} • Completed ${Number(llmCalls?.totals?.completed ?? 0)} • Failed ${Number(llmCalls?.totals?.failed ?? 0)}`;
  const visionSummary = `${Number(visionCalls.active_total ?? 0)} active • Started ${Number(
    visionCalls?.totals?.started ?? 0
  )} • Completed ${Number(visionCalls?.totals?.completed ?? 0)} • Failed ${Number(visionCalls?.totals?.failed ?? 0)}`;
  return `
    <div class="runtime-breakdown-grid">
      ${_renderRuntimeLoadedModelsCard(loadedModels)}
      <section class="runtime-breakdown-card runtime-breakdown-card-wide runtime-card-hydra">
        <div class="runtime-breakdown-head">
          <h4 class="runtime-breakdown-title">Hydra Jobs</h4>
          <div class="small muted">${escapeHtml(hydraSummary)}</div>
        </div>
        ${_renderRuntimeHydraJobRows(hydraJobs)}
      </section>
      <section class="runtime-breakdown-card runtime-card-llm">
        <div class="runtime-breakdown-head">
          <h4 class="runtime-breakdown-title">LLM Calls</h4>
          <div class="small muted">${escapeHtml(llmSummary)}</div>
        </div>
        ${_renderRuntimeLlmCallRows(llmCalls)}
      </section>
      <section class="runtime-breakdown-card runtime-card-vision">
        <div class="runtime-breakdown-head">
          <h4 class="runtime-breakdown-title">Vision Calls</h4>
          <div class="small muted">${escapeHtml(visionSummary)}</div>
        </div>
        ${_renderRuntimeVisionCallRows(visionCalls)}
      </section>
      ${_renderRuntimeContextWindowCard(contextEstimate)}
    </div>
  `;
}

function ensureRuntimeBreakdownModal() {
  let modal = document.getElementById("runtime-breakdown-modal");
  if (modal) {
    return modal;
  }

  document.body.insertAdjacentHTML(
    "beforeend",
    `
      <div id="runtime-breakdown-modal" class="cerb-modal" aria-hidden="true">
        <div class="cerb-modal-dialog card runtime-breakdown-dialog" role="dialog" aria-modal="true" aria-label="Loaded Models, CPU and GPU Usage, Hydra Jobs, LLM Calls, and Vision Calls">
          <div class="card-head runtime-breakdown-modal-head">
            <span class="runtime-breakdown-modal-badge" aria-hidden="true">RT</span>
            <div>
              <div class="runtime-breakdown-kicker">Runtime Stats</div>
              <h3 class="card-title">Live Activity</h3>
              <div class="small muted">Loaded runtime models, CPU/GPU usage, memory, Hydra turns, model calls, vision work, and context budget.</div>
            </div>
            <div class="inline-row runtime-breakdown-actions">
              <span id="runtime-breakdown-updated" class="small"></span>
              <button type="button" class="inline-btn" id="runtime-breakdown-refresh">Refresh</button>
              <button type="button" class="inline-btn" id="runtime-breakdown-close">Close</button>
            </div>
          </div>
          <div id="runtime-breakdown-status" class="small"></div>
          <div id="runtime-breakdown-content" class="cerb-modal-body runtime-breakdown-content"></div>
        </div>
      </div>
    `
  );

  modal = document.getElementById("runtime-breakdown-modal");
  const closeBtn = document.getElementById("runtime-breakdown-close");
  const refreshBtn = document.getElementById("runtime-breakdown-refresh");

  const closeModal = () => {
    stopRuntimeBreakdownPolling();
    closePopupModal(modal);
  };

  closeBtn?.addEventListener("click", closeModal);
  refreshBtn?.addEventListener("click", async () => {
    await loadRuntimeBreakdown({ force: true });
  });
  const contentEl = document.getElementById("runtime-breakdown-content");
  contentEl?.addEventListener("click", async (event) => {
    const targetEl = event.target instanceof Element ? event.target : null;
    const unloadButton = targetEl?.closest("[data-runtime-loaded-model-unload]");
    if (unloadButton) {
      const mode = String(unloadButton.getAttribute("data-runtime-loaded-model-unload") || "").trim();
      const statusEl = document.getElementById("runtime-breakdown-status");
      unloadButton.setAttribute("disabled", "disabled");
      if (statusEl) {
        statusEl.textContent = mode === "all" ? "Unloading all local models..." : "Unloading local model...";
      }
      try {
        const body = mode === "all"
          ? { unload_all: true }
          : {
              provider: String(unloadButton.getAttribute("data-provider") || "").trim(),
              model: String(unloadButton.getAttribute("data-model") || "").trim(),
              cache_key: String(unloadButton.getAttribute("data-cache-key") || "").trim(),
            };
        const result = await api("/api/runtime/local-llm/unload", {
          method: "POST",
          body: JSON.stringify(body),
        });
        const count = Number(result?.unloaded_count || 0);
        if (statusEl) {
          statusEl.textContent = count > 0 ? `Unloaded ${count} local model cache ${count === 1 ? "entry" : "entries"}.` : "No loaded model matched that request.";
        }
        showToast(count > 0 ? `Unloaded ${count} local model${count === 1 ? "" : "s"}.` : "No loaded model matched.");
        await loadRuntimeBreakdown({ force: true, silent: true });
        await refreshHealth();
      } catch (error) {
        unloadButton.removeAttribute("disabled");
        if (statusEl) {
          statusEl.textContent = `Unload failed: ${error?.message || "unknown error"}`;
        }
        showToast(`Unload failed: ${error?.message || "unknown error"}`, "error", 3600);
      }
      return;
    }

    const button = targetEl?.closest("[data-runtime-history-window]");
    if (!button) {
      return;
    }
    const nextKey = _runtimeHistoryWindowKey(button.getAttribute("data-runtime-history-window"), "");
    if (!nextKey) {
      return;
    }
    if (_runtimeHistoryWindowKey(state.runtimeHistoryWindow, "24h") === nextKey) {
      return;
    }
    state.runtimeHistoryWindow = nextKey;
    const cachedPayload = state.runtimeBreakdownPayload;
    if (cachedPayload && typeof cachedPayload === "object") {
      contentEl.innerHTML = renderRuntimeBreakdown(cachedPayload);
    } else {
      void loadRuntimeBreakdown({ force: true, silent: true });
    }
  });
  modal.addEventListener("click", (event) => {
    if (event.target === modal) {
      closeModal();
    }
  });
  document.addEventListener("keydown", (event) => {
    if (event.key === "Escape" && modal.classList.contains("active")) {
      closeModal();
    }
  });
  return modal;
}

function stopRuntimeBreakdownPolling() {
  const timer = Number(state.runtimeBreakdownPollTimer || 0);
  if (timer) {
    window.clearInterval(timer);
    state.runtimeBreakdownPollTimer = 0;
  }
}

function startRuntimeBreakdownPolling() {
  stopRuntimeBreakdownPolling();
  state.runtimeBreakdownPollTimer = window.setInterval(() => {
    const modal = document.getElementById("runtime-breakdown-modal");
    if (!modal || !modal.classList.contains("active")) {
      stopRuntimeBreakdownPolling();
      return;
    }
    loadRuntimeBreakdown({ silent: true });
  }, 5000);
}

async function loadRuntimeBreakdown({ force = false, silent = false } = {}) {
  const modal = ensureRuntimeBreakdownModal();
  if (!modal) {
    return;
  }
  if (!force && modal.dataset.loading === "1") {
    return;
  }
  const statusEl = document.getElementById("runtime-breakdown-status");
  const updatedEl = document.getElementById("runtime-breakdown-updated");
  const contentEl = document.getElementById("runtime-breakdown-content");
  modal.dataset.loading = "1";

  if (statusEl && !silent) {
    statusEl.textContent = "Loading runtime state...";
  }

  try {
    const payload = await api("/api/runtime/breakdown");
    state.runtimeBreakdownPayload = payload;
    try {
      document.dispatchEvent(new CustomEvent("tater:runtime-breakdown-updated", { detail: { payload } }));
    } catch {
      // Runtime breakdown is a convenience cache for other panels; ignore event failures.
    }
    if (contentEl) {
      contentEl.innerHTML = renderRuntimeBreakdown(payload);
    }
    if (statusEl) {
      statusEl.textContent = "";
    }
    if (updatedEl) {
      updatedEl.textContent = `Updated ${new Date().toLocaleTimeString()}`;
    }
  } catch (error) {
    if (statusEl) {
      statusEl.textContent = `Runtime breakdown failed: ${error?.message || "unknown error"}`;
    }
    if (contentEl && !silent) {
      contentEl.innerHTML = "";
    }
  } finally {
    modal.dataset.loading = "0";
  }
}

async function openRuntimeBreakdownModal() {
  const modal = ensureRuntimeBreakdownModal();
  openPopupModal(modal);
  await loadRuntimeBreakdown({ force: true });
  startRuntimeBreakdownPolling();
}

function bindRuntimeSummary() {
  const summary = document.getElementById("runtime-summary");
  if (!summary || summary.dataset.bound === "1") {
    return;
  }
  summary.dataset.bound = "1";
  summary.setAttribute("role", "button");
  summary.setAttribute("tabindex", "0");
  summary.title = "Open loaded models, CPU/GPU usage, memory, Hydra jobs, LLM calls, and vision calls";
  summary.classList.add("interactive");
  summary.addEventListener("click", () => {
    openRuntimeBreakdownModal();
  });
  summary.addEventListener("keydown", (event) => {
    if (event.key === "Enter" || event.key === " ") {
      event.preventDefault();
      openRuntimeBreakdownModal();
    }
  });
}

async function refreshHealth() {
  if (healthRefreshPromise) {
    return healthRefreshPromise;
  }

  healthRefreshPromise = (async () => {
    let redisConnected = false;
    try {
      const health = await api("/api/health", { _timeoutMs: HEALTH_REQUEST_TIMEOUT_MS });
      if (health?.redis_status && typeof health.redis_status === "object") {
        _setRedisStatus(health.redis_status);
      }
      redisConnected = Boolean(health?.redis_status?.connected ?? health?.redis);
      if (!redisConnected) {
        setRuntimeSummaryText("Starting internal Redis", "offline");
        return health;
      }
      setRuntimeSummaryHealth(health, "normal");
      return health;
    } catch {
      setRuntimeSummaryText("Backend offline", "offline");
      return null;
    } finally {
      const nextDelay = redisConnected ? HEALTH_POLL_CONNECTED_MS : HEALTH_POLL_RECOVERY_MS;
      _scheduleHealthRefresh(nextDelay);
      healthRefreshPromise = null;
    }
  })();

  return healthRefreshPromise;
}

function closeChatEventSource(jobId = "") {
  const targetId = String(jobId || "").trim();
  const sources = state.chatEventSources && typeof state.chatEventSources === "object" ? state.chatEventSources : {};

  if (targetId) {
    const source = sources[targetId];
    if (source && typeof source.close === "function") {
      source.close();
    }
    delete sources[targetId];
    state.chatEventSources = sources;
    return;
  }

  Object.keys(sources).forEach((id) => {
    const source = sources[id];
    if (source && typeof source.close === "function") {
      source.close();
    }
  });
  state.chatEventSources = {};
}

function stopAllChatJobPolling() {
  const pollMeta = state.chatPollMeta && typeof state.chatPollMeta === "object" ? state.chatPollMeta : {};
  Object.keys(pollMeta).forEach((id) => {
    const row = pollMeta[id] && typeof pollMeta[id] === "object" ? pollMeta[id] : {};
    row.token = Number(row.token || 0) + 1;
    if (row.timer) {
      window.clearTimeout(row.timer);
    }
  });
  state.chatPollMeta = {};
}

function _avatarInitial(label, fallback = "?") {
  const text = String(label || "").trim();
  if (!text) {
    return String(fallback || "?").slice(0, 1).toUpperCase();
  }
  const match = text.match(/[A-Za-z0-9]/);
  return (match ? match[0] : text[0]).toUpperCase();
}

function _chatAvatarMarkup({ src, displayName, role }) {
  if (src) {
    return `<img class="chat-avatar-img" src="${escapeHtml(src)}" alt="${escapeHtml(displayName)} avatar" />`;
  }
  return `<div class="chat-avatar-fallback ${escapeHtml(role)}">${escapeHtml(
    _avatarInitial(displayName, role === "user" ? "U" : "T")
  )}</div>`;
}

function _formatBytes(raw) {
  const bytes = Number(raw);
  if (!Number.isFinite(bytes) || bytes <= 0) {
    return "";
  }
  if (bytes < 1024) {
    return `${Math.round(bytes)} B`;
  }
  if (bytes < 1024 * 1024) {
    return `${(bytes / 1024).toFixed(1)} KB`;
  }
  if (bytes < 1024 * 1024 * 1024) {
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  }
  return `${(bytes / (1024 * 1024 * 1024)).toFixed(1)} GB`;
}

function _chatFileUrl(fileId, mimetype = "") {
  const token = String(fileId || "").trim();
  if (!token) {
    return "";
  }
  const base = `/api/chat/files/${encodeURIComponent(token)}`;
  const mm = String(mimetype || "").trim();
  const withQuery = mm ? `${base}?mimetype=${encodeURIComponent(mm)}` : base;
  return withBasePath(withQuery);
}

function _sanitizeMarkdownHref(rawHref) {
  const href = String(rawHref || "").trim();
  if (!href) {
    return "";
  }
  const lowered = href.toLowerCase();
  if (
    lowered.startsWith("http://") ||
    lowered.startsWith("https://") ||
    lowered.startsWith("mailto:") ||
    lowered.startsWith("tel:") ||
    lowered.startsWith("/") ||
    lowered.startsWith("#")
  ) {
    return href;
  }
  return "";
}

function _chatDirectMediaUrl(rawUrl) {
  const safeHref = _sanitizeMarkdownHref(rawUrl);
  if (!safeHref) {
    return "";
  }
  return safeHref.startsWith("/") ? withBasePath(safeHref) : safeHref;
}

function _renderMarkdownInline(rawText) {
  const source = String(rawText ?? "");
  if (!source) {
    return "";
  }

  const placeholders = [];
  let working = source;

  // Protect inline code first so emphasis/link transforms do not affect it.
  working = working.replace(/`([^`\n]+)`/g, (_match, codeText) => {
    const token = `@@MD_TOKEN_${placeholders.length}@@`;
    placeholders.push(`<code>${escapeHtml(codeText)}</code>`);
    return token;
  });

  // Convert markdown links to safe anchors.
  working = working.replace(/\[([^\]\n]+)\]\(([^)\s]+)\)/g, (_match, label, href) => {
    const safeHref = _sanitizeMarkdownHref(href);
    const token = `@@MD_TOKEN_${placeholders.length}@@`;
    if (!safeHref) {
      placeholders.push(`${escapeHtml(label)} (${escapeHtml(href)})`);
      return token;
    }
    placeholders.push(
      `<a href="${escapeHtml(safeHref)}" target="_blank" rel="noopener noreferrer">${escapeHtml(label)}</a>`
    );
    return token;
  });

  working = escapeHtml(working);
  working = working.replace(/\*\*([^*\n][^*\n]*?)\*\*/g, "<strong>$1</strong>");
  working = working.replace(/\*([^*\n][^*\n]*?)\*/g, "<em>$1</em>");

  // Restore protected inline code and links.
  placeholders.forEach((html, index) => {
    const token = `@@MD_TOKEN_${index}@@`;
    working = working.replaceAll(token, html);
  });

  return working;
}

function _renderAssistantMarkdownBubble(rawText) {
  const source = String(rawText ?? "").replace(/\r\n?/g, "\n");
  const lines = source.split("\n");
  const chunks = [];
  let paragraphLines = [];
  let listType = "";
  let listItems = [];
  let inCodeBlock = false;
  let codeLines = [];
  let codeLang = "";

  const flushParagraph = () => {
    if (!paragraphLines.length) {
      return;
    }
    const rendered = paragraphLines
      .map((line) => _renderMarkdownInline(line.trim()))
      .join("<br />");
    chunks.push(`<p>${rendered}</p>`);
    paragraphLines = [];
  };

  const flushList = () => {
    if (!listType || !listItems.length) {
      listType = "";
      listItems = [];
      return;
    }
    const itemsHtml = listItems.map((item) => `<li>${_renderMarkdownInline(item)}</li>`).join("");
    chunks.push(`<${listType}>${itemsHtml}</${listType}>`);
    listType = "";
    listItems = [];
  };

  const flushCodeBlock = () => {
    if (!inCodeBlock) {
      return;
    }
    const langClass = codeLang ? ` class="language-${escapeHtml(codeLang)}"` : "";
    chunks.push(`<pre><code${langClass}>${escapeHtml(codeLines.join("\n"))}</code></pre>`);
    inCodeBlock = false;
    codeLines = [];
    codeLang = "";
  };

  for (const rawLine of lines) {
    const line = String(rawLine ?? "");
    const fenceMatch = line.match(/^```(?:\s*([A-Za-z0-9_+\-]+))?\s*$/);
    if (fenceMatch) {
      flushParagraph();
      flushList();
      if (inCodeBlock) {
        flushCodeBlock();
      } else {
        inCodeBlock = true;
        codeLang = String(fenceMatch[1] || "").trim();
        codeLines = [];
      }
      continue;
    }

    if (inCodeBlock) {
      codeLines.push(line);
      continue;
    }

    const trimmed = line.trim();
    if (!trimmed) {
      flushParagraph();
      flushList();
      continue;
    }

    const headingMatch = trimmed.match(/^(#{1,6})\s+(.*)$/);
    if (headingMatch) {
      flushParagraph();
      flushList();
      const level = Math.min(6, Math.max(1, headingMatch[1].length));
      chunks.push(`<h${level}>${_renderMarkdownInline(headingMatch[2].trim())}</h${level}>`);
      continue;
    }

    const orderedMatch = trimmed.match(/^\d+\.\s+(.*)$/);
    if (orderedMatch) {
      flushParagraph();
      if (listType && listType !== "ol") {
        flushList();
      }
      listType = "ol";
      listItems.push(String(orderedMatch[1] || "").trim());
      continue;
    }

    const bulletMatch = trimmed.match(/^[-*+]\s+(.*)$/);
    if (bulletMatch) {
      flushParagraph();
      if (listType && listType !== "ul") {
        flushList();
      }
      listType = "ul";
      listItems.push(String(bulletMatch[1] || "").trim());
      continue;
    }

    if (listType) {
      flushList();
    }
    paragraphLines.push(trimmed);
  }

  flushParagraph();
  flushList();
  flushCodeBlock();

  if (!chunks.length) {
    return `<div class="bubble-body markdown">${_renderMarkdownInline(source)}</div>`;
  }
  return `<div class="bubble-body markdown">${chunks.join("")}</div>`;
}

function renderChatMessage(message) {
  const role = String(message.role || "assistant").toLowerCase();
  const roleClass = role === "user" ? "user" : "assistant";
  const displayName =
    roleClass === "user"
      ? String(message.username || state.chatProfile.username || "User")
      : getTaterFullName();
  const avatarSrc = roleClass === "user" ? state.chatProfile.userAvatar : state.chatProfile.taterAvatar;
  const content = message.content;
  let bodyHtml = "";
  let rowExtraClass = "";

  if (typeof content === "string") {
    bodyHtml =
      roleClass === "assistant"
        ? _renderAssistantMarkdownBubble(content)
        : `<div class="bubble-body">${escapeHtml(content)}</div>`;
  } else if (content && typeof content === "object") {
    const marker = String(content.marker || "").trim().toLowerCase();
    if (marker === "plugin_wait") {
      const waitText = String(content.content || "").trim() || "Working on it...";
      bodyHtml = `<div class="bubble-body">${escapeHtml(waitText)}</div>`;
    } else if (marker === "typing") {
      rowExtraClass = " typing-indicator";
      bodyHtml = `
        <div class="bubble-body chat-typing-body" aria-label="${escapeHtml(`${displayName} is typing`)}">
          <div class="chat-typing-label">${escapeHtml(`${displayName} is typing`)}</div>
          <div class="chat-typing-dots" aria-hidden="true">
            <span></span>
            <span></span>
            <span></span>
          </div>
        </div>
      `;
    } else {
      const contentType = String(content.type || "").toLowerCase();
      const fileId = String(content.id || content.file_id || "").trim();
      const fileName = String(content.name || "attachment").trim() || "attachment";
      const mimetype = String(content.mimetype || "").trim() || "application/octet-stream";
      const fileUrl = _chatFileUrl(fileId, mimetype);
      const directMediaUrl = _chatDirectMediaUrl(content.url || content.src || content.href);
      const mediaUrl = directMediaUrl || fileUrl;
      const hasDataB64 = typeof content.data_b64 === "string" && content.data_b64.trim().length > 0;
      const hasMediaUrl = Boolean(mediaUrl);
      if (contentType === "image" && hasDataB64) {
        const imageUrl = `data:${escapeHtml(content.mimetype || "image/png")};base64,${content.data_b64}`;
        bodyHtml = `<img class="chat-media-image" src="${imageUrl}" alt="${escapeHtml(content.name || "image")}" />`;
      } else if (contentType === "image" && hasMediaUrl) {
        bodyHtml = `<img class="chat-media-image" src="${escapeHtml(mediaUrl)}" alt="${escapeHtml(fileName)}" />`;
      } else if (contentType === "audio" && hasDataB64) {
        const mimetype = String(content.mimetype || "audio/mpeg");
        const audioUrl = `data:${escapeHtml(mimetype)};base64,${content.data_b64}`;
        bodyHtml = `
          <div class="chat-media-wrap">
            <audio controls preload="metadata" src="${audioUrl}"></audio>
            <div class="chat-file-meta">${escapeHtml(fileName)}</div>
            <a class="inline-btn" href="${audioUrl}" download="${escapeHtml(fileName)}">Download Audio</a>
          </div>
        `;
      } else if (contentType === "audio" && hasMediaUrl) {
        bodyHtml = `
          <div class="chat-media-wrap">
            <audio controls preload="metadata" src="${escapeHtml(mediaUrl)}"></audio>
            <div class="chat-file-meta">${escapeHtml(fileName)}</div>
            <a class="inline-btn" href="${escapeHtml(mediaUrl)}" download="${escapeHtml(fileName)}">Download Audio</a>
          </div>
        `;
      } else if (contentType === "video" && hasDataB64) {
        const mimetype = String(content.mimetype || "video/mp4");
        const videoUrl = `data:${escapeHtml(mimetype)};base64,${content.data_b64}`;
        bodyHtml = `
          <div class="chat-media-wrap">
            <video controls preload="metadata" src="${videoUrl}" class="chat-media-video"></video>
            <div class="chat-file-meta">${escapeHtml(fileName)}</div>
            <a class="inline-btn" href="${videoUrl}" download="${escapeHtml(fileName)}">Download Video</a>
          </div>
        `;
      } else if (contentType === "video" && hasMediaUrl) {
        bodyHtml = `
          <div class="chat-media-wrap">
            <video controls preload="metadata" src="${escapeHtml(mediaUrl)}" class="chat-media-video"></video>
            <div class="chat-file-meta">${escapeHtml(fileName)}</div>
            <a class="inline-btn" href="${escapeHtml(mediaUrl)}" download="${escapeHtml(fileName)}">Download Video</a>
          </div>
        `;
      } else if (contentType === "file" && hasDataB64) {
        const sizeLabel = _formatBytes(content.size);
        bodyHtml = `
          <div class="chat-file-card">
            <div class="chat-file-meta">${escapeHtml(fileName)}${sizeLabel ? ` (${escapeHtml(sizeLabel)})` : ""}</div>
            <a class="inline-btn" href="data:${escapeHtml(mimetype)};base64,${content.data_b64}" download="${escapeHtml(
              fileName
            )}">Download File</a>
          </div>
        `;
      } else if (contentType === "file" && hasMediaUrl) {
        const sizeLabel = _formatBytes(content.size);
        bodyHtml = `
          <div class="chat-file-card">
            <div class="chat-file-meta">${escapeHtml(fileName)}${sizeLabel ? ` (${escapeHtml(sizeLabel)})` : ""}</div>
            <a class="inline-btn" href="${escapeHtml(mediaUrl)}" download="${escapeHtml(fileName)}">Download File</a>
          </div>
        `;
      } else {
        bodyHtml = `<pre>${escapeHtml(JSON.stringify(content, null, 2))}</pre>`;
      }
    }
  } else {
    bodyHtml = `<div class="bubble-body">${escapeHtml(String(content ?? ""))}</div>`;
  }

  const avatarHtml = `<div class="chat-avatar">${_chatAvatarMarkup({ src: avatarSrc, displayName, role: roleClass })}</div>`;
  const bubbleHtml = `
    <div class="bubble ${escapeHtml(roleClass)}">
      <div class="role">${escapeHtml(displayName)}</div>
      ${bodyHtml}
    </div>
  `;

  return `
    <article class="chat-row ${escapeHtml(roleClass)}${rowExtraClass}">
      ${roleClass === "user" ? `${bubbleHtml}${avatarHtml}` : `${avatarHtml}${bubbleHtml}`}
    </article>
  `;
}

function reposToText(repos) {
  const rows = Array.isArray(repos) ? repos : [];
  return rows
    .map((repo) => {
      const name = String(repo?.name || "").trim();
      const url = String(repo?.url || "").trim();
      if (!url) {
        return "";
      }
      return name ? `${name}|${url}` : url;
    })
    .filter(Boolean)
    .join("\n");
}

function textToRepos(text) {
  const rows = [];
  String(text || "")
    .split("\n")
    .map((line) => line.trim())
    .filter(Boolean)
    .forEach((line) => {
      if (line.includes("|")) {
        const [namePart, ...urlParts] = line.split("|");
        const name = String(namePart || "").trim();
        const url = String(urlParts.join("|") || "").trim();
        if (url) {
          rows.push({ name, url });
        }
      } else {
        rows.push({ name: "", url: line });
      }
    });
  return rows;
}

function renderShopRepoListItem(kind, repo) {
  const name = String(repo?.name || "").trim();
  const url = String(repo?.url || "").trim();
  if (!url) {
    return "";
  }
  const title = name || "Unnamed Repo";
  return `
    <article class="shop-repo-item" data-kind="${escapeHtml(kind)}" data-repo-name="${escapeHtml(name)}" data-repo-url="${escapeHtml(url)}">
      <div class="shop-repo-body">
        <div class="shop-repo-name">${escapeHtml(title)}</div>
        <div class="shop-repo-url"><code>${escapeHtml(url)}</code></div>
      </div>
      <button class="inline-btn danger shop-remove-repo" type="button" data-kind="${escapeHtml(kind)}">Remove</button>
    </article>
  `;
}

function collectShopReposFromList(kind) {
  const list = document.getElementById(`shop-repo-list-${kind}`);
  if (!list) {
    return [];
  }
  return Array.from(list.querySelectorAll(".shop-repo-item"))
    .map((item) => ({
      name: String(item?.dataset?.repoName || "").trim(),
      url: String(item?.dataset?.repoUrl || "").trim(),
    }))
    .filter((repo) => repo.url);
}

function ensureShopRepoListEmptyState(kind) {
  const list = document.getElementById(`shop-repo-list-${kind}`);
  if (!list) {
    return;
  }
  const hasRows = Boolean(list.querySelector(".shop-repo-item"));
  const emptyNode = list.querySelector(".shop-repo-empty");
  if (hasRows && emptyNode) {
    emptyNode.remove();
  }
  if (!hasRows && !emptyNode) {
    list.insertAdjacentHTML("beforeend", `<div class="small shop-repo-empty">No additional repos configured.</div>`);
  }
}

function shopEndpoint(kind) {
  if (kind === "verbas") {
    return "/api/shop/verbas";
  }
  if (kind === "integrations") {
    return "/api/shop/integrations";
  }
  if (kind === "cores") {
    return "/api/shop/cores";
  }
  return "/api/shop/portals";
}

function shopLabel(kind) {
  if (kind === "verbas") {
    return "Verba";
  }
  if (kind === "cores") {
    return "Core";
  }
  if (kind === "integrations") {
    return "Integration";
  }
  return "Portal";
}

function setShopStatus(kind, text) {
  const statusEl = document.getElementById(`shop-status-${kind}`);
  if (statusEl) {
    statusEl.textContent = String(text || "").trim();
  }
}

function getActiveShopTab(kind) {
  const active = document.querySelector(`.shop-tab-btn[data-kind='${kind}'].active`);
  return String(active?.dataset?.tab || "").trim();
}

function activateShopTab(kind, tabName) {
  const requested = String(tabName || "").trim();
  const buttons = Array.from(document.querySelectorAll(`.shop-tab-btn[data-kind='${kind}']`));
  const panels = Array.from(document.querySelectorAll(`.shop-tab-panel[data-kind='${kind}']`));
  if (!buttons.length || !panels.length) {
    return;
  }
  const available = new Set(buttons.map((button) => String(button.dataset.tab || "").trim()).filter(Boolean));
  const fallback = String(buttons[0]?.dataset?.tab || "").trim();
  const activeTab = available.has(requested) ? requested : fallback;
  if (!activeTab) {
    return;
  }
  buttons.forEach((button) => {
    button.classList.toggle("active", button.dataset.tab === activeTab);
  });
  panels.forEach((panel) => {
    panel.classList.toggle("active", panel.dataset.tabPanel === activeTab);
  });
}

const shopNameCollator = typeof Intl !== "undefined"
  ? new Intl.Collator(undefined, { sensitivity: "base", numeric: true })
  : null;

function compareShopText(a, b) {
  const left = String(a || "").trim();
  const right = String(b || "").trim();
  if (shopNameCollator) {
    return shopNameCollator.compare(left, right);
  }
  const leftLower = left.toLowerCase();
  const rightLower = right.toLowerCase();
  if (leftLower < rightLower) {
    return -1;
  }
  if (leftLower > rightLower) {
    return 1;
  }
  return 0;
}

function shopItemDisplayName(item) {
  if (!item || typeof item !== "object") {
    return "";
  }
  return String(
    item.name ||
    item.display_name ||
    item.label ||
    item.title ||
    item.id ||
    item.module_key ||
    item.key ||
    ""
  ).trim();
}

function shopItemStableId(item) {
  if (!item || typeof item !== "object") {
    return "";
  }
  return String(item.id || item.module_key || item.key || item.name || item.label || "").trim();
}

function compareShopNames(leftName, rightName, leftId = "", rightId = "") {
  const nameCompare = compareShopText(leftName, rightName);
  if (nameCompare !== 0) {
    return nameCompare;
  }
  return compareShopText(leftId, rightId);
}

function compareShopItemsByDisplayName(left, right) {
  return compareShopNames(
    shopItemDisplayName(left),
    shopItemDisplayName(right),
    shopItemStableId(left),
    shopItemStableId(right)
  );
}

function sortedShopItems(items) {
  return (Array.isArray(items) ? items : []).slice().sort(compareShopItemsByDisplayName);
}

function renderShopManager(kind, data) {
  const noun = shopLabel(kind);
  const repos = data?.repos || {};
  const defaultRepo = repos.default || { name: "", url: "" };
  const additionalRepos = Array.isArray(repos.additional) ? repos.additional : [];
  const installed = sortedShopItems(data?.installed);
  const catalog = sortedShopItems(data?.catalog);
  const available = sortedShopItems(catalog.filter((item) => !item.installed));
  const errors = Array.isArray(data?.errors) ? data.errors : [];
  const updatesAvailable = Number(data?.updates_available || 0);

  const warningsHtml = errors.map((entry) => renderNotice(`${noun} shop: ${entry}`)).join("");

  const installedHtml = installed.length
    ? installed
        .map((entry) => {
          const enabledText = kind === "verbas" || kind === "integrations" ? ` • enabled: ${entry.enabled ? "yes" : "no"}` : "";
          const runtimeText = Object.prototype.hasOwnProperty.call(entry, "running") ? ` • running: ${entry.running ? "yes" : "no"}` : "";
          const requiredText = entry.required ? " • required" : "";
          const platformText = entry.platforms_str ? `<div class="small">Portals: ${escapeHtml(entry.platforms_str)}</div>` : "";

          return `
            <article class="card shop-installed-card" data-kind="${kind}" data-id="${escapeHtml(entry.id)}">
              <div class="card-head">
                <h3 class="card-title">${escapeHtml(entry.name || entry.id)}</h3>
                <span class="small">${escapeHtml(entry.id)}</span>
              </div>
              <div class="small">installed: ${escapeHtml(entry.installed_ver || "0.0.0")} • store: ${escapeHtml(entry.store_ver || "-")} • source: ${escapeHtml(entry.source_label || "local")}${enabledText}${runtimeText}${requiredText}</div>
              <div class="muted">${escapeHtml(entry.description || "")}</div>
              ${platformText}
              ${kind === "integrations" ? `
              <div class="inline-row" style="margin-top:8px;">
                ${entry.enabled
                  ? entry.required
                    ? `<button class="inline-btn" disabled>Required</button>`
                    : `<button class="inline-btn shop-action" data-kind="${kind}" data-action="disable" data-id="${escapeHtml(entry.id)}">Disable</button>`
                  : `<button class="action-btn shop-action" data-kind="${kind}" data-action="enable" data-id="${escapeHtml(entry.id)}">Enable</button>`}
              </div>` : ""}
              <div class="small" style="margin-top:8px;">Use <strong>Manage</strong> tab for update/remove actions.</div>
            </article>
          `;
        })
        .join("")
    : renderNotice(`No installed ${noun.toLowerCase()} modules found.`);

  const catalogHtml = available.length
    ? available
        .map((item) => {
          const platforms = Array.isArray(item.platforms) && item.platforms.length ? ` • portals: ${item.platforms.join(", ")}` : "";
          return `
            <article class="card">
              <div class="card-head">
                <h3 class="card-title">${escapeHtml(item.name || item.id)}</h3>
                <span class="small">${escapeHtml(item.id)}</span>
              </div>
              <div class="small">version: ${escapeHtml(item.version || "-")} • source: ${escapeHtml(item.source_label || "")}${escapeHtml(platforms)}</div>
              <div class="muted">${escapeHtml(item.description || "")}</div>
              <div class="inline-row" style="margin-top:8px;">
                <button class="action-btn shop-action" data-kind="${kind}" data-action="install" data-id="${escapeHtml(item.id)}">${kind === "integrations" ? "Download" : "Install"}</button>
              </div>
            </article>
          `;
        })
        .join("")
    : renderNotice(`No additional ${noun.toLowerCase()} modules available in configured repos.`);

  return `
    <div class="card">
      <div class="card-head">
        <h3 class="card-title">${noun} Shop Summary</h3>
        <div class="inline-row">
          <span class="small">updates: ${updatesAvailable}</span>
          <button class="action-btn shop-update-all" data-kind="${kind}" ${updatesAvailable ? "" : "disabled"}>Update All</button>
        </div>
      </div>
      <div class="small">Installed: ${installed.length} • Catalog: ${catalog.length} • Available: ${available.length}</div>
      <div id="shop-status-${kind}" class="small"></div>
    </div>
    ${warningsHtml}
    <div class="card">
      <div class="card-head">
        <h3 class="card-title">${noun} Repos</h3>
      </div>
      <div class="small">Default repo: ${escapeHtml(defaultRepo.name || "Default")} • ${escapeHtml(defaultRepo.url || "")}</div>
      <label style="margin-top:10px;">Additional repos (one per line; optional name as <code>name|url</code>)
        <textarea id="shop-repos-${kind}" style="min-height:110px;">${escapeHtml(reposToText(additionalRepos))}</textarea>
      </label>
      <div class="inline-row" style="margin-top:8px;">
        <button class="inline-btn shop-save-repos" data-kind="${kind}">Save Repos</button>
      </div>
    </div>
    <div class="card">
      <div class="card-head">
        <h3 class="card-title">Installed ${noun}s</h3>
      </div>
      <div class="form-grid shop-grid">${installedHtml}</div>
    </div>
    <div class="card">
      <div class="card-head">
        <h3 class="card-title">${noun} Catalog</h3>
      </div>
      <div class="form-grid shop-grid">${catalogHtml}</div>
    </div>
  `;
}

function renderShopTabbedManager(kind, data, options = {}) {
  const noun = shopLabel(kind);
  const repos = data?.repos || {};
  const defaultRepo = repos.default || { name: "", url: "" };
  const additionalRepos = Array.isArray(repos.additional) ? repos.additional : [];
  const installed = sortedShopItems(data?.installed);
  const catalog = sortedShopItems(data?.catalog);
  const available = sortedShopItems(catalog.filter((item) => !item.installed));
  const updates = sortedShopItems(installed.filter((item) => item.update_available));
  const errors = Array.isArray(data?.errors) ? data.errors : [];
  const updatesAvailable = Number(data?.updates_available || updates.length || 0);
  const runtimeHtml = String(options.runtimeHtml || "").trim();
  const runtimeTitle = String(options.runtimeTitle || `${noun} Runtime`).trim();
  const runtimeCard = options.runtimeCard !== false;
  const showInstalledTab = Object.prototype.hasOwnProperty.call(options, "showInstalledTab")
    ? Boolean(options.showInstalledTab)
    : kind !== "integrations";
  const defaultTab = showInstalledTab ? "installed" : "store";

  const warningsHtml = errors.map((entry) => renderNotice(`${noun} shop: ${entry}`)).join("");

  const installedHtml = installed.length
    ? installed
        .map((entry) => {
          const enabledText = kind === "verbas" || kind === "integrations" ? ` • enabled: ${entry.enabled ? "yes" : "no"}` : "";
          const runtimeText = Object.prototype.hasOwnProperty.call(entry, "running") ? ` • running: ${entry.running ? "yes" : "no"}` : "";
          const requiredText = entry.required ? " • required" : "";
          const platformText = entry.platforms_str ? `<div class="small">Portals: ${escapeHtml(entry.platforms_str)}</div>` : "";

          return `
            <article class="card shop-installed-card" data-kind="${kind}" data-id="${escapeHtml(entry.id)}">
              <div class="card-head">
                <h3 class="card-title">${escapeHtml(entry.name || entry.id)}</h3>
                <span class="small">${escapeHtml(entry.id)}</span>
              </div>
              <div class="small">installed: ${escapeHtml(entry.installed_ver || "0.0.0")} • store: ${escapeHtml(entry.store_ver || "-")} • source: ${escapeHtml(entry.source_label || "local")}${enabledText}${runtimeText}${requiredText}</div>
              <div class="muted">${escapeHtml(entry.description || "")}</div>
              ${platformText}
              ${kind === "integrations" ? `
              <div class="inline-row" style="margin-top:8px;">
                ${entry.enabled
                  ? entry.required
                    ? `<button class="inline-btn" disabled>Required</button>`
                    : `<button class="inline-btn shop-action" data-kind="${kind}" data-action="disable" data-id="${escapeHtml(entry.id)}">Disable</button>`
                  : `<button class="action-btn shop-action" data-kind="${kind}" data-action="enable" data-id="${escapeHtml(entry.id)}">Enable</button>`}
              </div>` : ""}
            </article>
          `;
        })
        .join("")
    : renderNotice(`No installed ${noun.toLowerCase()} modules found.`);

  const storeHtml = available.length
    ? available
        .map((item) => {
          const platforms = Array.isArray(item.platforms) && item.platforms.length ? ` • portals: ${item.platforms.join(", ")}` : "";
          return `
            <article class="card">
              <div class="card-head">
                <h3 class="card-title">${escapeHtml(item.name || item.id)}</h3>
                <span class="small">${escapeHtml(item.id)}</span>
              </div>
              <div class="small">version: ${escapeHtml(item.version || "-")} • source: ${escapeHtml(item.source_label || "")}${escapeHtml(platforms)}</div>
              <div class="muted">${escapeHtml(item.description || "")}</div>
              <div class="inline-row" style="margin-top:8px;">
                <button class="action-btn shop-action" data-kind="${kind}" data-action="install" data-id="${escapeHtml(item.id)}">${kind === "integrations" ? "Download" : "Install"}</button>
              </div>
            </article>
          `;
        })
        .join("")
    : renderNotice(`No additional ${noun.toLowerCase()} modules available in configured repos.`);

  const manageHtml = installed.length
    ? installed
        .map((entry) => {
          const updateButton = entry.update_available
            ? `<button class="action-btn shop-action" data-kind="${kind}" data-action="update" data-id="${escapeHtml(entry.id)}">Update</button>`
            : `<button class="inline-btn" disabled>Up to date</button>`;
          const enabledText = kind === "verbas" || kind === "integrations" ? ` • enabled: ${entry.enabled ? "yes" : "no"}` : "";
          const runtimeText = Object.prototype.hasOwnProperty.call(entry, "running") ? ` • running: ${entry.running ? "yes" : "no"}` : "";
          const requiredText = entry.required ? " • required" : "";
          const enableButton = kind === "integrations"
            ? entry.enabled
              ? entry.required
                ? `<button class="inline-btn" disabled>Required</button>`
                : `<button class="inline-btn shop-action" data-kind="${kind}" data-action="disable" data-id="${escapeHtml(entry.id)}">Disable</button>`
              : `<button class="action-btn shop-action" data-kind="${kind}" data-action="enable" data-id="${escapeHtml(entry.id)}">Enable</button>`
            : "";
          const removeButton = entry.required
            ? `<button class="inline-btn" disabled>Required</button>`
            : `<button class="inline-btn shop-action" data-kind="${kind}" data-action="remove" data-id="${escapeHtml(entry.id)}">Remove</button>`;
          return `
            <article class="card">
              <div class="card-head">
                <h3 class="card-title">${escapeHtml(entry.name || entry.id)}</h3>
                <span class="small">${escapeHtml(entry.id)}</span>
              </div>
              <div class="small">installed: ${escapeHtml(entry.installed_ver || "0.0.0")} • store: ${escapeHtml(entry.store_ver || "-")} • source: ${escapeHtml(entry.source_label || "local")}${enabledText}${runtimeText}${requiredText}</div>
              <div class="muted">${escapeHtml(entry.description || "")}</div>
              <div class="inline-row" style="margin-top:8px;">
                ${updateButton}
                ${enableButton}
                <label class="small inline-row">
                  <input type="checkbox" class="shop-purge" />
                  <span>Delete Data?</span>
                </label>
                ${removeButton}
              </div>
            </article>
          `;
        })
        .join("")
    : renderNotice(`No installed ${noun.toLowerCase()} modules found.`);

  const runtimeSection = runtimeHtml
    ? runtimeCard
      ? `
      <div class="card">
        <div class="card-head"><h3 class="card-title">${escapeHtml(runtimeTitle)}</h3></div>
        <div class="form-grid shop-grid">${runtimeHtml}</div>
      </div>
    `
      : `<div class="form-grid shop-grid">${runtimeHtml}</div>`
    : "";
  const installedPanelHtml = runtimeSection
    ? runtimeSection
    : `<div class="form-grid shop-grid">${installedHtml}</div>`;
  const defaultRepoName = String(defaultRepo.name || "Default").trim() || "Default";
  const defaultRepoUrl = String(defaultRepo.url || "").trim();
  const additionalRepoRows = additionalRepos.map((repo) => renderShopRepoListItem(kind, repo)).filter(Boolean).join("");

  return `
    <section class="shop-manager-root" data-kind="${kind}">
      <div class="card">
      <div class="card-head">
        <h3 class="card-title">${noun} Manager</h3>
        <div class="inline-row">
          <span class="small">Installed: ${installed.length}</span>
          <span class="small">Store: ${catalog.length}</span>
          <span class="small">Updates: ${updatesAvailable}</span>
        </div>
      </div>
      <div id="shop-status-${kind}" class="small"></div>
      ${warningsHtml}
      <div class="shop-tabs" data-kind="${kind}">
        ${showInstalledTab ? `<button class="shop-tab-btn ${defaultTab === "installed" ? "active" : ""}" data-kind="${kind}" data-tab="installed">Installed</button>` : ""}
        <button class="shop-tab-btn ${defaultTab === "store" ? "active" : ""}" data-kind="${kind}" data-tab="store">Store</button>
        <button class="shop-tab-btn" data-kind="${kind}" data-tab="manage">Manage</button>
        <button class="shop-tab-btn" data-kind="${kind}" data-tab="settings">Settings</button>
      </div>

      ${showInstalledTab ? `<section class="shop-tab-panel ${defaultTab === "installed" ? "active" : ""}" data-kind="${kind}" data-tab-panel="installed">
        ${installedPanelHtml}
      </section>` : ""}

      <section class="shop-tab-panel ${defaultTab === "store" ? "active" : ""}" data-kind="${kind}" data-tab-panel="store">
        <div class="form-grid shop-grid">${storeHtml}</div>
      </section>

      <section class="shop-tab-panel" data-kind="${kind}" data-tab-panel="manage">
        <div class="inline-row" style="margin: 8px 0 12px;">
          <button class="action-btn shop-update-all" data-kind="${kind}" ${updatesAvailable ? "" : "disabled"}>Update All</button>
          <span class="small">${updatesAvailable} update(s) available.</span>
        </div>
        <div class="form-grid shop-grid">${manageHtml}</div>
      </section>

      <section class="shop-tab-panel" data-kind="${kind}" data-tab-panel="settings">
        <div class="shop-repo-section">
          <div class="small">Default repo (read-only)</div>
          <article class="shop-repo-item default">
            <div class="shop-repo-body">
              <div class="shop-repo-name">${escapeHtml(defaultRepoName)}</div>
              <div class="shop-repo-url"><code>${escapeHtml(defaultRepoUrl || "(not set)")}</code></div>
            </div>
            <span class="small">Built-in</span>
          </article>
        </div>
        <div class="shop-repo-section">
          <div class="small">Additional repos</div>
          <div class="form-grid two-col shop-repo-inputs">
            <label>Repo Name (optional)
              <input id="shop-repo-name-${kind}" type="text" placeholder="My ${escapeHtml(noun)} Repo" />
            </label>
            <label>Repo URL
              <input id="shop-repo-url-${kind}" type="text" placeholder="https://example.com/${kind}-manifest.json" />
            </label>
          </div>
          <div class="inline-row" style="margin-top:8px;">
            <button class="inline-btn shop-add-repo" type="button" data-kind="${kind}">Add Repo</button>
            <button class="action-btn shop-save-repos" type="button" data-kind="${kind}">Save Repos</button>
          </div>
          <div id="shop-repo-list-${kind}" class="shop-repo-list" style="margin-top:10px;">
            ${additionalRepoRows || `<div class="small shop-repo-empty">No additional repos configured.</div>`}
          </div>
        </div>
      </section>
      </div>
    </section>
  `;
}

function bindShopTabs(kind) {
  const buttons = Array.from(document.querySelectorAll(`.shop-tab-btn[data-kind='${kind}']`));
  const panels = Array.from(document.querySelectorAll(`.shop-tab-panel[data-kind='${kind}']`));
  if (!buttons.length || !panels.length) {
    return;
  }

  buttons.forEach((button) => {
    button.addEventListener("click", () => activateShopTab(kind, button.dataset.tab));
  });
  activateShopTab(kind, getActiveShopTab(kind) || String(buttons[0]?.dataset?.tab || "installed"));
}

function buildVerbaRuntimeHtml(runtimeData, shopData) {
  const items = Array.isArray(runtimeData?.items) ? runtimeData.items : [];
  const installedShopItems = Array.isArray(shopData?.installed) ? shopData.installed : [];
  const shopById = new Map(
    installedShopItems
      .map((entry) => [String(entry?.id || "").trim(), entry])
      .filter(([id]) => Boolean(id))
  );

  if (!items.length) {
    resetRuntimeSettingsCatalog("verbas");
    return renderNotice("No verba found in verba registry.");
  }

  resetRuntimeSettingsCatalog("verbas");

  const sortedItems = items.slice().sort((left, right) => {
    const leftId = String(left?.id || "").trim();
    const rightId = String(right?.id || "").trim();
    const leftShopEntry = shopById.get(leftId) || {};
    const rightShopEntry = shopById.get(rightId) || {};
    const leftName = String(left?.name || leftShopEntry.name || leftId).trim() || leftId;
    const rightName = String(right?.name || rightShopEntry.name || rightId).trim() || rightId;
    return compareShopNames(leftName, rightName, leftId, rightId);
  });

  return sortedItems
    .map((item) => {
      const shopEntry = shopById.get(String(item.id || "").trim()) || {};
      const settings = Array.isArray(item.settings) ? item.settings : [];
      const pluginId = String(item.id || "").trim();
      registerRuntimeSettings("verbas", pluginId, {
        label: String(item.name || pluginId).trim() || pluginId,
        endpoint: "/api/verbas",
        settings,
      });
      const settingsBlock = settings.length
        ? `
            <div class="inline-row" style="margin-top:8px;">
              <button class="inline-btn open-runtime-settings" data-runtime-kind="verbas" data-runtime-key="${escapeHtml(pluginId)}">Settings</button>
            </div>
          `
        : `<div class="small">No configurable settings.</div>`;
      const platformValues = Array.isArray(item.platforms) && item.platforms.length
        ? item.platforms
        : Array.isArray(shopEntry.platforms)
          ? shopEntry.platforms
          : [];
      const platforms = platformValues.length ? platformValues.join(", ") : "all";
      const installedVer = String(shopEntry.installed_ver || "0.0.0").trim() || "0.0.0";
      const storeVer = String(shopEntry.store_ver || "-").trim() || "-";
      const sourceLabel = String(shopEntry.source_label || "local").trim() || "local";
      const description = String(shopEntry.description || item.description || "No description").trim() || "No description";
      return `
        <article class="card" data-plugin-id="${escapeHtml(item.id)}">
          <div class="card-head">
            <h3 class="card-title">${escapeHtml(item.name)}</h3>
            <div class="inline-row">
              <span class="small">${escapeHtml(item.id)}</span>
              <button class="inline-btn verba-toggle">${item.enabled ? "Disable" : "Enable"}</button>
            </div>
          </div>
          <div class="small">installed: ${escapeHtml(installedVer)} • store: ${escapeHtml(storeVer)} • source: ${escapeHtml(sourceLabel)} • enabled: ${item.enabled ? "yes" : "no"}</div>
          <div class="muted">${escapeHtml(description)}</div>
          <div class="small">Portals: ${escapeHtml(platforms)}</div>
          ${settingsBlock}
        </article>
      `;
    })
    .join("");
}

function buildSurfaceRuntimeHtml(kind, runtimeData, shopData) {
  const items = Array.isArray(runtimeData?.items) ? runtimeData.items : [];
  const installedShopItems = Array.isArray(shopData?.installed) ? shopData.installed : [];
  const endpoint = kind === "cores" ? "/api/cores" : "/api/portals";
  const moduleSuffix = kind === "cores" ? "_core" : "_portal";
  const shopByModuleKey = new Map();
  const shopById = new Map();
  installedShopItems.forEach((entry) => {
    const moduleKey = String(entry?.module_key || "").trim();
    const entryId = String(entry?.id || "").trim();
    if (moduleKey) {
      shopByModuleKey.set(moduleKey, entry);
    }
    if (entryId) {
      shopById.set(entryId, entry);
    }
  });
  const resolveShopEntry = (runtimeKey) => {
    const key = String(runtimeKey || "").trim();
    if (!key) {
      return null;
    }
    const byModule = shopByModuleKey.get(key);
    if (byModule) {
      return byModule;
    }
    const normalizedId = key.endsWith(moduleSuffix) ? key.slice(0, -moduleSuffix.length) : key;
    return shopById.get(normalizedId) || shopById.get(key) || null;
  };

  if (!items.length) {
    resetRuntimeSettingsCatalog(kind);
    return renderNotice(`No ${kind} found.`);
  }

  resetRuntimeSettingsCatalog(kind);

  const sortedItems = items.slice().sort((left, right) => {
    const leftKey = String(left?.key || "").trim();
    const rightKey = String(right?.key || "").trim();
    const leftShopEntry = resolveShopEntry(leftKey) || {};
    const rightShopEntry = resolveShopEntry(rightKey) || {};
    const leftName = String(left?.label || leftShopEntry.name || leftKey).trim() || leftKey;
    const rightName = String(right?.label || rightShopEntry.name || rightKey).trim() || rightKey;
    return compareShopNames(leftName, rightName, leftKey, rightKey);
  });

  return sortedItems
    .map((item) => {
      const shopEntry = resolveShopEntry(item.key) || {};
      const settings = Array.isArray(item.settings) ? item.settings : [];
      const running = Boolean(item.running);
      const desired = Boolean(item.desired_running);
      const statusClass = running ? "running" : "stopped";
      const statusText = running ? "Running" : desired ? "Pending start" : "Stopped";
      const actionLabel = running ? "Stop" : "Start";
      const installedVer = String(shopEntry.installed_ver || "0.0.0").trim() || "0.0.0";
      const storeVer = String(shopEntry.store_ver || "-").trim() || "-";
      const sourceLabel = String(shopEntry.source_label || "local").trim() || "local";
      const description = String(shopEntry.description || "").trim();
      const surfaceKey = String(item.key || "").trim();
      registerRuntimeSettings(kind, surfaceKey, {
        label: String(item.label || surfaceKey).trim() || surfaceKey,
        endpoint,
        settings,
      });
      const settingsBlock = settings.length
        ? `
            <div class="inline-row" style="margin-top:8px;">
              <button class="inline-btn open-runtime-settings" data-runtime-kind="${escapeHtml(kind)}" data-runtime-key="${escapeHtml(surfaceKey)}">Settings</button>
            </div>
          `
        : `<div class="small">No settings in manifest.</div>`;
      return `
        <article class="card" data-surface-key="${escapeHtml(item.key)}">
          <div class="card-head">
            <h3 class="card-title">${escapeHtml(item.label || item.key)}</h3>
            <div class="inline-row">
              <span class="status-chip ${statusClass}">${statusText}</span>
              <button class="inline-btn surface-toggle">${actionLabel}</button>
            </div>
          </div>
          <div class="small">installed: ${escapeHtml(installedVer)} • store: ${escapeHtml(storeVer)} • source: ${escapeHtml(sourceLabel)} • running: ${running ? "yes" : "no"}</div>
          ${description ? `<div class="muted">${escapeHtml(description)}</div>` : ""}
          ${settingsBlock}
        </article>
      `;
    })
    .join("");
}

function replaceShopManagerInPlace(kind, managerHtml) {
  const existing = document.querySelector(`.shop-manager-root[data-kind='${kind}']`);
  if (!existing) {
    return false;
  }
  const template = document.createElement("template");
  template.innerHTML = String(managerHtml || "").trim();
  const replacement = template.content.firstElementChild;
  if (!replacement) {
    return false;
  }
  existing.replaceWith(replacement);
  return true;
}

async function refreshShopManagerInPlace(kind, preferredTab = "") {
  const targetTab = String(preferredTab || getActiveShopTab(kind) || "installed").trim() || "installed";

  if (kind === "verbas") {
    const [runtimeData, shopData] = await Promise.all([api("/api/verbas"), api("/api/shop/verbas")]);
    const runtimeHtml = buildVerbaRuntimeHtml(runtimeData, shopData);
    const managerHtml = renderShopTabbedManager("verbas", shopData, {
      runtimeHtml,
      runtimeTitle: "Verba Runtime",
      runtimeCard: false,
    });
    if (!replaceShopManagerInPlace("verbas", managerHtml)) {
      return false;
    }
    bindVerbaRuntimeActions(document.getElementById("view-root"));
    bindShopTabs("verbas");
    bindShopActions("verbas");
    activateShopTab("verbas", targetTab);
    return true;
  }

  if (kind === "portals" || kind === "cores") {
    const endpoint = kind === "cores" ? "/api/cores" : "/api/portals";
    const shopApi = kind === "cores" ? "/api/shop/cores" : "/api/shop/portals";
    const [runtimeData, shopData] = await Promise.all([api(endpoint), api(shopApi)]);
    const runtimeHtml = buildSurfaceRuntimeHtml(kind, runtimeData, shopData);
    const managerHtml = renderShopTabbedManager(kind, shopData, {
      runtimeHtml,
      runtimeTitle: kind === "cores" ? "Core Runtime" : "Portal Runtime",
      runtimeCard: false,
    });
    if (!replaceShopManagerInPlace(kind, managerHtml)) {
      return false;
    }
    bindSurfaceRuntimeActions(kind, endpoint, document.getElementById("view-root"));
    bindShopTabs(kind);
    bindShopActions(kind);
    activateShopTab(kind, targetTab);
    return true;
  }

  if (kind === "integrations") {
    const shopData = await api("/api/shop/integrations");
    const managerHtml = renderShopTabbedManager("integrations", shopData, {
      runtimeCard: false,
    });
    if (!replaceShopManagerInPlace("integrations", managerHtml)) {
      return false;
    }
    bindShopTabs("integrations");
    bindShopActions("integrations");
    activateShopTab("integrations", targetTab);
    return true;
  }

  return false;
}

function encodeCoreManagerId(value) {
  return encodeURIComponent(String(value ?? ""));
}

function decodeCoreManagerId(value) {
  try {
    return decodeURIComponent(String(value || ""));
  } catch {
    return String(value || "");
  }
}

function renderCoreManagerField(field) {
  const key = String(field?.key || "").trim();
  if (!key) {
    return "";
  }
  const label = String(field?.label || key).trim() || key;
  const type = String(field?.type || "text").toLowerCase();
  const description = String(field?.description || "").trim();
  const descHtml = description ? `<div class="small">${escapeHtml(description)}</div>` : "";
  const placeholder = String(field?.placeholder || "").trim();
  const placeholderAttr = placeholder ? `placeholder="${escapeHtml(placeholder)}"` : "";
  const readOnly = boolFromAny(field?.read_only, false);
  const disabled = boolFromAny(field?.disabled, false);
  const hideLabel = boolFromAny(field?.hide_label, false);
  const readOnlyAttr = readOnly ? " readonly" : "";
  const disabledAttr = disabled ? " disabled" : "";
  const showWhen = field?.show_when && typeof field.show_when === "object" ? field.show_when : {};
  const showWhenAll = Array.isArray(field?.show_when_all)
    ? field.show_when_all.filter((item) => item && typeof item === "object")
    : [];
  const disableWhen = field?.disable_when && typeof field.disable_when === "object" ? field.disable_when : {};
  const disableWhenAll = Array.isArray(field?.disable_when_all)
    ? field.disable_when_all.filter((item) => item && typeof item === "object")
    : [];
  const disabledNote = String(field?.disabled_note || "").trim();
  const normalizeCondition = (condition) => {
    const sourceKey = String(condition?.source_key ?? condition?.key ?? "").trim();
    const values = [];
    const appendShowValue = (raw) => {
      const token = String(raw ?? "").trim();
      if (token && !values.includes(token)) {
        values.push(token);
      }
    };
    if (Array.isArray(condition?.any_of)) {
      condition.any_of.forEach(appendShowValue);
    }
    if (Array.isArray(condition?.values)) {
      condition.values.forEach(appendShowValue);
    }
    if (condition?.equals !== undefined) {
      appendShowValue(condition.equals);
    }
    if (condition?.eq !== undefined) {
      appendShowValue(condition.eq);
    }
    if (condition?.value !== undefined) {
      appendShowValue(condition.value);
    }
    return { sourceKey, values };
  };
  const encodeConditionValues = (values) => {
    try {
      return encodeURIComponent(JSON.stringify(values));
    } catch (_error) {
      return "";
    }
  };
  const wrapWithCondition = (innerHtml, condition) => {
    const { sourceKey, values } = normalizeCondition(condition || {});
    if (!sourceKey || !values.length) {
      return innerHtml;
    }
    const encodedValues = encodeConditionValues(values);
    return `<div data-core-show-source-key="${escapeHtml(sourceKey)}" data-core-show-values="${escapeHtml(encodedValues)}">${innerHtml}</div>`;
  };
  const wrapWithDisableCondition = (innerHtml, condition) => {
    const { sourceKey, values } = normalizeCondition(condition || {});
    if (!sourceKey || !values.length) {
      return innerHtml;
    }
    const encodedValues = encodeConditionValues(values);
    const noteAttr = disabledNote ? ` data-core-disable-note="${escapeHtml(disabledNote)}"` : "";
    return `<div class="core-conditional-field" data-core-disable-source-key="${escapeHtml(
      sourceKey
    )}" data-core-disable-values="${escapeHtml(encodedValues)}"${noteAttr}>${innerHtml}</div>`;
  };
  const wrapField = (innerHtml) => {
    let html = innerHtml;
    html = disableWhenAll.length
      ? disableWhenAll.reduce((currentHtml, condition) => wrapWithDisableCondition(currentHtml, condition), html)
      : wrapWithDisableCondition(html, disableWhen);
    html = showWhenAll.length
      ? showWhenAll.reduce((currentHtml, condition) => wrapWithCondition(currentHtml, condition), html)
      : wrapWithCondition(html, showWhen);
    return html;
  };

  if (type === "table") {
    const rawColumns = Array.isArray(field?.columns) ? field.columns : [];
    const columns = rawColumns
      .map((col, index) => {
        if (col && typeof col === "object") {
          const keyName = String(col.key ?? col.id ?? col.field ?? `col_${index}`).trim() || `col_${index}`;
          const labelName = String(col.label ?? keyName).trim() || keyName;
          return { key: keyName, label: labelName };
        }
        const labelName = String(col ?? "").trim();
        const keyName = labelName || `col_${index}`;
        return { key: keyName, label: labelName || keyName };
      })
      .filter((col) => col.key);
    const rows = Array.isArray(field?.rows) ? field.rows : [];

    if (!columns.length) {
      return wrapField(`
        <label>${escapeHtml(label)}
          <div class="small">No table columns configured.</div>
          ${descHtml}
        </label>
      `);
    }

    const headHtml = columns.map((col) => `<th>${escapeHtml(col.label)}</th>`).join("");
    const bodyHtml = rows.length
      ? rows
          .map((rawRow) => {
            const rowObj = rawRow && typeof rawRow === "object" ? rawRow : {};
            const cells = columns
              .map((col, colIndex) => {
                let value = "";
                if (Array.isArray(rawRow)) {
                  value = rawRow[colIndex] ?? "";
                } else {
                  value = rowObj[col.key] ?? "";
                }
                return `<td>${escapeHtml(value)}</td>`;
              })
              .join("");
            return `<tr>${cells}</tr>`;
          })
          .join("")
      : `<tr><td colspan="${columns.length}" class="small">No rows.</td></tr>`;

    return wrapField(`
      <label>${escapeHtml(label)}
        <div class="core-data-table-wrap">
          <table class="core-data-table">
            <thead><tr>${headHtml}</tr></thead>
            <tbody>${bodyHtml}</tbody>
          </table>
        </div>
        ${descHtml}
      </label>
    `);
  }

  if (type === "bar_chart" || type === "bars") {
    const points = Array.isArray(field?.points) ? field.points : [];
    const normalized = points
      .map((point) => {
        if (point && typeof point === "object") {
          const pointLabel = String(point.label ?? point.key ?? point.name ?? "").trim();
          const pointValue = Number(point.value ?? point.count ?? 0);
          return {
            label: pointLabel || "item",
            value: Number.isFinite(pointValue) ? pointValue : 0,
          };
        }
        return {
          label: String(point ?? "").trim() || "item",
          value: 0,
        };
      })
      .filter((row) => row.label);
    const maxValue = normalized.reduce((acc, row) => Math.max(acc, row.value), 0);

    const chartHtml = normalized.length
      ? normalized
          .map((row) => {
            const widthPct = maxValue > 0 ? Math.max(0, Math.min(100, (row.value / maxValue) * 100)) : 0;
            return `
              <div class="core-bar-row">
                <div class="core-bar-label">${escapeHtml(row.label)}</div>
                <div class="core-bar-track"><div class="core-bar-fill" style="width:${widthPct}%;"></div></div>
                <div class="core-bar-value">${escapeHtml(String(row.value))}</div>
              </div>
            `;
          })
          .join("")
      : `<div class="small">No chart data.</div>`;

    return wrapField(`
      <label>${escapeHtml(label)}
        <div class="core-bar-chart">${chartHtml}</div>
        ${descHtml}
      </label>
    `);
  }

  if (type === "image") {
    const src = String(field?.src ?? field?.url ?? "").trim();
    if (!src) {
      if (hideLabel) {
        return wrapField(`
          <div class="small">No image available.</div>
          ${descHtml}
        `);
      }
      return wrapField(`
        <label>${escapeHtml(label)}
          <div class="small">No image available.</div>
          ${descHtml}
        </label>
      `);
    }
    const alt = String(field?.alt || label || "Event image").trim() || "Event image";
    const imgCaption = String(field?.caption || "").trim();
    if (hideLabel) {
      return wrapField(`
        <div style="margin-top:6px;">
          <img src="${escapeHtml(src)}" alt="${escapeHtml(alt)}" loading="lazy" style="width:100%; max-height:320px; object-fit:contain; border:1px solid rgba(255,255,255,0.12); border-radius:10px; background:rgba(0,0,0,0.2);" />
        </div>
        ${imgCaption ? `<div class="small" style="margin-top:6px;">${escapeHtml(imgCaption)}</div>` : ""}
        ${descHtml}
      `);
    }
    return wrapField(`
      <label>${escapeHtml(label)}
        <div style="margin-top:6px;">
          <img src="${escapeHtml(src)}" alt="${escapeHtml(alt)}" loading="lazy" style="width:100%; max-height:320px; object-fit:contain; border:1px solid rgba(255,255,255,0.12); border-radius:10px; background:rgba(0,0,0,0.2);" />
        </div>
        ${imgCaption ? `<div class="small" style="margin-top:6px;">${escapeHtml(imgCaption)}</div>` : ""}
        ${descHtml}
      </label>
    `);
  }

  if (type === "checkbox") {
    const checked = boolFromAny(field?.value, false) ? "checked" : "";
    return wrapField(`
      <label>
        ${escapeHtml(label)}
        ${renderToggleRow(
          `<input class="toggle-input" type="checkbox" data-core-field-key="${escapeHtml(
            key
          )}" data-core-field-type="checkbox" ${checked}${disabledAttr} />`
        )}
        ${descHtml}
      </label>
    `);
  }

  if (type === "multiselect") {
    const options = Array.isArray(field?.options) ? field.options : [];
    const selectedValues = new Set(
      (Array.isArray(field?.value) ? field.value : [field?.value])
        .map((item) => String(item ?? "").trim())
        .filter(Boolean)
    );
    const dependent = field?.dependent_options && typeof field.dependent_options === "object" ? field.dependent_options : {};
    const filterSourceKey = String(dependent?.source_key || "").trim();
    let filterOptionsMap = "";
    let filterDefaultOptions = "";
    let filterPreferredValues = "";
    if (filterSourceKey) {
      try {
        filterOptionsMap = encodeURIComponent(JSON.stringify(dependent?.options_by_source || {}));
      } catch (_error) {
        filterOptionsMap = "";
      }
      try {
        const fallbackOptions = Array.isArray(dependent?.default_options) ? dependent.default_options : options;
        filterDefaultOptions = encodeURIComponent(JSON.stringify(fallbackOptions));
      } catch (_error) {
        filterDefaultOptions = "";
      }
      try {
        filterPreferredValues = encodeURIComponent(JSON.stringify(Array.from(selectedValues)));
      } catch (_error) {
        filterPreferredValues = "";
      }
    }
    const dependentAttrs = filterSourceKey
      ? ` data-core-filter-source-key="${escapeHtml(filterSourceKey)}"
          data-core-filter-options-map="${escapeHtml(filterOptionsMap)}"
          data-core-filter-default-options="${escapeHtml(filterDefaultOptions)}"
          data-core-filter-preferred-values="${escapeHtml(filterPreferredValues)}"`
      : "";
    const size = Math.max(4, Math.min(10, options.length || 6));
    const optionsHtml = options
      .map((raw) => {
        if (raw && typeof raw === "object") {
          const optionValue = String(raw.value ?? raw.id ?? raw.key ?? raw.label ?? "");
          const optionLabel = String(raw.label ?? optionValue);
          const isSelected = selectedValues.has(optionValue) ? "selected" : "";
          return `<option value="${escapeHtml(optionValue)}" ${isSelected}>${escapeHtml(optionLabel)}</option>`;
        }
        const optionValue = String(raw ?? "");
        const isSelected = selectedValues.has(optionValue) ? "selected" : "";
        return `<option value="${escapeHtml(optionValue)}" ${isSelected}>${escapeHtml(optionValue)}</option>`;
      })
      .join("");
    return wrapField(`
      <label>${escapeHtml(label)}
        <select multiple size="${size}" data-core-field-key="${escapeHtml(key)}" data-core-field-type="multiselect"${dependentAttrs}${disabledAttr}>${optionsHtml}</select>
        ${descHtml}
      </label>
    `);
  }

  if (type === "select") {
    const options = Array.isArray(field?.options) ? field.options : [];
    const selected = String(field?.value ?? "");
    const dependent = field?.dependent_options && typeof field.dependent_options === "object" ? field.dependent_options : {};
    const filterSourceKey = String(dependent?.source_key || "").trim();
    let filterOptionsMap = "";
    let filterDefaultOptions = "";
    if (filterSourceKey) {
      try {
        filterOptionsMap = encodeURIComponent(JSON.stringify(dependent?.options_by_source || {}));
      } catch (_error) {
        filterOptionsMap = "";
      }
      try {
        const fallbackOptions = Array.isArray(dependent?.default_options) ? dependent.default_options : options;
        filterDefaultOptions = encodeURIComponent(JSON.stringify(fallbackOptions));
      } catch (_error) {
        filterDefaultOptions = "";
      }
    }
    const dependentAttrs = filterSourceKey
      ? ` data-core-filter-source-key="${escapeHtml(filterSourceKey)}"
          data-core-filter-options-map="${escapeHtml(filterOptionsMap)}"
          data-core-filter-default-options="${escapeHtml(filterDefaultOptions)}"
          data-core-filter-preferred-value="${escapeHtml(selected)}"`
      : "";
    const renderSelectOptionRows = (rows) =>
      rows
        .map((raw) => {
          if (raw && typeof raw === "object" && Array.isArray(raw.options) && !("value" in raw) && !("id" in raw) && !("key" in raw)) {
            const groupLabel = String(raw.label ?? raw.title ?? "Options").trim() || "Options";
            const groupRows = renderSelectOptionRows(raw.options);
            return groupRows ? `<optgroup label="${escapeHtml(groupLabel)}">${groupRows}</optgroup>` : "";
          }
          if (raw && typeof raw === "object") {
            const optionValue = String(raw.value ?? raw.id ?? raw.key ?? raw.label ?? "");
            const optionLabel = String(raw.label ?? optionValue);
            const isSelected = optionValue === selected ? "selected" : "";
            const frameworkAttr = raw.framework ? ` data-framework="${escapeHtml(raw.framework)}"` : "";
            return `<option value="${escapeHtml(optionValue)}" ${isSelected}${frameworkAttr}>${escapeHtml(optionLabel)}</option>`;
          }
          const optionValue = String(raw ?? "");
          const isSelected = optionValue === selected ? "selected" : "";
          return `<option value="${escapeHtml(optionValue)}" ${isSelected}>${escapeHtml(optionValue)}</option>`;
        })
        .join("");
    const optionsHtml = renderSelectOptionRows(options);
    return wrapField(`
      <label>${escapeHtml(label)}
        <select data-core-field-key="${escapeHtml(key)}" data-core-field-type="select"${dependentAttrs}${disabledAttr}>${optionsHtml}</select>
        ${descHtml}
      </label>
    `);
  }

  if (type === "textarea" || type === "multiline") {
    if (readOnly) {
      const readonlyText = escapeHtml(String(field?.value ?? "")).replace(/\n/g, "<br>");
      if (hideLabel) {
        return wrapField(`
          <div class="core-readonly-text">${readonlyText}</div>
          ${descHtml}
        `);
      }
      return wrapField(`
        <label>${escapeHtml(label)}
          <div class="core-readonly-text">${readonlyText}</div>
          ${descHtml}
        </label>
      `);
    }
    return wrapField(`
      <label>${escapeHtml(label)}
        <textarea data-core-field-key="${escapeHtml(key)}" data-core-field-type="textarea"${readOnlyAttr}${disabledAttr} ${placeholderAttr}>${escapeHtml(
          field?.value ?? ""
        )}</textarea>
        ${descHtml}
      </label>
    `);
  }

  const htmlType = type === "password" ? "password" : type === "number" ? "number" : "text";
  const numberAttrs =
    type === "number"
      ? ` step="${escapeHtml(field?.step ?? "any")}"${
          field?.min !== undefined ? ` min="${escapeHtml(field.min)}"` : ""
        }${field?.max !== undefined ? ` max="${escapeHtml(field.max)}"` : ""}`
      : "";
  return wrapField(`
    <label>${escapeHtml(label)}
      <input type="${htmlType}"${numberAttrs}${readOnlyAttr}${disabledAttr} value="${escapeHtml(field?.value ?? "")}" ${placeholderAttr} data-core-field-key="${escapeHtml(
    key
  )}" data-core-field-type="${escapeHtml(type)}" />
      ${descHtml}
    </label>
  `);
}

function renderCoreSettingsManager(body, tabSpec) {
  const safeTabLabel = escapeHtml(tabSpec?.label || tabSpec?.core_key || "Core");
  const safeCoreKey = escapeHtml(tabSpec?.core_key || "");
  const summary = String(body.summary || "").trim();
  const stats = Array.isArray(body.stats) ? body.stats : [];
  const ui = body?.ui && typeof body.ui === "object" ? body.ui : {};
  const useTabs = boolFromAny(ui?.use_tabs, false);
  const createTabLabel = String(ui?.create_tab_label || "Create").trim() || "Create";
  const itemsTabLabel = String(ui?.items_tab_label || "Current").trim() || "Current";
  const itemFieldsDropdown = boolFromAny(ui?.item_fields_dropdown, false);
  const itemFieldsDropdownLabel = String(ui?.item_fields_dropdown_label || "Settings").trim() || "Settings";
  const itemFieldsPopup = boolFromAny(ui?.item_fields_popup, false);
  const itemFieldsPopupLabel = String(ui?.item_fields_popup_label || itemFieldsDropdownLabel || "Settings").trim() || "Settings";
  const itemSectionsInDropdown = boolFromAny(ui?.item_sections_in_dropdown, false);
  const addForm = ui?.add_form && typeof ui.add_form === "object" ? ui.add_form : {};
  const addFields = Array.isArray(addForm?.fields) ? addForm.fields : [];
  const itemForms = Array.isArray(ui?.item_forms) ? ui.item_forms : [];
  const addAction = String(addForm?.action || "").trim();
  const addSubmitLabel = String(addForm?.submit_label || "Add").trim() || "Add";
  const managerTitle = String(ui?.title || "Manager").trim() || "Manager";
  const emptyMessage = String(ui?.empty_message || body?.empty_message || "No entries found.").trim();
  const managerTabsRaw = Array.isArray(ui?.manager_tabs) ? ui.manager_tabs : [];
  const defaultManagerTab = String(ui?.default_tab || "").trim();
  const statsRefreshButton = boolFromAny(ui?.stats_refresh_button, false);
  const statsRefreshLabel = String(ui?.stats_refresh_label || "Refresh").trim() || "Refresh";
  const statsControls = Array.isArray(ui?.stats_controls)
    ? ui.stats_controls.filter((item) => item && typeof item === "object")
    : [];
  const statsControlsAction = String(ui?.stats_controls_action || "").trim();
  const statsControlsAutoSave = boolFromAny(ui?.stats_controls_auto_save, true);

  function renderCoreStatsControlField(field) {
    const key = String(field?.key || "").trim();
    if (!key) {
      return "";
    }
    const label = String(field?.label || key).trim() || key;
    const type = String(field?.type || "checkbox").trim().toLowerCase();
    if (type === "checkbox") {
      const checked = boolFromAny(field?.value, false) ? " checked" : "";
      return `
        <label class="small core-stats-control-toggle">
          <input type="checkbox"${checked} data-core-field-key="${escapeHtml(key)}" data-core-field-type="checkbox" />
          ${escapeHtml(label)}
        </label>
      `;
    }
    const value = String(field?.value ?? "");
    return `
      <label class="small core-stats-control-input">
        ${escapeHtml(label)}
        <input type="text" value="${escapeHtml(value)}" data-core-field-key="${escapeHtml(key)}" data-core-field-type="text" />
      </label>
    `;
  }

  const statsControlsHtml =
    statsControlsAction && statsControls.length
      ? `
        <form class="inline-row core-stats-controls-form"
          data-core-key="${safeCoreKey}"
          data-core-action="${escapeHtml(statsControlsAction)}"
          data-core-auto-save="${statsControlsAutoSave ? "1" : "0"}"
          style="margin-left:auto; gap:10px; align-items:center;">
          ${statsControls.map((field) => renderCoreStatsControlField(field)).join("")}
          <span class="small core-manager-status"></span>
        </form>
      `
      : "";

  const statsHtml = stats.length || statsRefreshButton || statsControlsHtml
    ? `
      <div class="core-metric-row">
        ${stats
          .map((entry) => {
            const label = String(entry?.label || "").trim();
            const value = entry?.value;
            if (!label) {
              return "";
            }
            const valueText = String(value ?? "-").trim() || "-";
            return `
              <div class="core-metric-pill">
                <div class="small">${escapeHtml(label)}</div>
                <div>${escapeHtml(valueText)}</div>
              </div>
            `;
          })
          .join("")}
        ${statsControlsHtml}
        ${
          statsRefreshButton
            ? `<button type="button" class="action-btn core-tab-refresh-btn" data-core-tab-refresh="1">${escapeHtml(
                statsRefreshLabel
              )}</button>`
            : ""
        }
      </div>
    `
    : "";

  function renderCoreManagerItemCard(item, renderOptions = {}) {
    const itemId = String(item?.id || "").trim();
    const encodedId = escapeHtml(encodeCoreManagerId(itemId));
    const title = String(item?.title || itemId || "(item)").trim() || "(item)";
    const subtitle = String(item?.subtitle || "").trim();
    const detail = String(item?.detail || "").trim();
    const itemGroup = String(item?.group || "").trim().toLowerCase();
    const itemGroupToken = itemGroup.replace(/[^a-z0-9_-]/g, "");
    const itemGroupClass = itemGroupToken ? ` core-manager-item-${itemGroupToken}` : "";
    const itemFields = Array.isArray(item?.fields) ? item.fields : [];
    const sections = Array.isArray(item?.sections) ? item.sections : [];
    const explicitPopupFields = Array.isArray(item?.popup_fields) ? item.popup_fields : [];
    const itemFieldsPopupEnabled = itemFieldsPopup && boolFromAny(item?.fields_popup, true);
    const itemFieldsDropdownEnabled = boolFromAny(item?.fields_dropdown, itemFieldsDropdown);
    const itemFieldsDropdownLabelLocal = String(item?.fields_dropdown_label || itemFieldsDropdownLabel).trim() || "Settings";
    const itemSectionsInDropdownEnabled = boolFromAny(item?.sections_in_dropdown, itemSectionsInDropdown);
    const saveAction = String(item?.save_action || "").trim();
    const resetAction = String(item?.reset_action || "").trim();
    const removeAction = String(item?.remove_action || "").trim();
    const runAction = String(item?.run_action || "").trim();
    const runConfirm = String(item?.run_confirm || "").trim();
    const removeConfirm = String(item?.remove_confirm || "Remove this item?").trim();
    const resetConfirm = String(item?.reset_confirm || "Reset this item to defaults?").trim();
    const itemFieldContent = itemFields.map((field) => renderCoreManagerField(field)).join("");
    const popupFields = [];
    explicitPopupFields.forEach((field) => {
      if (field && typeof field === "object") {
        popupFields.push({ ...field });
      }
    });
    if (itemFieldsPopupEnabled) {
      itemFields.forEach((field) => {
        if (field && typeof field === "object") {
          popupFields.push({ ...field });
        }
      });
      sections.forEach((section) => {
        const sectionLabel = String(section?.label || "Section").trim() || "Section";
        const fields = Array.isArray(section?.fields) ? section.fields : [];
        fields.forEach((field) => {
          if (!field || typeof field !== "object") {
            return;
          }
          const nextField = { ...field };
          const rawLabel = String(nextField.label || nextField.key || "Field").trim() || "Field";
          nextField.label = `${sectionLabel} • ${rawLabel}`;
          popupFields.push(nextField);
        });
      });
    }
    let popupFieldsEncoded = "";
    try {
      popupFieldsEncoded = popupFields.length ? encodeURIComponent(JSON.stringify(popupFields)) : "";
    } catch (_error) {
      popupFieldsEncoded = "";
    }
    const popupMode = String(item?.popup_mode || "").trim();
    let popupConfigEncoded = "";
    try {
      popupConfigEncoded = item?.popup_config ? encodeURIComponent(JSON.stringify(item.popup_config)) : "";
    } catch (_error) {
      popupConfigEncoded = "";
    }
    const popupTitle = String(item?.settings_title || `${title} Settings`).trim() || `${title} Settings`;
    const pageIndexRaw = Number(renderOptions?.page_index ?? renderOptions?.pageIndex ?? 0);
    const pageIndex = Number.isFinite(pageIndexRaw) ? Math.max(0, Math.floor(pageIndexRaw)) : 0;
    const pageAttr = pageIndex > 0 ? ` data-core-page-index="${pageIndex}"` : "";
    const pageStyle = pageIndex > 1 ? ` style="display:none;"` : "";
    const heroImageSrc = String(item?.hero_image_src || "").trim();
    const heroImageAlt = String(item?.hero_image_alt || title).trim() || title;
    const heroBadges = Array.isArray(item?.hero_badges) ? item.hero_badges : [];
    const summaryRows = Array.isArray(item?.summary_rows) ? item.summary_rows : [];
    const sensorRows = Array.isArray(item?.sensor_rows) ? item.sensor_rows : [];
    const sensorTitle = String(item?.sensor_title || "Sensors").trim() || "Sensors";
    const hasSatelliteSummary = Boolean(
      heroImageSrc || heroBadges.length || summaryRows.length || sensorRows.length || detail
    );

          const sectionHtml = sections
            .map((section) => {
              const sectionLabel = String(section?.label || "Section").trim() || "Section";
              const fields = Array.isArray(section?.fields) ? section.fields : [];
              const inline = itemSectionsInDropdownEnabled || boolFromAny(section?.inline, false);
              const tone = String(section?.tone || "").trim().toLowerCase();
              const toneClass = tone ? ` ${escapeHtml(`tone-${tone}`)}` : "";
              if (inline) {
                return `
                  <section class="core-inline-section${toneClass}">
                    <div class="small core-inline-section-title">${escapeHtml(sectionLabel)}</div>
                    <div class="form-grid">
                      ${fields.map((field) => renderCoreManagerField(field)).join("")}
                    </div>
                  </section>
                `;
              }
              return `
                  <details class="settings-dropdown">
                    <summary class="settings-summary">${escapeHtml(sectionLabel)}</summary>
                    <div class="form-grid">
                      ${fields.map((field) => renderCoreManagerField(field)).join("")}
                    </div>
                  </details>
                `;
            })
            .join("");

    const dropdownContentParts = [];
    if (itemFieldContent) {
      dropdownContentParts.push(`<div class="form-grid">${itemFieldContent}</div>`);
    }
    if (itemSectionsInDropdownEnabled && sectionHtml) {
      dropdownContentParts.push(sectionHtml);
    }
    const dropdownContentHtml = dropdownContentParts.join("");

    const itemFieldsHtml = itemFieldsPopupEnabled
      ? ""
      : itemFieldsDropdownEnabled
      ? dropdownContentHtml
        ? `
          <details class="settings-dropdown">
            <summary class="settings-summary">${escapeHtml(itemFieldsDropdownLabelLocal)}</summary>
            ${dropdownContentHtml}
          </details>
        `
        : ""
      : itemFieldContent
        ? `
          <div class="form-grid">
            ${itemFieldContent}
          </div>
        `
        : "";

    const hasPopupSettingsBtn = Boolean(popupFieldsEncoded) && (itemFieldsPopupEnabled || explicitPopupFields.length > 0);
    const hasSaveBtn = saveAction && (!itemFieldsPopupEnabled || !popupFieldsEncoded);
    const hasResetBtn = Boolean(resetAction);
    const hasAnyAction = Boolean(hasPopupSettingsBtn || hasSaveBtn || hasResetBtn || removeAction || runAction);
    const actionRowHtml = hasAnyAction
      ? `
        <div class="inline-row" style="margin-top:10px;">
          ${
            hasSaveBtn
              ? `<button type="button" class="action-btn core-manager-save">${escapeHtml(
                  String(item?.save_label || "Save")
                )}</button>`
              : ""
          }
          ${
            hasResetBtn
              ? `<button type="button" class="inline-btn danger core-manager-reset-defaults">${escapeHtml(
                  String(item?.reset_label || "Restore Default Settings")
                )}</button>`
              : ""
          }
          ${
            removeAction
              ? `<button type="button" class="inline-btn danger core-manager-remove">${escapeHtml(
                  String(item?.remove_label || "Remove")
                )}</button>`
              : ""
          }
          ${
            hasPopupSettingsBtn
              ? `<button type="button" class="action-btn core-manager-settings">${escapeHtml(
                  String(item?.settings_label || itemFieldsPopupLabel)
                )}</button>`
              : ""
          }
          ${
            runAction
              ? `<button type="button" class="action-btn core-manager-run" style="margin-left:auto;">${escapeHtml(
                  String(item?.run_label || "Run Now")
                )}</button>`
              : ""
          }
          <span class="small core-manager-status"></span>
        </div>
      `
      : "";

    const heroBadgesHtml = heroBadges.length
      ? `
        <div class="core-satellite-badges">
          ${heroBadges
            .map((badge) => {
              const label = String(badge?.label || "").trim();
              if (!label) {
                return "";
              }
              const tone = String(badge?.tone || "muted").trim().toLowerCase().replace(/[^a-z0-9_-]/g, "");
              return `<span class="core-satellite-badge tone-${escapeHtml(tone || "muted")}">${escapeHtml(label)}</span>`;
            })
            .join("")}
        </div>
      `
      : "";

    const summaryRowsHtml = summaryRows.length
      ? `
        <div class="core-satellite-facts">
          ${summaryRows
            .map((row) => {
              const label = String(row?.label || "").trim();
              const value = String(row?.value ?? "").trim();
              if (!label || !value) {
                return "";
              }
              return `
                <div class="core-satellite-fact">
                  <div class="small core-satellite-fact-label">${escapeHtml(label)}</div>
                  <div class="core-satellite-fact-value">${escapeHtml(value)}</div>
                </div>
              `;
            })
            .join("")}
        </div>
      `
      : "";

    const sensorRowsHtml = sensorRows.length
      ? `
        <div class="core-satellite-sensors">
          <div class="small core-satellite-sensors-title">${escapeHtml(sensorTitle)}</div>
          <div class="core-satellite-sensor-grid">
            ${sensorRows
              .map((row) => {
                const label = String(row?.label || "").trim();
                const value = String(row?.value ?? "").trim();
                const meta = String(row?.meta || row?.kind || "").trim();
                if (!label || !value) {
                  return "";
                }
                return `
                  <div class="core-satellite-sensor-pill">
                    <span class="core-satellite-sensor-label">${escapeHtml(label)}</span>
                    <span class="core-satellite-sensor-value">${escapeHtml(value)}</span>
                    ${meta ? `<span class="core-satellite-sensor-meta">${escapeHtml(meta)}</span>` : ""}
                  </div>
                `;
              })
              .join("")}
          </div>
        </div>
      `
      : "";

    const summaryBlockHtml = hasSatelliteSummary
      ? `
        <div class="core-satellite-summary${heroImageSrc ? "" : " no-image"}">
          ${
            heroImageSrc
              ? `<div class="core-satellite-image-wrap"><img class="core-satellite-image" src="${escapeHtml(heroImageSrc)}" alt="${escapeHtml(
                  heroImageAlt
                )}"></div>`
              : ""
          }
          <div class="core-satellite-summary-main">
            ${subtitle ? `<div class="small core-satellite-subtitle">${escapeHtml(subtitle)}</div>` : ""}
            ${heroBadgesHtml}
            ${detail ? `<div class="small core-satellite-detail">${escapeHtml(detail)}</div>` : ""}
            ${summaryRowsHtml}
            ${sensorRowsHtml}
          </div>
        </div>
      `
      : `${subtitle ? `<div class="small">${escapeHtml(subtitle)}</div>` : ""}`;

    return `
      <article class="card core-manager-item${itemGroupClass}"
        data-core-key="${safeCoreKey}"
        data-core-item-id="${encodedId}"
        data-core-item-group="${escapeHtml(itemGroup)}"
        data-core-save-action="${escapeHtml(saveAction)}"
        data-core-reset-action="${escapeHtml(resetAction)}"
        data-core-remove-action="${escapeHtml(removeAction)}"
        data-core-run-action="${escapeHtml(runAction)}"
        data-core-run-confirm="${escapeHtml(runConfirm)}"
        data-core-remove-confirm="${escapeHtml(removeConfirm)}"
        data-core-reset-confirm="${escapeHtml(resetConfirm)}"
        data-core-item-popup-fields="${escapeHtml(popupFieldsEncoded)}"
        data-core-item-popup-mode="${escapeHtml(popupMode)}"
        data-core-item-popup-config="${escapeHtml(popupConfigEncoded)}"
        data-core-item-popup-title="${escapeHtml(popupTitle)}"${pageAttr}${pageStyle}>
        <div class="card-head">
          <h3 class="card-title">${escapeHtml(title)}</h3>
          <span class="small">${safeCoreKey}</span>
        </div>
        ${summaryBlockHtml}
        ${itemFieldsHtml}
        ${itemFieldsPopupEnabled ? "" : itemSectionsInDropdownEnabled ? "" : sectionHtml}
        ${actionRowHtml}
      </article>
    `;
  }

  function filterCoreManagerItemsByGroup(groupKey) {
    const wanted = String(groupKey || "").trim().toLowerCase();
    if (!wanted) {
      return itemForms;
    }
    return itemForms.filter((item) => String(item?.group || "").trim().toLowerCase() === wanted);
  }

  function renderCoreManagerItemsContent(items, options = {}) {
    const rows = Array.isArray(items) ? items : [];
    const selector = boolFromAny(options?.selector, false);
    const selectorLabel = String(options?.selector_label || "Select Item").trim() || "Select Item";
    const sectionEmptyMessage = String(options?.empty_message || emptyMessage).trim() || emptyMessage;
    const itemGroup = String(options?.item_group || "").trim().toLowerCase();
    const groupToken = itemGroup.replace(/[^a-z0-9_-]/g, "");
    const groupClass = groupToken ? ` core-tab-items-group-${groupToken}` : "";
    const pageSizeRaw = Number(options?.page_size ?? 0);
    const pageSize = Number.isFinite(pageSizeRaw) ? Math.max(0, Math.floor(pageSizeRaw)) : 0;
    const serverPagination =
      options?.server_pagination && typeof options.server_pagination === "object" ? options.server_pagination : null;

    if (!rows.length) {
      return renderNotice(sectionEmptyMessage);
    }

    if (!selector && serverPagination && boolFromAny(serverPagination?.enabled, false)) {
      const serverPageSizeRaw = Number(serverPagination?.page_size ?? (pageSize || 0));
      const serverPageSize = Number.isFinite(serverPageSizeRaw)
        ? Math.max(1, Math.floor(serverPageSizeRaw))
        : Math.max(1, pageSize || 1);
      const serverPageCountRaw = Number(serverPagination?.page_count ?? 1);
      const serverPageCount = Number.isFinite(serverPageCountRaw) ? Math.max(1, Math.floor(serverPageCountRaw)) : 1;
      const serverCurrentRaw = Number(serverPagination?.page ?? 1);
      const serverCurrentPage = Math.min(
        serverPageCount,
        Number.isFinite(serverCurrentRaw) ? Math.max(1, Math.floor(serverCurrentRaw)) : 1
      );
      const serverAction = String(serverPagination?.action || "").trim();
      const serverTotalRaw = Number(serverPagination?.total ?? 0);
      const serverTotal = Number.isFinite(serverTotalRaw) ? Math.max(0, Math.floor(serverTotalRaw)) : 0;
      const cardsHtml = rows.map((item) => renderCoreManagerItemCard(item)).join("");
      const prevDisabled = serverCurrentPage <= 1 ? " disabled" : "";
      const nextDisabled = serverCurrentPage >= serverPageCount ? " disabled" : "";
      return `
        <div
          class="core-manager-pagination"
          data-core-pagination
          data-core-pagination-mode="server"
          data-core-key="${safeCoreKey}"
          data-core-page-action="${escapeHtml(serverAction)}"
          data-core-page-count="${serverPageCount}"
          data-core-current-page="${serverCurrentPage}"
          data-core-page-size="${serverPageSize}"
          data-core-page-total="${serverTotal}"
          data-core-item-group="${escapeHtml(itemGroup)}">
          <div class="core-tab-items${groupClass}" style="margin-top:10px;">${cardsHtml}</div>
          <div class="inline-row" style="margin-top:10px;">
            <button type="button" class="action-btn" data-core-page-prev${prevDisabled}>Previous</button>
            <span class="small" data-core-page-label>Page ${serverCurrentPage} of ${serverPageCount}</span>
            <button type="button" class="action-btn" data-core-page-next${nextDisabled}>Next</button>
          </div>
        </div>
      `;
    }

    if (!selector && pageSize > 0 && rows.length > pageSize) {
      const pageCount = Math.max(1, Math.ceil(rows.length / pageSize));
      const cardsHtml = rows
        .map((item, index) =>
          renderCoreManagerItemCard(item, {
            pageIndex: Math.floor(index / pageSize) + 1,
          })
        )
        .join("");
      return `
        <div class="core-manager-pagination" data-core-pagination data-core-page-count="${pageCount}" data-core-current-page="1">
          <div class="core-tab-items${groupClass}" style="margin-top:10px;">${cardsHtml}</div>
          <div class="inline-row" style="margin-top:10px;">
            <button type="button" class="action-btn" data-core-page-prev disabled>Previous</button>
            <span class="small" data-core-page-label>Page 1 of ${pageCount}</span>
            <button type="button" class="action-btn" data-core-page-next>Next</button>
          </div>
        </div>
      `;
    }

    if (!selector || rows.length <= 1) {
      return `<div class="core-tab-items${groupClass}" style="margin-top:10px;">${rows.map((item) => renderCoreManagerItemCard(item)).join("")}</div>`;
    }

    const rowsWithToken = rows.map((item, index) => {
      const rawId = String(item?.id || "").trim() || `idx_${index}`;
      return {
        token: encodeCoreManagerId(rawId),
        label: String(item?.title || rawId || `Item ${index + 1}`).trim() || `Item ${index + 1}`,
        html: renderCoreManagerItemCard(item),
      };
    });

    const optionsHtml = rowsWithToken
      .map((row) => `<option value="${escapeHtml(row.token)}">${escapeHtml(row.label)}</option>`)
      .join("");
    const cardsHtml = rowsWithToken
      .map(
        (row, index) => `
          <div class="core-manager-select-card ${index === 0 ? "active" : ""}" data-core-manager-select-card="${escapeHtml(row.token)}">
            ${row.html}
          </div>
        `
      )
      .join("");

    return `
      <div class="core-manager-selector-wrap" data-core-manager-selector-block>
        <label>${escapeHtml(selectorLabel)}
          <select class="core-manager-selector" data-core-manager-selector>
            ${optionsHtml}
          </select>
        </label>
        <div class="core-manager-selector-cards" style="margin-top:10px;">
          ${cardsHtml}
        </div>
      </div>
    `;
  }

  function renderCoreManagerGroupedItems(groupsRaw, groupPanelEmptyMessage) {
    const groups = (Array.isArray(groupsRaw) ? groupsRaw : [])
      .map((group, index) => {
        const key = String(group?.key || `group_${index + 1}`).trim();
        if (!key) {
          return null;
        }
        return {
          key,
          label: String(group?.label || key).trim() || key,
          itemGroup: String(group?.item_group || key).trim(),
          selector: boolFromAny(group?.selector, true),
          selectorLabel: String(group?.selector_label || "Select Item").trim() || "Select Item",
          emptyMessage: String(group?.empty_message || groupPanelEmptyMessage || emptyMessage).trim() || emptyMessage,
        };
      })
      .filter(Boolean);

    if (!groups.length) {
      return renderNotice(groupPanelEmptyMessage || "No grouped items defined.");
    }

    const defaultSubTab = groups[0]?.key || "";
    const subButtonsHtml = groups
      .map(
        (group, index) => `
          <button type="button" class="core-manager-subtab-btn ${index === 0 ? "active" : ""}" data-core-manager-subtab="${escapeHtml(
            group.key
          )}">
            ${escapeHtml(group.label)}
          </button>
        `
      )
      .join("");

    const subPanelsHtml = groups
      .map((group, index) => {
        const groupItems = filterCoreManagerItemsByGroup(group.itemGroup);
        const content = renderCoreManagerItemsContent(groupItems, {
          selector: group.selector,
          selector_label: group.selectorLabel,
          item_group: group.itemGroup,
          empty_message: group.emptyMessage,
        });
        return `
          <section class="core-manager-subtab-panel ${index === 0 ? "active" : ""}" data-core-manager-subtab-panel="${escapeHtml(
            group.key
          )}">
            ${content}
          </section>
        `;
      })
      .join("");

    return `
      <div class="core-manager-subtabs-wrap">
        <div class="core-manager-subtabs" data-core-manager-default-subtab="${escapeHtml(defaultSubTab)}">
          ${subButtonsHtml}
        </div>
        ${subPanelsHtml}
      </div>
    `;
  }

  const addFormHtml = addAction
    ? `
      <form class="form-grid core-manager-add-form" data-core-key="${safeCoreKey}" data-core-action="${escapeHtml(addAction)}">
        ${addFields.map((field) => renderCoreManagerField(field)).join("")}
        <div class="inline-row">
          <button type="submit" class="action-btn">${escapeHtml(addSubmitLabel)}</button>
          <span class="small core-manager-status"></span>
        </div>
      </form>
    `
    : "";

  const itemCardsHtml = renderCoreManagerItemsContent(itemForms, { selector: false, empty_message: emptyMessage });

  const managerTabs = managerTabsRaw
    .map((raw, index) => {
      const key = String(raw?.key || `tab_${index + 1}`).trim();
      if (!key) {
        return null;
      }
      const label = String(raw?.label || key).trim() || key;
      const source = String(raw?.source || "items").trim().toLowerCase();
      return {
        key,
        label,
        source,
        itemGroup: String(raw?.item_group || "").trim(),
        selector: boolFromAny(raw?.selector, false),
        selectorLabel: String(raw?.selector_label || "Select Item").trim() || "Select Item",
        groups: Array.isArray(raw?.groups) ? raw.groups : [],
        pageSize: (() => {
          const parsed = Number(raw?.page_size ?? 0);
          return Number.isFinite(parsed) ? Math.max(0, Math.floor(parsed)) : 0;
        })(),
        serverPagination: (() => {
          const rawPagination =
            raw?.server_pagination && typeof raw.server_pagination === "object" ? raw.server_pagination : null;
          if (!rawPagination) {
            return null;
          }
          return {
            enabled: boolFromAny(rawPagination?.enabled, false),
            action: String(rawPagination?.action || "").trim(),
            page: (() => {
              const parsed = Number(rawPagination?.page ?? 1);
              return Number.isFinite(parsed) ? Math.max(1, Math.floor(parsed)) : 1;
            })(),
            page_size: (() => {
              const parsed = Number(rawPagination?.page_size ?? 0);
              return Number.isFinite(parsed) ? Math.max(1, Math.floor(parsed)) : 1;
            })(),
            page_count: (() => {
              const parsed = Number(rawPagination?.page_count ?? 1);
              return Number.isFinite(parsed) ? Math.max(1, Math.floor(parsed)) : 1;
            })(),
            total: (() => {
              const parsed = Number(rawPagination?.total ?? 0);
              return Number.isFinite(parsed) ? Math.max(0, Math.floor(parsed)) : 0;
            })(),
          };
        })(),
        emptyMessage: String(raw?.empty_message || "").trim(),
      };
    })
    .filter(Boolean);

  function renderManagerTabContent(tab) {
    if (!tab || typeof tab !== "object") {
      return renderNotice("Invalid tab configuration.");
    }
    if (tab.source === "add_form") {
      return addFormHtml || `<div class="small">No tool form defined.</div>`;
    }
    if (tab.source === "grouped_items") {
      return renderCoreManagerGroupedItems(tab.groups, tab.emptyMessage || emptyMessage);
    }
    const rows = tab.itemGroup ? filterCoreManagerItemsByGroup(tab.itemGroup) : itemForms;
    return renderCoreManagerItemsContent(rows, {
      selector: tab.selector,
      selector_label: tab.selectorLabel,
      item_group: tab.itemGroup,
      page_size: tab.pageSize,
      server_pagination: tab.serverPagination,
      empty_message: tab.emptyMessage || emptyMessage,
    });
  }

  let managerInnerHtml = "";
  if (managerTabs.length) {
    const tabKeys = new Set(managerTabs.map((tab) => tab.key));
    const firstKey = managerTabs[0]?.key || "";
    const activeKey = tabKeys.has(defaultManagerTab) ? defaultManagerTab : firstKey;
    const tabButtonsHtml = managerTabs
      .map(
        (tab) => `
          <button type="button" class="core-manager-tab-btn ${tab.key === activeKey ? "active" : ""}" data-core-manager-tab="${escapeHtml(
            tab.key
          )}">
            ${escapeHtml(tab.label)}
          </button>
        `
      )
      .join("");
    const tabPanelsHtml = managerTabs
      .map(
        (tab) => `
          <section class="core-manager-tab-panel ${tab.key === activeKey ? "active" : ""}" data-core-manager-tab-panel="${escapeHtml(
              tab.key
            )}">
            ${renderManagerTabContent(tab)}
          </section>
        `
      )
      .join("");
    managerInnerHtml = `
      <div class="core-manager-tabs" data-core-manager-default-tab="${escapeHtml(activeKey)}">
        ${tabButtonsHtml}
      </div>
      ${tabPanelsHtml}
    `;
  } else if (useTabs) {
    const tabKeys = new Set(["create", "items"]);
    const activeTab = tabKeys.has(defaultManagerTab) ? defaultManagerTab : "create";
    managerInnerHtml = `
      <div class="core-manager-tabs" data-core-manager-default-tab="${escapeHtml(activeTab)}">
        <button type="button" class="core-manager-tab-btn ${activeTab === "create" ? "active" : ""}" data-core-manager-tab="create">${escapeHtml(
          createTabLabel
        )}</button>
        <button type="button" class="core-manager-tab-btn ${activeTab === "items" ? "active" : ""}" data-core-manager-tab="items">${escapeHtml(
          itemsTabLabel
        )}</button>
      </div>
      <section class="core-manager-tab-panel ${activeTab === "create" ? "active" : ""}" data-core-manager-tab-panel="create">
        ${addFormHtml || `<div class="small">No create form defined.</div>`}
      </section>
      <section class="core-manager-tab-panel ${activeTab === "items" ? "active" : ""}" data-core-manager-tab-panel="items">
        ${itemCardsHtml}
      </section>
    `;
  } else {
    managerInnerHtml = `
      ${addFormHtml || `<div class="small">No add form defined.</div>`}
      ${itemCardsHtml}
    `;
  }

  return `
    <div class="card">
      <div class="card-head">
        <h3 class="card-title">${safeTabLabel}</h3>
        <span class="small">${safeCoreKey}</span>
      </div>
      ${summary ? `<div class="small">${escapeHtml(summary)}</div>` : ""}
      ${statsHtml}
      <div class="card" style="margin-top:10px;">
        <div class="card-head">
          <h3 class="card-title">${escapeHtml(managerTitle)}</h3>
        </div>
        ${managerInnerHtml}
      </div>
    </div>
  `;
}

function renderCoreTabPayload(payload, tabSpec) {
  const safeTabLabel = escapeHtml(tabSpec?.label || tabSpec?.core_key || "Core");
  const safeCoreKey = escapeHtml(tabSpec?.core_key || "");
  const body = payload && typeof payload === "object" ? payload : {};
  const errorText = String(body.error || "").trim();
  if (errorText) {
    return `
      <div class="card">
        <div class="card-head">
          <h3 class="card-title">${safeTabLabel}</h3>
          <span class="small">${safeCoreKey}</span>
        </div>
        ${renderNotice(errorText)}
      </div>
    `;
  }

  if (body?.ui && typeof body.ui === "object" && String(body.ui.kind || "").trim() === "settings_manager") {
    return renderCoreSettingsManager(body, tabSpec);
  }

  const summary = String(body.summary || "").trim();
  const stats = Array.isArray(body.stats) ? body.stats : [];
  const items = Array.isArray(body.items) ? body.items : [];
  const emptyMessage = String(body.empty_message || "No data available for this tab.").trim();

  const statsHtml = stats.length
    ? `
      <div class="core-metric-row">
        ${stats
          .map((entry) => {
            const label = String(entry?.label || "").trim();
            const value = entry?.value;
            if (!label) {
              return "";
            }
            const valueText = String(value ?? "-").trim() || "-";
            return `
              <div class="core-metric-pill">
                <div class="small">${escapeHtml(label)}</div>
                <div>${escapeHtml(valueText)}</div>
              </div>
            `;
          })
          .join("")}
      </div>
    `
    : "";

  const itemsHtml = items.length
    ? items
        .map((entry) => {
          const title = String(entry?.title || "").trim() || "(untitled)";
          const subtitle = String(entry?.subtitle || "").trim();
          const detail = String(entry?.detail || "").trim();
          return `
            <article class="core-tab-item">
              <div class="card-head">
                <h3 class="card-title">${escapeHtml(title)}</h3>
              </div>
              ${subtitle ? `<div class="small">${escapeHtml(subtitle)}</div>` : ""}
              ${detail ? `<div class="muted">${escapeHtml(detail)}</div>` : ""}
            </article>
          `;
        })
        .join("")
    : renderNotice(emptyMessage);

  return `
    <div class="card">
      <div class="card-head">
        <h3 class="card-title">${safeTabLabel}</h3>
        <span class="small">${safeCoreKey}</span>
      </div>
      ${summary ? `<div class="small">${escapeHtml(summary)}</div>` : ""}
      ${statsHtml}
      <div class="core-tab-items">${itemsHtml}</div>
    </div>
  `;
}

function _encodeCoreManagerJson(value) {
  try {
    return value ? encodeURIComponent(JSON.stringify(value)) : "";
  } catch (_error) {
    return "";
  }
}

function renderEspHomeRuntimeStats(stats) {
  const rows = Array.isArray(stats) ? stats : [];
  if (!rows.length) {
    return "";
  }
  return `
    <div class="core-metric-row">
      ${rows
        .map((entry) => {
          const label = String(entry?.label || "").trim();
          const valueText = String(entry?.value ?? "-").trim() || "-";
          if (!label) {
            return "";
          }
          return `
            <div class="core-metric-pill">
              <div class="small">${escapeHtml(label)}</div>
              <div>${escapeHtml(valueText)}</div>
            </div>
          `;
        })
        .join("")}
      <button type="button" class="action-btn core-tab-refresh-btn" data-core-tab-refresh="1">Refresh</button>
    </div>
  `;
}

function renderEspHomeStatsPanel(sections, tables) {
  const metricSections = Array.isArray(sections) ? sections : [];
  const dataTables = Array.isArray(tables) ? tables : [];
  const sectionHtml = metricSections
    .map((section) => {
      const title = String(section?.title || "Stats").trim() || "Stats";
      const metrics = Array.isArray(section?.metrics) ? section.metrics : [];
      const pills = metrics
        .map((entry) => {
          const label = String(entry?.label || "").trim();
          const valueText = String(entry?.value ?? "-").trim() || "-";
          if (!label) {
            return "";
          }
          return `
            <div class="core-metric-pill">
              <div class="small">${escapeHtml(label)}</div>
              <div>${escapeHtml(valueText)}</div>
            </div>
          `;
        })
        .join("");
      if (!pills) {
        return "";
      }
      return `
        <section class="core-inline-section">
          <div class="small core-inline-section-title">${escapeHtml(title)}</div>
          <div class="core-metric-row">${pills}</div>
        </section>
      `;
    })
    .join("");
  const tableHtml = dataTables
    .map((table) => {
      const title = String(table?.title || "Table").trim() || "Table";
      const columns = Array.isArray(table?.columns) ? table.columns : [];
      const rows = Array.isArray(table?.rows) ? table.rows : [];
      const emptyMessage = String(table?.empty_message || "No rows.").trim() || "No rows.";
      return `
        <section class="core-inline-section">
          <div class="small core-inline-section-title">${escapeHtml(title)}</div>
          ${renderSimpleDataTable(columns, rows, emptyMessage)}
        </section>
      `;
    })
    .join("");
  if (!sectionHtml && !tableHtml) {
    return renderNotice("No ESPHome stats yet.");
  }
  return `${sectionHtml}${tableHtml}`;
}

async function runEspHomeRefreshAction() {
  return api("/api/settings/esphome/runtime/action", {
    method: "POST",
    body: JSON.stringify({
      action: "voice_refresh",
      payload: {},
    }),
  });
}

function renderEspHomeSummaryRows(summaryRows) {
  const rows = Array.isArray(summaryRows) ? summaryRows : [];
  if (!rows.length) {
    return "";
  }
  return `
    <div class="core-satellite-facts">
      ${rows
        .map((row) => {
          const label = String(row?.label || "").trim();
          const value = String(row?.value ?? "").trim();
          if (!label || !value) {
            return "";
          }
          return `
            <div class="core-satellite-fact">
              <div class="small core-satellite-fact-label">${escapeHtml(label)}</div>
              <div class="core-satellite-fact-value">${escapeHtml(value)}</div>
            </div>
          `;
        })
        .join("")}
    </div>
  `;
}

function renderEspHomeEntityControl(row, connected = true) {
  const control = row?.control && typeof row.control === "object" ? row.control : null;
  if (!control) {
    return "";
  }
  const entityKey = String(row?.key || "").trim();
  const label = String(row?.label || "").trim() || "Entity";
  if (!entityKey) {
    return "";
  }
  const disabledAttr = connected ? "" : " disabled";
  const controlType = String(control.type || "").trim().toLowerCase();
  const command = String(control.command || "").trim();
  if (!command) {
    return "";
  }

  if (controlType === "toggle" || controlType === "light") {
    const checked = boolFromAny(control.checked, false) ? " checked" : "";
    const toggleHtml = `
      <label class="toggle-row core-satellite-entity-toggle-row">
        <input
          type="checkbox"
          class="toggle-input esphome-entity-toggle"
          data-esphome-entity-key="${escapeHtml(entityKey)}"
          data-esphome-entity-command="${escapeHtml(command)}"
          data-esphome-entity-label="${escapeHtml(label)}"${checked}${disabledAttr}
        />
        <span class="small">${boolFromAny(control.checked, false) ? "On" : "Off"}</span>
      </label>
    `;
    const colorEnabled = controlType === "light" && boolFromAny(control.supports_color, false);
    const colorValue = String(control.color || "#ff9b45").trim() || "#ff9b45";
    const colorHtml = colorEnabled
      ? `
        <label class="core-satellite-entity-color-wrap" title="Set light color">
          <span class="small">Color</span>
          <input
            type="color"
            class="esphome-entity-color"
            value="${escapeHtml(colorValue)}"
            data-esphome-entity-key="${escapeHtml(entityKey)}"
            data-esphome-entity-command="${escapeHtml(command)}"
            data-esphome-entity-label="${escapeHtml(label)}"${disabledAttr}
          />
        </label>
      `
      : "";
    return `<div class="core-satellite-sensor-controls">${toggleHtml}${colorHtml}</div>`;
  }

  if (controlType === "button") {
    return `
      <div class="core-satellite-sensor-controls">
        <button
          type="button"
          class="inline-btn esphome-entity-button"
          data-esphome-entity-key="${escapeHtml(entityKey)}"
          data-esphome-entity-command="${escapeHtml(command)}"
          data-esphome-entity-label="${escapeHtml(label)}"${disabledAttr}
        >${escapeHtml(String(control.label || "Run"))}</button>
      </div>
    `;
  }

  if (controlType === "select") {
    const options = Array.isArray(control.options) ? control.options : [];
    if (!options.length) {
      return "";
    }
    const currentValue = String(control.value || "").trim();
    return `
      <div class="core-satellite-sensor-controls">
        <select
          class="esphome-entity-select"
          data-esphome-entity-key="${escapeHtml(entityKey)}"
          data-esphome-entity-command="${escapeHtml(command)}"
          data-esphome-entity-label="${escapeHtml(label)}"${disabledAttr}>
          ${options
            .map((option) => {
              const value = String(option || "").trim();
              if (!value) {
                return "";
              }
              const selected = value === currentValue ? " selected" : "";
              return `<option value="${escapeHtml(value)}"${selected}>${escapeHtml(value)}</option>`;
            })
            .join("")}
        </select>
      </div>
    `;
  }

  if (controlType === "number") {
    const value = String(control.value ?? "").trim();
    const min = control.min ?? "";
    const max = control.max ?? "";
    const step = control.step ?? "";
    return `
      <div class="core-satellite-sensor-controls">
        <div class="core-satellite-inline-set">
          <input
            type="number"
            class="esphome-entity-number"
            value="${escapeHtml(value)}"
            ${min !== "" ? `min="${escapeHtml(String(min))}"` : ""}
            ${max !== "" ? `max="${escapeHtml(String(max))}"` : ""}
            ${step !== "" ? `step="${escapeHtml(String(step))}"` : ""}
            data-esphome-entity-key="${escapeHtml(entityKey)}"
            data-esphome-entity-command="${escapeHtml(command)}"
            data-esphome-entity-label="${escapeHtml(label)}"${disabledAttr}
          />
          <button
            type="button"
            class="inline-btn esphome-entity-number-set"
            data-esphome-entity-key="${escapeHtml(entityKey)}"
            data-esphome-entity-command="${escapeHtml(command)}"
            data-esphome-entity-label="${escapeHtml(label)}"${disabledAttr}
          >Set</button>
        </div>
      </div>
    `;
  }

  if (controlType === "text") {
    const value = String(control.value ?? "").trim();
    const maxLength = Number(control.max_length ?? 0);
    const maxLengthAttr = Number.isFinite(maxLength) && maxLength > 0 ? ` maxlength="${escapeHtml(String(maxLength))}"` : "";
    return `
      <div class="core-satellite-sensor-controls">
        <div class="core-satellite-inline-set">
          <input
            type="text"
            class="esphome-entity-text"
            value="${escapeHtml(value)}"${maxLengthAttr}
            data-esphome-entity-key="${escapeHtml(entityKey)}"
            data-esphome-entity-command="${escapeHtml(command)}"
            data-esphome-entity-label="${escapeHtml(label)}"${disabledAttr}
          />
          <button
            type="button"
            class="inline-btn esphome-entity-text-set"
            data-esphome-entity-key="${escapeHtml(entityKey)}"
            data-esphome-entity-command="${escapeHtml(command)}"
            data-esphome-entity-label="${escapeHtml(label)}"${disabledAttr}
          >Set</button>
        </div>
      </div>
    `;
  }

  return "";
}

function renderEspHomeSensorRows(sensorRows, sensorTitle = "Live Entities", connected = true) {
  const rows = Array.isArray(sensorRows) ? sensorRows : [];
  if (!rows.length) {
    return "";
  }
  return `
    <div class="core-satellite-sensors">
      <div class="small core-satellite-sensors-title">${escapeHtml(String(sensorTitle || "Live Entities"))}</div>
      <div class="core-satellite-sensor-grid">
        ${rows
          .map((row) => {
            const label = String(row?.label || "").trim();
            const value = String(row?.value ?? "").trim();
            const meta = String(row?.meta || row?.kind || "").trim();
            const controlHtml = renderEspHomeEntityControl(row, connected);
            if (!label || !value) {
              return "";
            }
            return `
              <div class="core-satellite-sensor-pill${controlHtml ? " is-controllable" : ""}">
                <span class="core-satellite-sensor-label">${escapeHtml(label)}</span>
                <span class="core-satellite-sensor-value">${escapeHtml(value)}</span>
                ${meta ? `<span class="core-satellite-sensor-meta">${escapeHtml(meta)}</span>` : ""}
                ${controlHtml}
              </div>
            `;
          })
          .join("")}
      </div>
    </div>
  `;
}

function renderEspHomeSatelliteCard(item, coreKey = "esphome", displaySensors = null) {
  const itemId = String(item?.id || "").trim();
  const encodedId = escapeHtml(encodeCoreManagerId(itemId));
  const title = String(item?.title || itemId || "Satellite").trim() || "Satellite";
  const subtitle = String(item?.subtitle || "").trim();
  const detail = String(item?.detail || "").trim();
  const saveAction = String(item?.save_action || "").trim();
  const identifyAction = String(item?.identify_action || "").trim();
  const identifyLabel = String(item?.identify_label || "Identify").trim() || "Identify";
  const removeAction = String(item?.remove_action || "").trim();
  const runAction = String(item?.run_action || "").trim();
  const runConfirm = String(item?.run_confirm || "").trim();
  const removeConfirm = String(item?.remove_confirm || "Forget this satellite?").trim();
  const popupFields = Array.isArray(item?.popup_fields) ? item.popup_fields : [];
  const popupFieldsEncoded = _encodeCoreManagerJson(popupFields);
  const popupConfigEncoded = _encodeCoreManagerJson(item?.popup_config || {});
  const popupMode = String(item?.popup_mode || "").trim();
  const popupTitle = String(item?.settings_title || `${title} Live Log`).trim() || `${title} Live Log`;
  const settingsLabel = String(item?.settings_label || "Live Log").trim() || "Live Log";
  const fields = Array.isArray(item?.fields) ? item.fields : [];
  const heroImageSrc = String(item?.hero_image_src || "").trim();
  const heroImageAlt = String(item?.hero_image_alt || title).trim() || title;
  const heroBadges = Array.isArray(item?.hero_badges) ? item.hero_badges : [];
  const summaryRows = Array.isArray(item?.summary_rows) ? item.summary_rows : [];
  const sensorRows = Array.isArray(item?.sensor_rows) ? item.sensor_rows : [];
  const sensorTitle = String(item?.sensor_title || "Live Entities").trim() || "Live Entities";
  const connected = boolFromAny(item?.connected, false);
  const displaySensorsHtml = renderEspHomeDisplaySensorPanel(displaySensors, coreKey, {
    satellite: item,
    embedded: true,
    showTargetSelector: false,
  });

  const heroBadgesHtml = heroBadges.length
    ? `
      <div class="core-satellite-badges">
        ${heroBadges
          .map((badge) => {
            const label = String(badge?.label || "").trim();
            if (!label) {
              return "";
            }
            const tone = String(badge?.tone || "muted").trim().toLowerCase().replace(/[^a-z0-9_-]/g, "");
            return `<span class="core-satellite-badge tone-${escapeHtml(tone || "muted")}">${escapeHtml(label)}</span>`;
          })
          .join("")}
      </div>
    `
    : "";

  const summaryBlockHtml = `
    <div class="core-satellite-summary">
      ${
        heroImageSrc
          ? `<div class="core-satellite-image-wrap"><img class="core-satellite-image" src="${escapeHtml(heroImageSrc)}" alt="${escapeHtml(
              heroImageAlt
            )}"></div>`
          : ""
      }
      <div class="core-satellite-summary-main">
        ${subtitle ? `<div class="small core-satellite-subtitle">${escapeHtml(subtitle)}</div>` : ""}
        ${heroBadgesHtml}
        ${detail ? `<div class="small core-satellite-detail">${escapeHtml(detail)}</div>` : ""}
        ${renderEspHomeSummaryRows(summaryRows)}
        ${renderEspHomeSensorRows(sensorRows, sensorTitle, connected)}
      </div>
    </div>
  `;

  return `
    <article class="card core-manager-item esphome-satellite-card"
      data-core-key="${escapeHtml(coreKey)}"
      data-core-item-id="${encodedId}"
      data-core-item-group="satellite"
      data-core-save-action="${escapeHtml(saveAction)}"
      data-core-identify-action="${escapeHtml(identifyAction)}"
      data-core-remove-action="${escapeHtml(removeAction)}"
      data-core-run-action="${escapeHtml(runAction)}"
      data-core-run-confirm="${escapeHtml(runConfirm)}"
      data-core-remove-confirm="${escapeHtml(removeConfirm)}"
      data-core-item-popup-fields="${escapeHtml(popupFieldsEncoded)}"
      data-core-item-popup-mode="${escapeHtml(popupMode)}"
      data-core-item-popup-config="${escapeHtml(popupConfigEncoded)}"
      data-core-item-popup-title="${escapeHtml(popupTitle)}">
      <div class="card-head">
        <h3 class="card-title">${escapeHtml(title)}</h3>
        <span class="small">${escapeHtml(coreKey)}</span>
      </div>
      ${summaryBlockHtml}
      ${fields.length ? `<div class="form-grid">${fields.map((field) => renderCoreManagerField(field)).join("")}</div>` : ""}
      ${displaySensorsHtml}
      <div class="inline-row" style="margin-top:10px;">
        ${saveAction ? `<button type="button" class="action-btn core-manager-save">Save</button>` : ""}
        ${
          identifyAction
            ? `<button type="button" class="inline-btn esphome-satellite-identify" ${
                connected ? "" : 'disabled title="Connect this satellite before identifying it."'
              }>${escapeHtml(identifyLabel)}</button>`
            : ""
        }
        <button type="button" class="inline-btn esphome-entities-refresh">Refresh Entities</button>
        ${popupFields.length ? `<button type="button" class="action-btn core-manager-settings">${escapeHtml(settingsLabel)}</button>` : ""}
        ${removeAction ? `<button type="button" class="inline-btn danger core-manager-remove">Forget</button>` : ""}
        ${runAction ? `<button type="button" class="action-btn core-manager-run" style="margin-left:auto;">${escapeHtml(String(item?.run_label || "Run"))}</button>` : ""}
        <span class="small core-manager-status"></span>
      </div>
    </article>
  `;
}

